// Mirrors Table View's filtered spots into the bandspread popout, plus a
// hint about which band the user is "on": the band of the only band present
// in filtered, or the band of the current radio frequency if multi-band.
// Cheap no-op when the popout isn't open.
let _bandspreadPopoutOpen = false;
function pushBandspreadView(filtered) {
  if (!_bandspreadPopoutOpen || !window.api || !window.api.bandspreadPopoutPush) return;
  const bands = new Set();
  for (const s of filtered) if (s.band) bands.add(s.band);
  let band = null;
  if (bands.size === 1) {
    band = bands.values().next().value;
  } else if (typeof radioFreqKhz === 'number' && radioFreqKhz > 0) {
    band = freqToBandActivator(radioFreqKhz) || null;
  }
  try { window.api.bandspreadPopoutPush({ spots: filtered, band }); } catch {}
}

function pushJtcatSpotsHighlight(filtered) {
  if (!window.api || !window.api.jtcatSpotsHighlight) return;
  const calls = [];
  const seen = new Set();
  for (const s of filtered) {
    // POTA/WWFF only — JTCAT highlight is about activator calls, not DX
    // cluster spots or RBN watch hits.
    if (s.source !== 'pota' && s.source !== 'wwff') continue;
    const call = (s.callsign || '').toUpperCase();
    if (!call || seen.has(call)) continue;
    seen.add(call);
    calls.push({
      call,
      reference: s.reference || '',
      isNewPark: (s.source === 'pota' || s.source === 'wwff') && isAtnoRef(s.reference),
    });
  }
  // Cheap signature for dedup
  const sig = calls.map(c => c.call + (c.isNewPark ? '!' : '')).join(',');
  if (sig === _lastJtcatHighlightSig) return;
  _lastJtcatHighlightSig = sig;
  try { window.api.jtcatSpotsHighlight({ calls }); } catch {}
}

/** Send tuned spot info to VFO popout */
function notifyVfoTunedSpot(spot) {
  if (!spot) { window.api.vfoTunedSpot(null); return; }
  // Find all activators on same frequency
  const sameFreq = allSpots.filter(s => s.frequency === spot.frequency);
  const spots = sameFreq.length > 0 ? sameFreq : [spot];
  // Build array of operator data. For net spots we also forward band/mode/
  // comments so the popout can render an HF NET card instead of a QRZ card.
  const ops = spots.map(s => {
    // Activator dupe check — same call + band + mode + UTC day already in
    // this activation's contact list. POTA scoring counts each combination
    // once, so flagging it on the popout op-card lets the activator skip
    // the QSO instead of logging it twice. (Rohnboy request.)
    const dupe = isActivatorDupe(s.callsign, parseFloat(s.frequency), s.mode);
    return {
      callsign: s.callsign || '',
      reference: s.reference || '',
      parkName: s.parkName || '',
      source: s.source || '',
      wpm: s.wpm || null,
      bearing: (typeof s.bearing === 'number' && isFinite(s.bearing)) ? s.bearing : null,
      isDupe: !!dupe,
      dupeDetail: dupe ? {
        when: dupe.timestamp || '',
        freq: dupe.frequency || '',
        mode: dupe.mode || '',
      } : null,
      // Net-only fields (harmless on other sources; popout keys off source==='net')
      band: s.band || '',
      mode: s.mode || '',
      comments: s.comments || '',
    };
  });
  window.api.vfoTunedSpot({ ops });
  // QRZ lookup for each real operator (skip nets — their callsign is the net name).
  const pending = ops.map((op, i) => {
    if (!op.callsign || op.source === 'net') return Promise.resolve();
    return window.api.qrzLookup(op.callsign).then(info => {
      if (info) {
        const first = cleanQrzName(info.nickname) || cleanQrzName(info.fname);
        const last = cleanQrzName(info.name);
        ops[i].displayName = [first, last].filter(Boolean).join(' ');
        ops[i].grid = info.grid || '';
        ops[i].country = info.country || '';
        ops[i].image = info.image || '';
      }
    }).catch(() => {});
  });
  Promise.all(pending).then(() => {
    window.api.vfoTunedSpot({ ops });
  });
}
