/** Clean up QRZ name: title-case fully-uppercase / fully-lowercase
 *  input, drop trailing single-letter middle initial, preserve names
 *  that already have mixed case (McDonald, O'Brien, diSilva).
 *  Mirrors lib/qrz.js's cleanQrzName — source-of-truth lives there. */
function cleanQrzName(raw) {
  if (!raw) return '';
  const parts = raw.trim().split(/\s+/);
  if (parts.length > 1 && /^[A-Za-z]\.?$/.test(parts[parts.length - 1])) {
    parts.pop();
  }
  const joined = parts.join(' ');
  const hasLower = /[a-z]/.test(joined);
  const hasUpper = /[A-Z]/.test(joined);
  if (hasLower && hasUpper) return joined;
  return joined.toLowerCase().replace(/(^|[\s\-'])([a-z])/g, (_, sep, ch) => sep + ch.toUpperCase());
}

/** Auto-prepend POTA country prefix to bare park numbers based on callsign.
 *  e.g. callsign "W1AW" + ref "1234" -> "US-1234", "VE3ABC" + "5678" -> "VE-5678" */
function autoPotaPrefix(ref, callsign) {
  if (!ref) return ref;
  // Already has a prefix (contains letters before a dash)
  if (/^[A-Z]/.test(ref)) return ref;
  // Bare number — try to determine prefix from callsign
  const call = (callsign || '').toUpperCase().replace(/\/.*$/, '');
  if (!call) return ref;
  // US callsigns: start with K, W, N, or A followed by a digit
  if (/^[KWNA]\d/.test(call) || /^A[A-L]\d/.test(call)) return 'US-' + ref;
  // Canadian callsigns: VE, VA, VY, VO, CY, CF, CG, CI, CJ, CK
  if (/^V[AEOY]\d/.test(call) || /^C[FGIJK]\d/.test(call)) return 'VE-' + ref;
  return ref;
}

/** Build display name from QRZ info, respecting full-name setting.
 *  Prefers nickname over fname when available. */
function qrzDisplayName(info) {
  if (!info) return '';
  const first = cleanQrzName(info.nickname) || cleanQrzName(info.fname);
  if (!qrzFullName) return first || cleanQrzName(info.name);
  const last = cleanQrzName(info.name);
  return [first, last].filter(Boolean).join(' ');
}

/** Display name with a location suffix for the bottom banner logger.
 *  US ops get " · US-NY", DX ops get " · Germany", etc. (W9TEF request) */
function qrzNameAndLocation(info) {
  const name = qrzDisplayName(info);
  if (!info) return name;
  const country = (info.country || '').trim();
  const state = (info.state || '').trim();
  let loc = '';
  if (state && /^united states|^usa$/i.test(country)) {
    loc = `US-${state.toUpperCase()}`;
  } else if (country) {
    loc = country;
  } else if (state) {
    loc = state;
  }
  if (!loc) return name;
  return name ? `${name} \u00B7 ${loc}` : loc;
}

