if (window.api.onEchocatPairedDevices) {
  window.api.onEchocatPairedDevices(() => echocatRefreshPairedList());
}
echocatRefreshPairedList();

// --- Remote Launcher install / uninstall / status ---
// Surfaces scripts/launcher.js install state as a one-click button so
// users don't have to run `node scripts/launcher-install.js` from a
// terminal. The launcher lets the phone restart POTACAT after a crash.
const launcherStatusPill = document.getElementById('launcher-status-pill');
const launcherStatusDetail = document.getElementById('launcher-status-detail');
const launcherInstallBtn = document.getElementById('launcher-install-btn');
const launcherStartBtn = document.getElementById('launcher-start-btn');
const launcherUninstallBtn = document.getElementById('launcher-uninstall-btn');
async function refreshLauncherStatus() {
  if (!launcherStatusPill || !window.api.launcherStatus) return;
  try {
    const s = await window.api.launcherStatus();
    const installed = !!s.installed;
    const running = !!s.running;
    let label, color, detail;
    if (running && installed) {
      label = '● running'; color = '#4ecca3';
      detail = 'Auto-starts at login. The phone app can restart POTACAT via port 7301.';
    } else if (installed && !running) {
      label = '○ installed, not running'; color = '#f0a500';
      detail = 'Click Start now to spawn it without logging out, or wait — it will auto-start at your next login.';
    } else if (!installed && running) {
      label = '● running (no autostart)'; color = '#f0a500';
      detail = 'Launcher is up but won\'t auto-start at login. Click Install to make it persistent.';
    } else {
      label = '○ not installed'; color = '#888';
      detail = '';
    }
    launcherStatusPill.textContent = label;
    launcherStatusPill.style.color = color;
    if (launcherStatusDetail) launcherStatusDetail.textContent = detail;
    // Install button hides when already installed (regardless of running).
    // Start now button visible only when installed AND not running — the
    // exact state where the user has an autostart entry but no live process.
    // Uninstall button visible whenever installed.
    if (launcherInstallBtn)   launcherInstallBtn.classList.toggle('hidden', installed);
    if (launcherStartBtn)     launcherStartBtn.classList.toggle('hidden', !(installed && !running));
    if (launcherUninstallBtn) launcherUninstallBtn.classList.toggle('hidden', !installed);
  } catch (err) {
    launcherStatusPill.textContent = 'status unavailable';
    launcherStatusPill.style.color = '#888';
  }
}
if (launcherInstallBtn) {
  launcherInstallBtn.addEventListener('click', async () => {
    launcherInstallBtn.disabled = true;
    const prev = launcherInstallBtn.textContent;
    launcherInstallBtn.textContent = 'Installing…';
    try {
      const r = await window.api.launcherInstall();
      if (r && r.ok) {
        showLogToast('Remote Launcher installed (PID ' + (r.pid || '?') + ')', { duration: 4000 });
      } else {
        showLogToast('Install failed: ' + (r && r.error ? r.error : 'unknown error'), { warn: true, duration: 6000 });
      }
    } catch (err) {
      showLogToast('Install failed: ' + (err.message || err), { warn: true, duration: 6000 });
    }
    launcherInstallBtn.disabled = false;
    launcherInstallBtn.textContent = prev;
    // Give the spawned launcher ~800 ms to bind port 7301 before we re-probe.
    setTimeout(refreshLauncherStatus, 800);
  });
}
// Start now — spawns the existing extracted launcher script without
// touching the autostart entry. Visible only when state is "installed,
// not running" (refreshLauncherStatus toggles the .hidden class).
if (launcherStartBtn) {
  launcherStartBtn.addEventListener('click', async () => {
    launcherStartBtn.disabled = true;
    const prev = launcherStartBtn.textContent;
    launcherStartBtn.textContent = 'Starting…';
    try {
      const r = await window.api.launcherStart();
      if (r && r.ok) {
        showLogToast('Remote Launcher started (PID ' + (r.pid || '?') + ')', { duration: 4000 });
      } else {
        showLogToast('Start failed: ' + (r && r.error ? r.error : 'unknown error'), { warn: true, duration: 6000 });
      }
    } catch (err) {
      showLogToast('Start failed: ' + (err.message || err), { warn: true, duration: 6000 });
    }
    launcherStartBtn.disabled = false;
    launcherStartBtn.textContent = prev;
    setTimeout(refreshLauncherStatus, 800);
  });
}
if (launcherUninstallBtn) {
  launcherUninstallBtn.addEventListener('click', async () => {
    if (!confirm('Remove the auto-start entry for the Remote Launcher?\n\nAny currently-running launcher keeps running until you reboot.')) return;
    launcherUninstallBtn.disabled = true;
    const prev = launcherUninstallBtn.textContent;
    launcherUninstallBtn.textContent = 'Removing…';
    try {
      const r = await window.api.launcherUninstall();
      if (r && r.ok) {
        showLogToast(r.note || 'Auto-start removed.', { duration: 5000 });
      } else {
        showLogToast('Uninstall failed: ' + (r && r.error ? r.error : 'unknown error'), { warn: true });
      }
    } catch (err) {
      showLogToast('Uninstall failed: ' + (err.message || err), { warn: true });
    }
    launcherUninstallBtn.disabled = false;
    launcherUninstallBtn.textContent = prev;
    refreshLauncherStatus();
  });
}
refreshLauncherStatus();

// Tailscale cert status. Setup is automatic (part of the pair-QR
// flow), so this is informational only. Without a publicly-trusted
// cert, iOS would reject self-signed at the TLS layer
// (NSAllowsLocalNetworking neuters NSAllowsArbitraryLoads); the
// pair-QR handler issues a Tailscale-managed LE cert on first run
// and caches it.
const echocatTsStatus = document.getElementById('echocat-ts-status');

// Advanced ECHOCAT controls (in the <details> block). Hidden by
// default; useful for users with non-Tailscale cert setups, custom
// reverse proxies, or unusual interface picker outcomes.
const setEchocatPairHost = document.getElementById('set-echocat-pair-host');
const setEchocatTlsCertPath = document.getElementById('set-echocat-tls-cert-path');
const setEchocatTlsKeyPath = document.getElementById('set-echocat-tls-key-path');
const echocatTlsCertBrowse = document.getElementById('echocat-tls-cert-browse');
const echocatTlsKeyBrowse = document.getElementById('echocat-tls-key-browse');
const echocatTsRenewBtn = document.getElementById('echocat-ts-renew-btn');
const echocatTsRenewStatus = document.getElementById('echocat-ts-renew-status');

if (echocatTlsCertBrowse) {
  echocatTlsCertBrowse.addEventListener('click', async () => {
    const p = await window.api.echocatPickFile({
      title: 'Select TLS certificate file',
      filters: [{ name: 'Certificates', extensions: ['pem', 'crt', 'cer'] }, { name: 'All files', extensions: ['*'] }],
    });
    if (p) setEchocatTlsCertPath.value = p;
  });
}
if (echocatTlsKeyBrowse) {
  echocatTlsKeyBrowse.addEventListener('click', async () => {
    const p = await window.api.echocatPickFile({
      title: 'Select TLS private key file',
      filters: [{ name: 'Keys', extensions: ['key', 'pem'] }, { name: 'All files', extensions: ['*'] }],
    });
    if (p) setEchocatTlsKeyPath.value = p;
  });
}
if (echocatTsRenewBtn) {
  echocatTsRenewBtn.addEventListener('click', async () => {
    echocatTsRenewBtn.disabled = true;
    const prev = echocatTsRenewBtn.textContent;
    echocatTsRenewBtn.textContent = 'Renewing…';
    if (echocatTsRenewStatus) echocatTsRenewStatus.textContent = 'Issuing fresh cert via Tailscale (can take up to a minute)…';
    try {
      const r = await window.api.echocatIssueTailscaleCert();
      if (!r.ok) {
        if (echocatTsRenewStatus) echocatTsRenewStatus.textContent = 'Failed: ' + r.error;
      } else {
        if (echocatTsRenewStatus) echocatTsRenewStatus.textContent = 'Done. ECHOCAT restarted with new cert.';
        await echocatRefreshTailscaleStatus();
      }
    } catch (err) {
      if (echocatTsRenewStatus) echocatTsRenewStatus.textContent = 'Failed: ' + (err.message || err);
    }
    echocatTsRenewBtn.disabled = false;
    echocatTsRenewBtn.textContent = prev;
  });
}
async function echocatRefreshTailscaleStatus() {
  if (!echocatTsStatus) return;
  let s;
  try {
    s = await window.api.echocatTailscaleStatus();
  } catch {
    echocatTsStatus.textContent = 'Tailscale: status check failed.';
    return;
  }
  // (Legacy: echocat-pair-setup checklist was lifted into the
  // <details> "Use Tailscale instead" disclosure inside the pair
  // section. Element no longer exists; status copy below remains
  // the source of truth for the Tailscale state.)
  // Each branch points the user at exactly the next thing to fix.
  // Deep links go straight to the correct admin page so users
  // don't have to hunt through Tailscale's docs.
  if (!s.installed) {
    echocatTsStatus.innerHTML =
      'Tailscale not detected. <a href="https://tailscale.com/download" target="_blank" style="color:#4fc3f7;">Install Tailscale</a> for iOS app pairing.';
    return;
  }
  if (!s.loggedIn) {
    echocatTsStatus.innerHTML =
      'Tailscale is installed but not signed in. Open the Tailscale app and sign in.';
    return;
  }
  if (!s.magicDNS) {
    echocatTsStatus.innerHTML =
      'Tailscale connected, but <strong>MagicDNS is off</strong>. Enable it at <a href="https://login.tailscale.com/admin/dns" target="_blank" style="color:#4fc3f7;">admin → DNS</a> (toggle MagicDNS on, then HTTPS Certificates).';
    return;
  }
  if (!s.certCached) {
    echocatTsStatus.innerHTML =
      `Tailscale: <code>${s.hostname}</code>. Tap "Open pairing QR" to issue a TLS cert. ` +
      `If issuance fails, enable HTTPS Certificates at <a href="https://login.tailscale.com/admin/dns" target="_blank" style="color:#4fc3f7;">admin → DNS</a>.`;
    return;
  }
  const expiry = s.certExpiresAt ? s.certExpiresAt.slice(0, 10) : 'unknown';
  echocatTsStatus.innerHTML =
    `Tailscale: <code>${s.hostname}</code>. TLS cert ready, valid until ${expiry} (${s.daysLeft} days). ` +
    `<span style="color:#888;">Auto-renews when fewer than 14 days remain.</span>`;
}
echocatRefreshTailscaleStatus();
// Refresh whenever the user opens the Settings dialog so a state
// change (just signed in, just enabled MagicDNS, just upgraded to
// POTACAT Cloud) is reflected without a POTACAT restart.
if (typeof settingsDialog !== 'undefined' && settingsDialog) {
  const origShow = settingsDialog.showModal.bind(settingsDialog);
  settingsDialog.showModal = function() {
    echocatRefreshTailscaleStatus();
    if (typeof _pairRefreshCloudStatus === 'function') _pairRefreshCloudStatus();
    _restoreSettingsDialogSize();
    // Summary tab cards: refresh on every open so QSO counts, cloud
    // sub status, and POTA stats reflect anything that changed while
    // the dialog was closed.
    if (typeof refreshSummaryCard === 'function') {
      setTimeout(refreshSummaryCard, 0);
    }
    // Quick-settings inputs (data-mirror) read their values from the
    // canonical Station-tab inputs. The canonical values aren't
    // populated until restoreSettings() runs (which fires during the
    // openSettings flow elsewhere), so defer the sync one tick.
    setTimeout(_syncQuickSettingsFromCanonical, 50);
    return origShow();
  };
}

// ── Quick-settings mirror layer ─────────────────────────────────────
// Each element with data-mirror="<canonical-id>" is the Summary-tab
// twin of an existing Station-tab input. We pull values in (canonical
// → quick) on dialog open, and push values out (quick → canonical) on
// every change. The canonical input's own listeners (visibility
// toggles, save flow) keep working unchanged — we just fire its
// `change` and `input` events after writing.
function _syncQuickSettingsFromCanonical() {
  const mirrors = document.querySelectorAll('[data-mirror]');
  for (const quick of mirrors) {
    const canonical = document.getElementById(quick.dataset.mirror);
    if (!canonical) continue;
    if (quick.type === 'checkbox' || quick.type === 'radio') {
      quick.checked = !!canonical.checked;
    } else {
      quick.value = canonical.value;
    }
  }
  _updateQuickCwState();
  _updateQuickCwVolumeLabel();
}

function _updateQuickCwState() {
  const enabled = document.getElementById('quick-cw-enabled');
  const state = document.getElementById('quick-cw-state');
  if (!enabled || !state) return;
  const on = enabled.checked;
  state.textContent = on ? 'on' : 'off';
  state.classList.toggle('on', on);
}

function _updateQuickCwVolumeLabel() {
  const vol = document.getElementById('quick-cw-sidetone-volume');
  const label = document.getElementById('quick-cw-sidetone-volume-label');
  if (!vol || !label) return;
  label.textContent = (vol.value || 0) + '%';
}

(function _wireQuickSettingsMirrors() {
  // Push quick → canonical on any change, and fire the canonical's
  // change event so existing handlers (cw-keyer-config visibility,
  // type-specific sub-section toggles, etc.) react correctly.
  document.addEventListener('change', (e) => {
    const quick = e.target.closest('[data-mirror]');
    if (!quick) return;
    const canonical = document.getElementById(quick.dataset.mirror);
    if (!canonical) return;
    if (quick.type === 'checkbox' || quick.type === 'radio') {
      canonical.checked = quick.checked;
    } else {
      canonical.value = quick.value;
    }
    canonical.dispatchEvent(new Event('change', { bubbles: true }));
    if (quick.id === 'quick-cw-enabled') _updateQuickCwState();
  });
  // Live-update for range slider feedback.
  document.addEventListener('input', (e) => {
    const quick = e.target.closest('[data-mirror]');
    if (!quick) return;
    const canonical = document.getElementById(quick.dataset.mirror);
    if (canonical && (quick.type === 'range' || quick.type === 'number' || quick.type === 'text')) {
      canonical.value = quick.value;
      canonical.dispatchEvent(new Event('input', { bubbles: true }));
    }
    if (quick.id === 'quick-cw-sidetone-volume') _updateQuickCwVolumeLabel();
  });
  // Reverse direction: if the canonical input changes (user is in
  // Station tab editing the full setting), reflect back to the quick
  // mirror so reopening Summary doesn't show stale values.
  document.addEventListener('change', (e) => {
    if (!e.target || !e.target.id) return;
    const quick = document.querySelector('[data-mirror="' + e.target.id + '"]');
    if (!quick || quick === e.target) return;
    if (quick.type === 'checkbox' || quick.type === 'radio') {
      quick.checked = !!e.target.checked;
    } else {
      quick.value = e.target.value;
    }
    if (quick.id === 'quick-cw-enabled') _updateQuickCwState();
    if (quick.id === 'quick-cw-sidetone-volume') _updateQuickCwVolumeLabel();
  });
})();

// Persist Settings dialog size across launches.
// CSS gives a sensible default (min(1100px, calc(100vw - 32px))) but the
// user can drag the bottom-right grip to resize. We save what they pick
// and restore it on next open, clamped to the current viewport so a
// 4K-sized dialog doesn't reopen off-screen on a 1366×768 laptop.
const SETTINGS_SIZE_KEY = 'potacat-settings-dialog-size';
function _restoreSettingsDialogSize() {
  try {
    const raw = localStorage.getItem(SETTINGS_SIZE_KEY);
    if (!raw) return;
    const saved = JSON.parse(raw);
    if (!saved || typeof saved.w !== 'number' || typeof saved.h !== 'number') return;
    const w = Math.max(360, Math.min(saved.w, window.innerWidth - 16));
    const h = Math.max(360, Math.min(saved.h, window.innerHeight - 16));
    settingsDialog.style.width = w + 'px';
    settingsDialog.style.height = h + 'px';
  } catch {}
}
if (typeof settingsDialog !== 'undefined' && settingsDialog && typeof ResizeObserver !== 'undefined') {
  let _saveSizeTimer = null;
  const _ro = new ResizeObserver(() => {
    if (!settingsDialog.open) return;
    clearTimeout(_saveSizeTimer);
    _saveSizeTimer = setTimeout(() => {
      try {
        const r = settingsDialog.getBoundingClientRect();
        if (r.width < 100 || r.height < 100) return;
        localStorage.setItem(SETTINGS_SIZE_KEY, JSON.stringify({
          w: Math.round(r.width),
          h: Math.round(r.height),
        }));
      } catch {}
    }, 200);
  });
  _ro.observe(settingsDialog);
}

// ── Settings → Summary tab cards ────────────────────────────────────
// Landing dashboard that reads existing data sources (logbook on
// disk, cloud-get-status, ECHOCAT pair list, pota-sync cache) and
// renders five cards: Operator / Logbook / Cloud / ECHOCAT / POTA.app.
// Refresh fires on dialog open, on tab switch into Summary, and on
// any of the relevant state-change events.
let _summaryWired = false;
function refreshSummaryCard() {
  if (!document.getElementById('summary-card-operator')) return;
  _wireSummaryCardActionsOnce();
  _renderSummaryOperator();
  _renderSummaryLogbook();
  _renderSummaryCloud();
  _renderSummaryEchocat();
  _renderSummaryPota();
  // The ECHOCAT web-access block in Quick Settings was relocated
  // from the main-toolbar dropdown 2026-06-04. Same DOM IDs, same
  // populator; just needs to fire on dialog open instead of on
  // dropdown open.
  if (typeof refreshEchoCatInfo === 'function') refreshEchoCatInfo();
  // Sync the Summary header theme toggle to the current theme.
  if (quickLightMode) {
    quickLightMode.checked = document.documentElement.getAttribute('data-theme') === 'light';
    if (typeof _updateThemeToggleLabel === 'function') _updateThemeToggleLabel();
  }
  // PSTRotator quick toggle: only visible when a rotor has been
  // configured under Settings → Tuning. quickRotorLabel was
  // gated on this in the old dropdown's open path.
  if (quickRotorLabel) quickRotorLabel.classList.toggle('hidden', !rotorConfigured);
  if (quickRotorDivider) quickRotorDivider.classList.toggle('hidden', !rotorConfigured);
  // Sync Hide Worked Parks mirror with live state. (Activator mode
  // is now a click-to-enter button in the More dropdown, no checked
  // state to sync.)
  if (quickHideWorkedParks) quickHideWorkedParks.checked = hideWorkedParks;
}

async function _renderSummaryOperator() {
  try {
    const s = await window.api.getSettings();
    const grid = (s && s.grid) ? String(s.grid) : '';
    const myCall = (s && s.myCallsign) ? String(s.myCallsign).toUpperCase() : '';
    const sel = document.getElementById('summary-op-select');
    const gridEl = document.getElementById('summary-op-grid');
    if (gridEl) gridEl.textContent = grid ? grid : '';
    if (!sel) return;
    let activeCall = myCall;
    let list = [];
    try {
      const r = await window.api.profilesList();
      activeCall = (r && r.active) || myCall;
      list = (r && Array.isArray(r.profiles)) ? r.profiles : [];
    } catch {}
    // If no profile exists yet (pre-migration), show the legacy
    // single-operator label so the user sees their callsign at minimum.
    if (list.length === 0) {
      sel.innerHTML = '<option value="' + (activeCall || '') + '">' + (activeCall || '(not set)') + '</option>';
      sel.disabled = true;
      return;
    }
    sel.disabled = false;
    sel.innerHTML = list.map(c => {
      const sel = c === activeCall ? ' selected' : '';
      return '<option value="' + c + '"' + sel + '>' + c + '</option>';
    }).join('');
  } catch {}
}

// Document-level external-link delegation. Catches any anchor with a
// data-external attribute anywhere in the renderer and routes it
// through window.api.openExternal so it opens in the user's default
// browser (not inside the Electron renderer, which would try to
// navigate the whole app away). Bound unconditionally at script load —
// independent of any IIFE state — because the §97.119 link inside the
// Share Your Rig dialog was reported as not firing in production.
document.addEventListener('click', (e) => {
  const a = e.target.closest('a[data-external]');
  if (!a || !a.href) return;
  e.preventDefault();
  e.stopPropagation();
  console.log('[external-link] intercepted click, href=', a.href);
  if (window.api && window.api.openExternal) {
    window.api.openExternal(a.href);
  } else {
    console.warn('[external-link] window.api.openExternal not available');
  }
}, true); // capture phase so dialog children can't swallow it first

// ── Cloud Tunnel diagnostics dialog ─────────────────────────────────
// Surfaces the verbose state from GET /v1/cloud-tunnel/diagnostics so
// the user can see WHICH step (DB row / CF tunnel / CF DNS / env) is
// stuck when "Turn on tunnel" returns a 500. Triggered from the
// Settings → Summary → ECHOCAT → Diagnostics button.
function _summaryTunnelDiagOpen() {
  const dlg = document.getElementById('tunnel-diag-dialog');
  if (!dlg) return;
  if (typeof dlg.showModal === 'function') dlg.showModal();
  _summaryTunnelDiagRefresh();
}

async function _summaryTunnelDiagRefresh() {
  const status = document.getElementById('tunnel-diag-status');
  const summary = document.getElementById('tunnel-diag-summary');
  const raw = document.getElementById('tunnel-diag-raw');
  if (!status || !summary || !raw) return;
  status.textContent = 'Loading…';
  summary.innerHTML = '';
  raw.textContent = '';
  try {
    const r = await window.api.cloudTunnelDiagnostics();
    if (!r || r.error) {
      status.textContent = 'Error: ' + (r && r.error ? r.error : 'unknown');
      return;
    }
    const d = r.result || {};
    status.textContent = '';
    // Verdict row — what each step would find right now.
    const ok = (b) => b ? '✓' : '✗';
    const dim = (s) => '<span style="color:var(--text-tertiary);">' + s + '</span>';
    const lines = [];
    if (d.user && d.user.callsign) {
      lines.push('<div><strong>User:</strong> ' + _esc(d.user.callsign) + ' (id ' + _esc(d.user.id) + ')</div>');
    }
    if (d.db) {
      lines.push('<div><strong>DB row:</strong> tunnelId=' + (d.db.cloudTunnelId ? _esc(d.db.cloudTunnelId.slice(0, 8) + '…') : dim('null')) + ' host=' + (d.db.cloudHost ? _esc(d.db.cloudHost) : dim('null')) + ' sub=' + _esc(d.db.subscriptionStatus || 'none') + '</div>');
    }
    if (d.expectedHost) {
      lines.push('<div><strong>Would create at:</strong> ' + _esc(d.expectedHost) + '</div>');
    }
    if (d.cfEnv) {
      lines.push('<div><strong>CF env:</strong> token ' + ok(d.cfEnv.token) + '  account ' + ok(d.cfEnv.account) + '  zone ' + ok(d.cfEnv.zone) + '</div>');
    }
    if (d.cfTunnel && d.cfTunnel.checked) {
      const tail = d.cfTunnel.error ? dim(' — ' + _esc(d.cfTunnel.error)) : (d.cfTunnel.status ? dim(' (' + _esc(d.cfTunnel.status) + ')') : '');
      lines.push('<div><strong>CF tunnel record:</strong> found ' + ok(d.cfTunnel.found) + tail + '</div>');
    }
    if (d.cfDns && d.cfDns.checked) {
      const tail = d.cfDns.error ? dim(' — ' + _esc(d.cfDns.error)) : (d.cfDns.content ? dim(' → ' + _esc(d.cfDns.content)) : '');
      lines.push('<div><strong>CF DNS record:</strong> found ' + ok(d.cfDns.found) + tail + '</div>');
    }
    summary.innerHTML = lines.join('');
    raw.textContent = JSON.stringify(d, null, 2);
  } catch (err) {
    status.textContent = 'Error: ' + (err.message || err);
  }
}

(function _summaryTunnelDiagWire() {
  const dlg = document.getElementById('tunnel-diag-dialog');
  if (!dlg) return;
  const closeBtn = document.getElementById('tunnel-diag-close');
  if (closeBtn) closeBtn.addEventListener('click', () => dlg.close());
  const refreshBtn = document.getElementById('tunnel-diag-refresh');
  if (refreshBtn) refreshBtn.addEventListener('click', _summaryTunnelDiagRefresh);
  const copyBtn = document.getElementById('tunnel-diag-copy');
  if (copyBtn) copyBtn.addEventListener('click', () => {
    const raw = document.getElementById('tunnel-diag-raw');
    if (raw && raw.textContent) {
      window.api.copyToClipboard(raw.textContent);
      copyBtn.textContent = 'Copied!';
      setTimeout(() => { copyBtn.textContent = 'Copy JSON'; }, 1500);
    }
  });
})();

// ── Share Your Rig dialog (Guest Pass owner-side) ───────────────────
// Standalone modal for issuing time-boxed access passes. Talks to the
// cloud via the existing passes-issue / passes-list / passes-revoke /
// passes-qr-png IPC. Replaces the role of opening pair-popout with
// share:true (which is just a longer-TTL paired-device token, not a
// privilege-gated cloud pass).
function _shareRigOpen() {
  const dlg = document.getElementById('share-rig-dialog');
  if (!dlg) return;
  // Reset to form view, pre-fill callsigns from current settings.
  _shareRigShowFormView();
  _shareRigPrefillCallsigns();
  _shareRigUpdateClassDetail();
  _shareRigUpdateReachNotice();
  _shareRigResetWhenSection();
  _shareRigRefreshList();
  if (typeof dlg.showModal === 'function') dlg.showModal();
}

// ─── When? section helpers (mig 013 — Guest Pass scheduling) ──────────
//
// The Guest Pass form now supports two modes: "Starts now" (today's
// behavior, sends duration_seconds) and "Schedule for later" (sends
// starts_at + expires_at). _shareRigResetWhenSection rehydrates the
// schedule pickers to sensible defaults every time the dialog opens.

function _shareRigResetWhenSection() {
  // Reset radio to "Starts now" — the common case.
  const nowRadio = document.querySelector('input[name="share-rig-when"][value="now"]');
  if (nowRadio) nowRadio.checked = true;
  _shareRigSwapWhenMode('now');
  // Default the anonymous-redemption opt-in to OFF on every reopen.
  const anonChk = document.getElementById('share-rig-allow-anonymous');
  if (anonChk) anonChk.checked = false;
  // Pre-fill the schedule pickers so they're not empty when the user
  // first reveals them. Starts = next round 5 min, Ends = +2 hours.
  const startsEl = document.getElementById('share-rig-starts-at');
  const endsEl = document.getElementById('share-rig-ends-at');
  if (startsEl && endsEl) {
    const round = (d, ms) => new Date(Math.ceil(d.getTime() / ms) * ms);
    const s = round(new Date(Date.now() + 60 * 1000), 5 * 60 * 1000);
    const e = new Date(s.getTime() + 2 * 60 * 60 * 1000);
    startsEl.value = _toDatetimeLocal(s);
    endsEl.value = _toDatetimeLocal(e);
  }
}
function _toDatetimeLocal(d) {
  // <input type="datetime-local"> wants `YYYY-MM-DDTHH:MM` in LOCAL
  // time (no Z, no offset). Build by hand — toISOString gives UTC.
  const pad = (n) => String(n).padStart(2, '0');
  return `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())}T${pad(d.getHours())}:${pad(d.getMinutes())}`;
}
function _shareRigSwapWhenMode(mode) {
  const nowBox = document.getElementById('share-rig-when-now');
  const schedBox = document.getElementById('share-rig-when-schedule');
  if (!nowBox || !schedBox) return;
  if (mode === 'schedule') {
    nowBox.classList.add('hidden');
    schedBox.classList.remove('hidden');
  } else {
    nowBox.classList.remove('hidden');
    schedBox.classList.add('hidden');
  }
}
function _shareRigSelectedWhen() {
  const checked = document.querySelector('input[name="share-rig-when"]:checked');
  return checked && checked.value === 'schedule' ? 'schedule' : 'now';
}

// Sets the notice banner at the top of the form based on the user's
// network reach state. Goal: never let an operator generate a pass
// expecting "share anywhere" when they're actually on LAN-only and
// the recipient won't be able to reach them.
async function _shareRigUpdateReachNotice() {
  const box = document.getElementById('share-rig-reach-notice');
  if (!box) return;
  // Detect the shack's current public reach. Cloud Tunnel beats
  // Tailscale beats LAN-only — pick the one with the widest reach.
  let mode = 'lan';
  let detail = '';
  try {
    const ts = await window.api.cloudTunnelGetState();
    if (ts && (ts.status === 'live' || ts.status === 'connecting' || ts.status === 'provisioning' || ts.status === 'reconnecting')) {
      mode = 'cloud';
    }
  } catch {}
  if (mode === 'lan') {
    try {
      const tail = await window.api.echocatTailscaleStatus();
      if (tail && tail.installed && tail.loggedIn) {
        mode = 'tailscale';
        detail = tail.hostname ? (' (' + tail.hostname + ')') : '';
      }
    } catch {}
  }

  // The notice is ALWAYS shown — Casey 2026-06-04. Sharing has a
  // network-reach precondition that's invisible to users until they
  // hand a code to a friend who can't reach the shack. Lead with the
  // boundary so operators pick the right tier (or the right recipient)
  // before they spend time on privileges + scheduling. Copy structure:
  //   "You can share with <scope>. Since you <state>, <explanation>."
  box.classList.remove('hidden', 'warn', 'ok', 'info');
  if (mode === 'cloud') {
    box.classList.add('ok');
    box.innerHTML = '<strong>You can share with anyone, anywhere.</strong> '
      + 'Since you have POTACAT Cloud Tunnel turned on, your friend can '
      + 'connect from any internet connection. They\'ll need a free '
      + 'POTACAT Cloud account to redeem the code.';
  } else if (mode === 'tailscale') {
    box.classList.add('info');
    box.innerHTML = '<strong>You can share with people on your tailnet.</strong> '
      + 'Since you\'re using Tailscale' + _esc(detail) + ', your friend must '
      + 'be on YOUR tailnet — add their device to your Tailscale account '
      + 'first, then send them the code. Want to share with anyone, '
      + 'anywhere? <a href="#" data-act="open-cloud-signup">Join POTACAT Cloud</a>.';
  } else {
    box.classList.add('info');
    box.innerHTML = '<strong>You can share with people on your local network.</strong> '
      + 'Since you don\'t have Tailscale or POTACAT Cloud set up, your '
      + 'friend must be on the same Wi-Fi / Ethernet as this shack. '
      + 'Want them to connect from anywhere? Set up Tailscale (free for '
      + 'a few devices) or '
      + '<a href="#" data-act="open-cloud-signup">join POTACAT Cloud</a>.';
  }
}

function _shareRigShowFormView() {
  document.getElementById('share-rig-form-view').classList.remove('hidden');
  document.getElementById('share-rig-result-view').classList.add('hidden');
  document.getElementById('share-rig-status').textContent = '';
}
function _shareRigShowResultView() {
  document.getElementById('share-rig-form-view').classList.add('hidden');
  document.getElementById('share-rig-result-view').classList.remove('hidden');
}

async function _shareRigPrefillCallsigns() {
  try {
    const s = await window.api.getSettings();
    const my = (s && s.myCallsign) ? String(s.myCallsign).toUpperCase() : '';
    const station = document.getElementById('share-rig-station');
    const control = document.getElementById('share-rig-control');
    if (station && !station.value && my) station.value = my;
    if (control && !control.value && my) control.value = my;
  } catch {}
}

function _shareRigUpdateClassDetail() {
  const sel = document.getElementById('share-rig-class');
  const detail = document.getElementById('share-rig-class-detail');
  if (!sel || !detail) return;
  const opt = sel.options[sel.selectedIndex];
  const bands = opt && opt.dataset.bands ? opt.dataset.bands : '';
  detail.textContent = bands ? ('Subject to: ' + bands) : '';
}

function _shareRigSelectedHours() {
  const active = document.querySelector('#share-rig-duration-presets .share-rig-preset.active');
  if (active) return parseInt(active.dataset.hours, 10) || 1;
  const custom = document.getElementById('share-rig-custom-hours');
  return Math.max(1, Math.min(720, parseInt(custom && custom.value, 10) || 24));
}
function _shareRigSelectedWatts() {
  const active = document.querySelector('#share-rig-power-presets .share-rig-preset.active');
  if (active) return parseInt(active.dataset.watts, 10) || 100;
  const custom = document.getElementById('share-rig-custom-watts');
  return Math.max(1, Math.min(1500, parseInt(custom && custom.value, 10) || 100));
}

async function _shareRigIssue() {
  const status = document.getElementById('share-rig-status');
  const btn = document.getElementById('share-rig-issue');
  const watts = _shareRigSelectedWatts();
  const cls = document.getElementById('share-rig-class').value || 'general';
  const station = (document.getElementById('share-rig-station').value || '').toUpperCase().trim() || null;
  const operator = (document.getElementById('share-rig-operator').value || '').toUpperCase().trim() || null;
  const control = (document.getElementById('share-rig-control').value || '').toUpperCase().trim() || null;

  // Body branches on When? mode. The "starts now" branch keeps the
  // legacy duration_seconds shape — backwards compatible with every
  // cloud + shack already in the field. The "schedule" branch sends
  // starts_at + expires_at as ISO 8601 strings (the new mig 013 path).
  const mode = _shareRigSelectedWhen();
  const anonChk = document.getElementById('share-rig-allow-anonymous');
  const allowAnonymous = !!(anonChk && anonChk.checked);
  const body = {
    privilege_class: cls,
    max_power_w: watts,
    allowed_modes: null,
    station_callsign: station,
    operator_callsign: operator,
    control_operator_callsign: control,
    allow_anonymous: allowAnonymous,
  };
  let hoursForDisplay; // shown in the result summary line
  if (mode === 'schedule') {
    const startsEl = document.getElementById('share-rig-starts-at');
    const endsEl = document.getElementById('share-rig-ends-at');
    const startsVal = (startsEl && startsEl.value) || '';
    const endsVal = (endsEl && endsEl.value) || '';
    if (!startsVal || !endsVal) {
      status.textContent = 'Pick both a start and an end time.';
      return;
    }
    // datetime-local values lack a timezone — parsed as local time,
    // which is what the user typed. new Date(...) handles that.
    const startsAt = new Date(startsVal);
    const endsAt = new Date(endsVal);
    if (isNaN(startsAt.getTime()) || isNaN(endsAt.getTime())) {
      status.textContent = 'Could not read those dates. Try again.';
      return;
    }
    if (endsAt <= startsAt) {
      status.textContent = 'End time must be after start time.';
      return;
    }
    body.starts_at = startsAt.toISOString();
    body.expires_at = endsAt.toISOString();
    hoursForDisplay = (endsAt.getTime() - startsAt.getTime()) / 3600000;
  } else {
    const hours = _shareRigSelectedHours();
    body.duration_seconds = hours * 3600;
    hoursForDisplay = hours;
  }

  btn.disabled = true;
  status.textContent = 'Generating…';
  try {
    const res = await window.api.passesIssue(body);
    if (!res || res.error) {
      const errMap = {
        subscription_required: 'POTACAT Cloud subscription required to share your rig. Sign up from the Cloud card.',
        unauthorized: 'Sign in to POTACAT Cloud first.',
      };
      status.textContent = errMap[res && res.error] || ('Error: ' + (res && res.error ? res.error : 'unknown'));
      return;
    }
    _shareRigShowResultView();
    document.getElementById('share-rig-result-code').textContent = res.code || '';
    document.getElementById('share-rig-result-url').textContent = res.share_url || '';
    // Surface whether the recipient will need to sign in or not. The
    // copy here is the source of truth — the operator just made this
    // choice via the checkbox, and we want it loud at result time.
    const introEl = document.getElementById('share-rig-result-intro');
    if (introEl) {
      introEl.innerHTML = res.allow_anonymous
        ? 'Pass generated. Send the link below to your friend. <b>They can redeem without signing in to POTACAT Cloud</b> — perfect for one-off guests.'
        : 'Pass generated. Send the link below to your friend. They\'ll need a free POTACAT Cloud account (sign-up is one click).';
    }
    const startsAt = res.starts_at ? new Date(res.starts_at) : null;
    const expiresAt = res.expires_at ? new Date(res.expires_at) : null;
    const expiresEl = document.getElementById('share-rig-result-expires');
    if (expiresEl) {
      expiresEl.textContent = startsAt
        ? (startsAt.toLocaleString() + ' → ' + (expiresAt ? expiresAt.toLocaleString() : '?') + ' (scheduled)')
        : (expiresAt ? expiresAt.toLocaleString() : '?');
    }
    const lengthLabel = hoursForDisplay >= 1
      ? (Math.round(hoursForDisplay * 10) / 10) + (hoursForDisplay === 1 ? ' hour' : ' hours')
      : Math.round(hoursForDisplay * 60) + ' min';
    const anonTag = res.allow_anonymous ? ' · no sign-in required' : '';
    const privTxt = (res.privilege_class || cls).toString().toUpperCase()
      + ' · ' + (res.max_power_w || watts) + ' W max · ' + lengthLabel + anonTag;
    document.getElementById('share-rig-result-priv').textContent = privTxt;
    // QR is optional / collapsed — we set src lazily anyway so it's
    // there if the user expands the <details>.
    try {
      const qr = await window.api.passesQrPng(res.share_url || res.code);
      if (qr && !qr.error) document.getElementById('share-rig-result-qr').src = qr;
    } catch {}
    // Stash the active code on the Revoke button so the handler knows
    // which pass to kill without round-tripping.
    document.getElementById('share-rig-revoke').dataset.code = res.code || '';
    _shareRigRefreshList();
  } catch (err) {
    status.textContent = 'Error: ' + (err.message || err);
  } finally {
    btn.disabled = false;
  }
}

async function _shareRigRevoke() {
  const btn = document.getElementById('share-rig-revoke');
  const code = btn && btn.dataset.code;
  if (!code) return;
  if (!confirm('Revoke pass ' + code + '? The guest will be kicked from the rig immediately.')) return;
  btn.disabled = true;
  try {
    const r = await window.api.passesRevoke(code);
    if (r && r.error) {
      alert('Revoke failed: ' + r.error);
      btn.disabled = false;
      return;
    }
    _shareRigShowFormView();
    _shareRigRefreshList();
  } catch (err) {
    alert('Revoke failed: ' + (err.message || err));
    btn.disabled = false;
  }
}

async function _shareRigRefreshList() {
  const ul = document.getElementById('share-rig-list');
  if (!ul) return;
  ul.innerHTML = '<li class="share-rig-list-empty">Loading…</li>';
  try {
    const res = await window.api.passesList();
    if (res && res.error) {
      ul.innerHTML = '<li class="share-rig-list-empty">Could not load passes: ' + _esc(res.error) + '</li>';
      return;
    }
    const passes = (res && res.passes) || [];
    if (!passes.length) {
      ul.innerHTML = '<li class="share-rig-list-empty">No passes issued yet.</li>';
      return;
    }
    const now = Date.now();
    ul.innerHTML = passes.map(p => {
      const startsAtMs = p.starts_at ? new Date(p.starts_at).getTime() : null;
      const expires = p.expires_at ? new Date(p.expires_at).toLocaleString() : '?';
      const cls = p.privilege_class ? p.privilege_class.toUpperCase() : '';
      const watts = p.max_power_w || '?';
      // Derive the effective state for display. The cloud already
      // emits status='scheduled' via shapePass when starts_at is in
      // the future, but the list query returns the raw DB status —
      // recompute here so the list and the validate path agree.
      let st = (p.status || 'unknown').toLowerCase();
      if (st === 'active' && startsAtMs != null && startsAtMs > now) st = 'scheduled';
      const stCls = st === 'active' ? 'active'
        : (st === 'scheduled' ? 'scheduled'
          : (st === 'expired' ? 'expired' : 'revoked'));
      const sessions = (p.activeSessionCount || p.active_session_count || 0);
      const sessionLine = sessions > 0 ? '<span class="lst-meta" style="color:var(--accent-green);">· ' + sessions + ' guest connected now</span>' : '';
      // Active and scheduled passes can both be revoked + their link
      // copied. Expired/revoked can't.
      const canActOn = (st === 'active' || st === 'scheduled');
      const copyBtn = canActOn
        ? '<button type="button" class="lst-copy" data-act="lst-copy-link" data-code="' + _esc(p.code) + '" title="Copy share link to clipboard">Copy link</button>'
        : '';
      const revokeBtn = canActOn
        ? '<button type="button" class="lst-revoke" data-act="lst-revoke" data-code="' + _esc(p.code) + '">Revoke</button>'
        : '';
      // Callsign identity for the row — station_callsign is the
      // on-air ID (always set; defaults to operator's myCallsign).
      // If operator_callsign is also set, show "STATION → OPERATOR"
      // so the owner can scan-spot "who's this pass for?" at a
      // glance. NO 4-word code in the list — that's the share secret.
      const stationCall = (p.station_callsign || '').trim();
      const opCall = (p.operator_callsign || '').trim();
      const callTxt = (stationCall && opCall)
        ? (stationCall + ' → ' + opCall)
        : (stationCall || opCall || '—');
      const anonTag = p.allow_anonymous ? ' · anonymous OK' : '';
      const metaTxt = (st === 'scheduled' && startsAtMs)
        ? (cls + ' · ' + watts + 'W' + anonTag + ' · starts ' + new Date(startsAtMs).toLocaleString())
        : (cls + ' · ' + watts + 'W' + anonTag + ' · expires ' + expires);
      return '<li>'
        + '<span class="lst-call">' + _esc(callTxt) + '</span>'
        + '<span class="lst-meta">' + _esc(metaTxt) + '</span>'
        + sessionLine
        + '<span class="lst-status ' + stCls + '">' + st + '</span>'
        + copyBtn
        + revokeBtn
        + '</li>';
    }).join('');
  } catch (err) {
    ul.innerHTML = '<li class="share-rig-list-empty">Could not load passes: ' + _esc(err.message || String(err)) + '</li>';
  }
}

function _esc(s) {
  return String(s == null ? '' : s).replace(/[&<>"']/g, c => ({ '&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;' }[c]));
}

// Wire dialog interactions once at load time. Defensive: the dialog's
// HTML may not exist on older builds, so each binding null-checks.
(function _shareRigWire() {
  const dlg = document.getElementById('share-rig-dialog');
  if (!dlg) return;

  // When? radio — swap the sub-form between "Starts now" duration and
  // "Schedule for later" datetime pickers. Wired here so opening +
  // closing the dialog doesn't bind multiple times.
  const whenRow = dlg.querySelector('.share-rig-when-mode');
  if (whenRow) whenRow.addEventListener('change', () => {
    _shareRigSwapWhenMode(_shareRigSelectedWhen());
  });

  // Duration presets — clicking activates one, also writes hours into
  // the custom field so the two stay coherent. Typing in custom field
  // clears the active preset.
  const durRow = document.getElementById('share-rig-duration-presets');
  const durCustom = document.getElementById('share-rig-custom-hours');
  if (durRow) durRow.addEventListener('click', (e) => {
    const b = e.target.closest('.share-rig-preset');
    if (!b) return;
    durRow.querySelectorAll('.share-rig-preset').forEach(x => x.classList.remove('active'));
    b.classList.add('active');
    if (durCustom) durCustom.value = b.dataset.hours;
  });
  if (durCustom) durCustom.addEventListener('input', () => {
    durRow.querySelectorAll('.share-rig-preset').forEach(x => x.classList.remove('active'));
  });

  const pwrRow = document.getElementById('share-rig-power-presets');
  const pwrCustom = document.getElementById('share-rig-custom-watts');
  if (pwrRow) pwrRow.addEventListener('click', (e) => {
    const b = e.target.closest('.share-rig-preset');
    if (!b) return;
    pwrRow.querySelectorAll('.share-rig-preset').forEach(x => x.classList.remove('active'));
    b.classList.add('active');
    if (pwrCustom) pwrCustom.value = b.dataset.watts;
  });
  if (pwrCustom) pwrCustom.addEventListener('input', () => {
    pwrRow.querySelectorAll('.share-rig-preset').forEach(x => x.classList.remove('active'));
  });

  const clsSel = document.getElementById('share-rig-class');
  if (clsSel) clsSel.addEventListener('change', _shareRigUpdateClassDetail);

  // Per-element binding for the §97.119 link (kept for compat).
  // The unconditional document-level handler below is the real safety net.
  const link97 = document.getElementById('share-rig-97119-link');
  if (link97) link97.addEventListener('click', (e) => {
    e.preventDefault();
    e.stopPropagation();
    console.log('[share-rig] §97.119 link clicked (per-id), href=', link97.href);
    if (window.api && window.api.openExternal) window.api.openExternal(link97.href);
  });

  // "Join POTACAT Cloud" link inside the reach-notice banner.
  const notice = document.getElementById('share-rig-reach-notice');
  if (notice) notice.addEventListener('click', (e) => {
    const a = e.target.closest('[data-act="open-cloud-signup"]');
    if (!a) return;
    e.preventDefault();
    window.api.cloudOpenSubscribe();
  });

  const issueBtn = document.getElementById('share-rig-issue');
  if (issueBtn) issueBtn.addEventListener('click', _shareRigIssue);

  const closeBtn = document.getElementById('share-rig-close');
  if (closeBtn) closeBtn.addEventListener('click', () => dlg.close());
  const doneBtn = document.getElementById('share-rig-done');
  if (doneBtn) doneBtn.addEventListener('click', () => dlg.close());

  const issueAnother = document.getElementById('share-rig-issue-another');
  if (issueAnother) issueAnother.addEventListener('click', _shareRigShowFormView);

  const revokeBtn = document.getElementById('share-rig-revoke');
  if (revokeBtn) revokeBtn.addEventListener('click', _shareRigRevoke);

  // Copy link, copy code, email — all hit the clipboard / mailto.
  const copyUrl = document.getElementById('share-rig-copy-url');
  if (copyUrl) copyUrl.addEventListener('click', () => {
    const url = document.getElementById('share-rig-result-url').textContent;
    if (!url) return;
    window.api.copyToClipboard(url);
    copyUrl.textContent = 'Copied!';
    setTimeout(() => { copyUrl.textContent = 'Copy link'; }, 1500);
  });
  const copyCode = document.getElementById('share-rig-copy-code');
  if (copyCode) copyCode.addEventListener('click', () => {
    const code = document.getElementById('share-rig-result-code').textContent;
    if (!code) return;
    window.api.copyToClipboard(code);
    copyCode.textContent = 'Copied!';
    setTimeout(() => { copyCode.textContent = 'Copy code only'; }, 1500);
  });
  const mailto = document.getElementById('share-rig-mailto');
  if (mailto) mailto.addEventListener('click', () => {
    const url = document.getElementById('share-rig-result-url').textContent;
    const code = document.getElementById('share-rig-result-code').textContent;
    const expires = document.getElementById('share-rig-result-expires').textContent;
    const priv = document.getElementById('share-rig-result-priv').textContent;
    const subject = encodeURIComponent('You can use my rig: ' + code);
    const body = encodeURIComponent(
      "Hey,\n\nYou're cleared to operate my rig until " + expires + ".\n\n"
      + 'Open this link in POTACAT to connect:\n' + url + "\n\n"
      + 'Pass code: ' + code + "\n"
      + 'Privileges: ' + priv + "\n\n"
      + 'You\'ll need POTACAT installed and signed in (free trial is fine for guests).'
    );
    window.api.openExternal('mailto:?subject=' + subject + '&body=' + body);
  });

  const refresh = document.getElementById('share-rig-refresh-list');
  if (refresh) refresh.addEventListener('click', _shareRigRefreshList);

  // Per-row Copy link + Revoke in My recent passes. The 4-word
  // code is intentionally NOT displayed in the row (it's a share
  // secret — shoulder-surfers shouldn't be able to read it off the
  // dialog). The Copy link button reconstructs the share URL from
  // the code that ships with each row's data-code attribute. Same
  // URL shape as SHARE_URL_ROOT in potacat-cloudlog/routes/passes.js.
  const SHARE_URL_ROOT = 'https://api.potacat.com/guest-pass.html';
  const list = document.getElementById('share-rig-list');
  if (list) list.addEventListener('click', async (e) => {
    const copyBtn = e.target.closest('[data-act="lst-copy-link"]');
    if (copyBtn) {
      const code = copyBtn.dataset.code;
      if (!code) return;
      const url = SHARE_URL_ROOT + '?code=' + encodeURIComponent(code);
      try { await navigator.clipboard.writeText(url); }
      catch {
        // Fallback for older Electron / blocked clipboard API.
        try { window.api.copyToClipboard(url); } catch {}
      }
      const prev = copyBtn.textContent;
      copyBtn.textContent = 'Copied';
      setTimeout(() => { copyBtn.textContent = prev; }, 1400);
      return;
    }

    const btn = e.target.closest('[data-act="lst-revoke"]');
    if (!btn) return;
    const code = btn.dataset.code;
    if (!code || !confirm('Revoke this pass? The guest will be kicked from the rig immediately.')) return;
    btn.disabled = true;
    try {
      const r = await window.api.passesRevoke(code);
      if (r && r.error) { alert('Revoke failed: ' + r.error); btn.disabled = false; return; }
      _shareRigRefreshList();
    } catch (err) {
      alert('Revoke failed: ' + (err.message || err));
      btn.disabled = false;
    }
  });
})();

// ─── Remote Radios dialog — desktop-to-desktop client manager (v1.9) ─
//
// Lists settings.connectionTargets[] (shacks this desktop has paired
// with) plus a "Local rig" row at the top. The active row drives the
// laptop's rig backend; switching tears down the current ECHOCAT WS
// and dials the next shack via the connection-targets-activate IPC.
// Subscribes to remote-client-status pushes so the active row's badge
// updates live without manual refresh.

let _remoteRadiosLastStatus = { state: 'idle' };

function _remoteRadiosOpen() {
  const dlg = document.getElementById('remote-radios-dialog');
  if (!dlg) return;
  if (!dlg.open) dlg.showModal();
  _remoteRadiosRefreshList();
}

async function _remoteRadiosRefreshList() {
  const listEl = document.getElementById('remote-radios-list');
  const localBtn = document.getElementById('remote-radios-local-btn');
  const localRow = document.getElementById('remote-radios-local-row');
  const localMeta = document.getElementById('remote-radios-local-meta');
  if (!listEl) return;
  let targets = [];
  try { targets = await window.api.connectionTargetsList(); } catch {}
  let status = _remoteRadiosLastStatus;
  try { status = await window.api.connectionTargetsGetStatus(); } catch {}
  _remoteRadiosLastStatus = status;

  // Local-rig row visual state.
  const activeIsRemote = status && status.state !== 'idle' && status.state !== 'auth-fail';
  if (localRow) localRow.classList.toggle('active', !activeIsRemote);
  if (localBtn) {
    if (!activeIsRemote) {
      localBtn.textContent = 'Active';
      localBtn.disabled = true;
      localBtn.classList.remove('primary');
    } else {
      localBtn.textContent = 'Use local rig';
      localBtn.disabled = false;
      localBtn.classList.add('primary');
    }
  }
  if (localMeta) localMeta.textContent = 'This computer';

  if (!Array.isArray(targets) || targets.length === 0) {
    listEl.innerHTML = '<li class="remote-radios-empty">No remote shacks paired yet. Open <b>Summary → Pair another desktop&hellip;</b> on your shack to generate a link.</li>';
    return;
  }

  const fmtAge = (ts) => {
    if (!ts) return 'never connected';
    const ago = Date.now() - ts;
    if (ago < 60000) return 'just now';
    if (ago < 3600000) return Math.floor(ago / 60000) + 'm ago';
    if (ago < 86400000) return Math.floor(ago / 3600000) + 'h ago';
    return Math.floor(ago / 86400000) + 'd ago';
  };
  const fmtExpiry = (ts) => {
    if (ts == null) return null;
    const ms = ts - Date.now();
    if (ms <= 0) return 'expired';
    const d = Math.floor(ms / (24 * 3600 * 1000));
    if (d > 1) return 'expires in ' + d + 'd';
    const h = Math.floor(ms / (3600 * 1000));
    if (h >= 1) return 'expires in ' + h + 'h';
    // Guest Passes run on hours, not days — show minutes under an hour.
    return 'expires in ' + Math.max(1, Math.floor(ms / 60000)) + 'm';
  };

  listEl.innerHTML = targets.map(t => {
    const isActive = status && status.targetId === t.id;
    const dotClass = (() => {
      if (isActive && status.state === 'connected') return 'connected';
      if (isActive && status.state === 'auth-fail') return 'expired';
      if (t.expiresAt != null && t.expiresAt < Date.now()) return 'expired';
      if (t.lastConnectedAt && (Date.now() - t.lastConnectedAt > 7 * 86400 * 1000)) return 'unreachable';
      return '';
    })();
    const expBadgeRaw = fmtExpiry(t.expiresAt);
    let trustBadgeHtml = '';
    if (t.kind === 'pass') {
      // Guest Pass session — show the guardrails right on the row.
      const caps = [t.privilegeClass ? String(t.privilegeClass).toUpperCase() : null,
                    t.maxPowerW ? t.maxPowerW + 'W max' : null].filter(Boolean).join(' · ');
      trustBadgeHtml = '<span class="rr-badge guest">🎟 Guest Pass' + (caps ? ' — ' + _esc(caps) : '') + '</span>';
    }
    else if (t.trust === 'account' || t.accountLinked) trustBadgeHtml = '<span class="rr-badge account">🔗 Account-linked</span>';
    else if (t.trust === 'trusted' || t.trusted) trustBadgeHtml = '<span class="rr-badge trusted">🔒 Trusted</span>';
    else trustBadgeHtml = '<span class="rr-badge guest">Guest</span>';
    const expBadgeHtml = expBadgeRaw ? '<span class="rr-badge leg">' + _esc(expBadgeRaw) + '</span>' : '<span class="rr-badge leg">no expiry</span>';
    const legBadge = (isActive && status.leg) ? '<span class="rr-badge leg">via ' + _esc(status.leg) + '</span>' : '';
    const stateLine = (() => {
      if (isActive && status.state === 'connected') return '<b>Connected.</b> Last used ' + _esc(fmtAge(t.lastConnectedAt));
      if (isActive && status.state === 'connecting') return '<b>Connecting&hellip;</b>';
      if (isActive && status.state === 'authing') return '<b>Authenticating&hellip;</b>';
      if (isActive && status.state === 'auth-fail') {
        return t.kind === 'pass'
          ? '<b>Pass refused.</b> It may have expired or been revoked — ask the owner for a fresh link.'
          : '<b>Auth failed.</b> Token may have expired — re-pair from your shack.';
      }
      if (isActive && status.state === 'disconnected') return '<b>Reconnecting&hellip;</b>';
      if (t.kind === 'pass' && t.expiresAt != null && t.expiresAt <= Date.now()) {
        return '<b>Session ended.</b> Ask the owner for a fresh pass to reconnect.';
      }
      return 'Last connected ' + _esc(fmtAge(t.lastConnectedAt));
    })();
    const actionBtnHtml = (() => {
      if (isActive && status.state === 'connected') {
        return '<button type="button" class="primary" data-act="rr-disconnect" data-id="' + _esc(t.id) + '">Disconnect</button>';
      }
      if (isActive && (status.state === 'connecting' || status.state === 'authing' || status.state === 'disconnected')) {
        return '<button type="button" data-act="rr-disconnect" data-id="' + _esc(t.id) + '">Cancel</button>';
      }
      return '<button type="button" class="primary" data-act="rr-connect" data-id="' + _esc(t.id) + '">Connect</button>';
    })();
    const reachParts = [];
    if (t.lanHost) reachParts.push('LAN');
    if (t.tsHost) reachParts.push('Tailscale');
    if (t.cloudHost) reachParts.push('Cloud');
    const reach = reachParts.length > 0 ? reachParts.join(' / ') : '—';
    return '<li class="' + (isActive ? 'active' : '') + '">'
      + '<div class="rr-row">'
      +   '<div class="rr-dot ' + dotClass + '"></div>'
      +   '<div class="rr-name" data-act="rr-rename" data-id="' + _esc(t.id) + '" data-name="' + _esc(t.name) + '">' + _esc(t.name) + '</div>'
      + '</div>'
      + '<div class="rr-meta"><b>' + _esc(t.rigModel || 'Remote rig') + '</b> · ' + _esc(reach) + ' · ' + stateLine + '</div>'
      + '<div class="rr-badges">' + trustBadgeHtml + expBadgeHtml + legBadge + '</div>'
      + '<div class="rr-actions">'
      +   actionBtnHtml
      +   '<button type="button" data-act="rr-rename" data-id="' + _esc(t.id) + '" data-name="' + _esc(t.name) + '">Rename</button>'
      +   '<button type="button" class="danger" data-act="rr-remove" data-id="' + _esc(t.id) + '">Remove</button>'
      + '</div>'
      + '</li>';
  }).join('');
}

async function _remoteRadiosConnect(id) {
  try {
    const r = await window.api.connectionTargetsActivate(id);
    if (r && r.error) alert('Connect failed: ' + r.error);
  } catch (err) {
    alert('Connect failed: ' + (err.message || err));
  }
  _remoteRadiosRefreshList();
}

async function _remoteRadiosDisconnect() {
  try { await window.api.connectionTargetsActivate(null); } catch {}
  _remoteRadiosRefreshList();
}

async function _remoteRadiosRename(id, currentName) {
  const next = await _summaryPrompt({
    title: 'Rename shack',
    message: 'Pick a label you’ll recognize in this list.',
    defaultValue: currentName,
  });
  if (next == null) return;
  const trimmed = next.trim();
  if (!trimmed || trimmed === currentName) return;
  try { await window.api.connectionTargetsRename(id, trimmed); } catch {}
  _remoteRadiosRefreshList();
}

async function _remoteRadiosRemove(id) {
  if (!confirm('Remove this paired shack? You’ll need a new pair link to reconnect.')) return;
  try { await window.api.connectionTargetsRemove(id); } catch {}
  _remoteRadiosRefreshList();
}

(function _remoteRadiosWire() {
  const dlg = document.getElementById('remote-radios-dialog');
  if (!dlg) return;

  const closeBtn = document.getElementById('remote-radios-close');
  if (closeBtn) closeBtn.addEventListener('click', () => dlg.close());

  const refresh = document.getElementById('remote-radios-refresh');
  if (refresh) refresh.addEventListener('click', _remoteRadiosRefreshList);

  const localBtn = document.getElementById('remote-radios-local-btn');
  if (localBtn) localBtn.addEventListener('click', _remoteRadiosDisconnect);

  // Paste-a-pair-link path. Redeems directly in main (window.api.pairRedeemUrl)
  // — no dependency on the potacat:// OS protocol handler being registered.
  const rrPasteBtn = document.getElementById('remote-radios-paste-btn');
  const rrPasteInput = document.getElementById('remote-radios-paste-input');
  const rrPasteStatus = document.getElementById('remote-radios-paste-status');
  function _remoteRadiosPasteStatus(msg, isErr) {
    if (!rrPasteStatus) return;
    rrPasteStatus.textContent = msg || '';
    rrPasteStatus.classList.toggle('hidden', !msg);
    rrPasteStatus.style.color = isErr ? 'var(--accent-red)' : 'var(--text-secondary)';
  }
  // One box, any credential: a potacat://pair link (paired-device token), a
  // Guest Pass share URL / potacat://pass link, or a bare 4-word pass code.
  function _rrLooksLikeGuestPass(s) {
    if (/^potacat:\/?\/?pass\//i.test(s)) return true;
    if (/guest-pass\.html/i.test(s)) return true;
    return /^[a-z]+(-[a-z]+){2,3}$/i.test(s); // bare 4-word (or legacy 3-word) code
  }
  async function _remoteRadiosPaste() {
    const url = (rrPasteInput && rrPasteInput.value || '').trim();
    if (!url) return;
    try {
      if (/^potacat:\/\/pair\?/i.test(url)) {
        _remoteRadiosPasteStatus('Redeeming pair link…', false);
        const r = window.api.pairRedeemUrl ? await window.api.pairRedeemUrl(url) : { ok: false, error: 'unsupported build' };
        if (r && r.ok) {
          _remoteRadiosPasteStatus('✓ Paired. Added to your shacks below.', false);
          if (rrPasteInput) rrPasteInput.value = '';
        } else {
          _remoteRadiosPasteStatus('Could not redeem: ' + ((r && r.error) || 'all paths failed'), true);
        }
      } else if (_rrLooksLikeGuestPass(url)) {
        _remoteRadiosPasteStatus('Redeeming Guest Pass…', false);
        const r = window.api.guestPassRedeem ? await window.api.guestPassRedeem(url) : { ok: false, error: 'unsupported build' };
        if (r && r.ok) {
          const until = r.expiresAt ? new Date(r.expiresAt).toLocaleString() : '?';
          _remoteRadiosPasteStatus('✓ Guest Pass active — connecting to ' + (r.owner || r.name) + '. ' +
            (r.maxPowerW ? r.maxPowerW + 'W max · ' : '') + 'until ' + until + '.', false);
          if (rrPasteInput) rrPasteInput.value = '';
        } else {
          _remoteRadiosPasteStatus('Could not redeem: ' + ((r && r.error) || 'unknown error'), true);
        }
      } else {
        _remoteRadiosPasteStatus("That doesn't look like a pair link or a Guest Pass — paste a potacat://pair link, a guest-pass URL, or the 4-word pass code.", true);
        return;
      }
      _remoteRadiosRefreshList();
    } catch (err) {
      _remoteRadiosPasteStatus('Could not redeem: ' + (err.message || err), true);
    }
  }
  if (rrPasteBtn) rrPasteBtn.addEventListener('click', _remoteRadiosPaste);
  if (rrPasteInput) rrPasteInput.addEventListener('keydown', (e) => { if (e.key === 'Enter') { e.preventDefault(); _remoteRadiosPaste(); } });

  // More-menu entry point.
  const openBtn = document.getElementById('view-remote-radios-btn');
  if (openBtn) openBtn.addEventListener('click', () => {
    _remoteRadiosOpen();
    // Close the More dropdown if it auto-stayed open.
    const drop = document.getElementById('views-dropdown');
    if (drop) drop.classList.remove('open');
  });

  // Delegated row action handler.
  const listEl = document.getElementById('remote-radios-list');
  if (listEl) listEl.addEventListener('click', (e) => {
    const btn = e.target.closest('[data-act]');
    if (!btn) return;
    const act = btn.dataset.act;
    const id = btn.dataset.id;
    if (act === 'rr-connect') return _remoteRadiosConnect(id);
    if (act === 'rr-disconnect') return _remoteRadiosDisconnect();
    if (act === 'rr-rename') return _remoteRadiosRename(id, btn.dataset.name || '');
    if (act === 'rr-remove') return _remoteRadiosRemove(id);
  });

  // Live status pushes.
  if (window.api && window.api.onRemoteClientStatus) {
    window.api.onRemoteClientStatus((s) => {
      _remoteRadiosLastStatus = s || { state: 'idle' };
      if (dlg.open) _remoteRadiosRefreshList();
    });
  }
  if (window.api && window.api.onConnectionTargetsUpdated) {
    window.api.onConnectionTargetsUpdated(() => {
      if (dlg.open) _remoteRadiosRefreshList();
    });
  }
})();

// Displacement banner — when the shack kicks our connection because
// another client (phone, web ECHOCAT, second laptop) took over, show
// a friendly explainer with a Reconnect button. Replaces the
// otherwise-mystery "rig disconnected" experience that today's iOS +
// browser users get. Phase 1, single-client model — see plan §4.
// ─── Architecture B: log-error modal (Brief C §2g / Brief B §3) ──────
//
// Loud, dismiss-by-user modal that appears when the host couldn't
// deliver an auto-logged QSO (no capability, sendToClient threw, WS
// dropped). Casey's hard rule (2026-06-05): a guest's QSO never
// falls back to the host's logbook — instead the operator gets the
// full QSO details rendered loudly so they can write it down by hand.
//
// Modal, NOT a toast. Stays open until user dismisses. Copy is the
// verbatim wording Casey wrote — do not "improve."
function _showLogErrorModal(payload) {
  const qso = (payload && payload.qso) || {};
  const reason = (payload && payload.reason) || 'unknown';
  const messageOverride = (payload && payload.message) || '';

  // Pull QSO details defensively — any field may be missing.
  const callsign = (qso.callsign || '').toUpperCase() || '(unknown)';
  // timeOn is 'HHMM' on the wire; format 'HH:MM UTC'
  const timeRaw = String(qso.timeOn || '').replace(/[^0-9]/g, '');
  const timeUtc = timeRaw.length >= 4
    ? (timeRaw.slice(0, 2) + ':' + timeRaw.slice(2, 4) + ' UTC')
    : '(unknown time)';
  // frequency is kHz string → MHz with 3 dp for display
  const freqKhz = parseFloat(qso.frequency || '0');
  const freqMHz = Number.isFinite(freqKhz) && freqKhz > 0
    ? (freqKhz / 1000).toFixed(3) + ' MHz'
    : '(unknown freq)';
  const mode = qso.mode || '(unknown mode)';
  const rstSent = qso.rstSent || '---';
  const rstRcvd = qso.rstRcvd || '---';

  // n-fer ref clause — list every program ref that's set. Mirror Brief B §3.
  const refParts = [];
  if (qso.potaRef) refParts.push('POTA ' + String(qso.potaRef).toUpperCase());
  if (qso.sotaRef) refParts.push('SOTA ' + String(qso.sotaRef).toUpperCase());
  if (qso.wwffRef) refParts.push('WWFF ' + String(qso.wwffRef).toUpperCase());
  if (qso.llotaRef) refParts.push('LLOTA ' + String(qso.llotaRef).toUpperCase());
  if (qso.wwbotaRef) refParts.push('WWBOTA ' + String(qso.wwbotaRef).toUpperCase());
  if (refParts.length === 0 && qso.sig && qso.sigInfo) {
    refParts.push(String(qso.sig).toUpperCase() + ' ' + String(qso.sigInfo).toUpperCase());
  }
  const refClause = refParts.length > 0 ? ' (at ' + refParts.join(' + ') + ')' : '';

  // Compose modal DOM. Use existing <dialog> if present, else create.
  let dlg = document.getElementById('log-error-dialog');
  if (!dlg) {
    dlg = document.createElement('dialog');
    dlg.id = 'log-error-dialog';
    dlg.className = 'log-error-dialog';
    document.body.appendChild(dlg);
  }
  const heading = messageOverride || 'Logging Error.';
  dlg.innerHTML =
    '<h3 class="log-error-heading">' + _esc(heading) + '</h3>' +
    '<p class="log-error-body">' +
      'QSO with <b>' + _esc(callsign) + '</b> at <b>' + _esc(timeUtc) + '</b> on <b>' +
      _esc(freqMHz) + ' ' + _esc(mode) + '</b> with RST Rcvd <b>' + _esc(rstRcvd) +
      '</b> and RST Sent <b>' + _esc(rstSent) + '</b>' + _esc(refClause) +
      ' failed to save.' +
    '</p>' +
    '<p class="log-error-action"><b>Write it down and manually add to your logbook.</b></p>' +
    '<p class="log-error-meta">Reason: ' + _esc(reason) + '</p>' +
    '<div class="dialog-buttons">' +
      '<button type="button" id="log-error-dismiss" class="primary">I wrote it down</button>' +
    '</div>';
  const dismissBtn = dlg.querySelector('#log-error-dismiss');
  if (dismissBtn) dismissBtn.addEventListener('click', () => dlg.close(), { once: true });
  if (typeof dlg.showModal === 'function' && !dlg.open) dlg.showModal();
}

if (window.api && window.api.onLogError) {
  window.api.onLogError(_showLogErrorModal);
}

function _displacedBannerShow(info) {
  let banner = document.getElementById('displaced-banner');
  if (!banner) {
    banner = document.createElement('div');
    banner.id = 'displaced-banner';
    banner.className = 'displaced-banner';
    document.body.appendChild(banner);
  }
  const platform = (info.byPlatform || '').toLowerCase();
  const friendly = (() => {
    if (platform.includes('ios')) return '📱 Your iPhone took over the rig.';
    if (platform.includes('android')) return '📱 Your Android took over the rig.';
    if (platform.includes('desktop')) return '💻 Another POTACAT desktop took over the rig.';
    if (platform.includes('browser') || platform.includes('web')) return '🌐 An ECHOCAT browser tab took over the rig.';
    return '⚠️ Another device took over the rig.';
  })();
  const sub = 'Reconnect to take it back — the other device will be displaced.';
  banner.innerHTML = '<div class="displaced-banner-msg">' + friendly + ' ' + sub + '</div>'
    + '<div class="displaced-banner-actions">'
    + '<button type="button" id="displaced-reconnect" class="primary">Reconnect</button>'
    + '<button type="button" id="displaced-dismiss">Dismiss</button>'
    + '</div>';
  banner.classList.remove('hidden');
  document.getElementById('displaced-dismiss').addEventListener('click', () => banner.classList.add('hidden'));
  document.getElementById('displaced-reconnect').addEventListener('click', async () => {
    banner.classList.add('hidden');
    // Re-activate the same target — server will displace the new
    // tenant in turn.
    try {
      const status = await window.api.connectionTargetsGetStatus();
      if (status && status.targetId) {
        await window.api.connectionTargetsActivate(status.targetId);
      } else {
        // Fall back to the last connection-targets list head.
        const list = await window.api.connectionTargetsList();
        const t = (list || []).find(t => t.lastConnectedAt) || (list || [])[0];
        if (t) await window.api.connectionTargetsActivate(t.id);
      }
    } catch (err) {
      alert('Reconnect failed: ' + (err.message || err));
    }
  });
}
if (window.api && window.api.onRemoteClientDisplaced) {
  window.api.onRemoteClientDisplaced(_displacedBannerShow);
}

// Active-remote-shack status chip. Hidden unless this desktop is in
// remote-client mode. State driven by the same onRemoteClientStatus
// stream the Remote Radios dialog uses; the chip is the always-on
// surface so users notice WHICH shack the rig pane is showing.
(function _remoteChipWire() {
  const chip = document.getElementById('remote-shack-status');
  if (!chip) return;
  let _lastChipState = null;
  const setChip = (state) => {
    _lastChipState = state;
    if (!state || state.state === 'idle') {
      chip.classList.add('hidden');
      chip.textContent = 'REMOTE';
      return;
    }
    chip.classList.remove('hidden');
    const name = state.name || 'shack';
    const leg = state.leg ? (' · ' + state.leg.toUpperCase()) : '';
    if (state.state === 'connected') {
      chip.textContent = '🔗 ' + name + leg;
      chip.style.background = '#4ecca3';
      chip.style.color = '#0a1a14';
      chip.title = 'Connected to ' + name + ' — click to manage';
    } else if (state.state === 'connecting' || state.state === 'authing') {
      chip.textContent = '🔗 ' + name + ' · connecting';
      chip.style.background = '#d4a64a';
      chip.style.color = '#1a1a2e';
      chip.title = 'Dialing ' + name + '…';
    } else if (state.state === 'disconnected') {
      chip.textContent = '🔗 ' + name + ' · reconnecting';
      chip.style.background = '#d4a64a';
      chip.style.color = '#1a1a2e';
      chip.title = 'Lost connection to ' + name + ' — auto-reconnecting';
    } else if (state.state === 'auth-fail') {
      chip.textContent = '🔗 ' + name + ' · re-pair';
      chip.style.background = '#e94560';
      chip.style.color = '#fff';
      chip.title = 'Auth failed (' + (state.reason || 'expired') + ') — open Remote Radios to re-pair';
    } else if (state.state === 'pass-ended') {
      chip.textContent = '🎟 Guest Pass ended';
      chip.style.background = '#e94560';
      chip.style.color = '#fff';
      chip.title = 'Guest Pass session ended (' + (state.reason || 'expired') + ') — back on the local rig';
    } else if (state.state === 'revoked') {
      chip.textContent = '🔗 pairing revoked';
      chip.style.background = '#e94560';
      chip.style.color = '#fff';
      chip.title = 'The shack operator revoked this desktop\'s pairing (' + (state.reason || 'revoked') + ') — back on the local rig';
    }
  };
  chip.addEventListener('click', _remoteRadiosOpen);
  if (window.api && window.api.onRemoteClientStatus) {
    window.api.onRemoteClientStatus(setChip);
    // Loud, app-wide notice when a Guest Pass session ends — the user may
    // be nowhere near the Remote Radios dialog when the clock runs out.
    window.api.onRemoteClientStatus((s) => {
      if (s && s.state === 'pass-ended' && typeof showLogToast === 'function') {
        showLogToast('Guest Pass session ended (' + (s.reason || 'expired') + ') — switched back to your local rig.', { warn: true, duration: 8000 });
      }
      if (s && s.state === 'revoked' && typeof showLogToast === 'function') {
        showLogToast('The shack operator revoked this desktop\'s pairing — switched back to your local rig.', { warn: true, duration: 8000 });
      }
    });
  }
  // Guest Pass redeemed via a potacat://pass/ deep link (landing-page
  // button) — surface the outcome even with no dialog open.
  if (window.api && window.api.onGuestPassRedeemed) {
    window.api.onGuestPassRedeemed((r) => {
      if (typeof showLogToast !== 'function') return;
      if (r && r.ok) {
        const until = r.expiresAt ? new Date(r.expiresAt).toLocaleTimeString() : '?';
        showLogToast('🎟 Guest Pass active — connecting to ' + (r.owner || r.name) + ' (until ' + until + ').', { duration: 6000 });
      } else {
        showLogToast('Guest Pass failed: ' + ((r && r.error) || 'unknown error'), { warn: true, duration: 8000 });
      }
    });
  }
  // Phase 2 audio leg: bring up the rig-audio answerer (listen to the remote
  // rig; mic stays muted until PTT) when connected to a remote shack, tear it
  // down on drop, and gate the voice push-to-talk button on that same state.
  // The shack mints TURN creds and offers; the hidden answerer window plays
  // the audio. Idempotent — start/stop fire only on a real connected→not edge.
  if (window.api && window.api.onRemoteClientStatus && window.api.remoteClientAudioStart) {
    const pttBtn = document.getElementById('remote-ptt-btn');
    const ptt = (typeof RemotePttController === 'function')
      ? new RemotePttController({
          sendPtt: (on) => { try { window.api.remoteClientAudioPtt(on); } catch (e) {} },
          onChange: (keyed) => {
            if (!pttBtn) return;
            pttBtn.textContent = keyed ? '🔴 ON AIR' : '🎙 HOLD TO TALK';
            pttBtn.style.background = keyed ? '#ff2d55' : '#e94560';
          },
        })
      : null;
    // Press-and-hold (mouse + touch). Release on pointerup / pointerleave /
    // pointercancel / window blur so a dragged-off, interrupted, or alt-tabbed
    // press can NEVER leave the remote rig stuck keyed. No keyboard PTT — an
    // explicit hold is the only way to transmit (no accidental TX).
    if (pttBtn && ptt) {
      const down = (e) => { e.preventDefault(); ptt.down(); };
      const up = () => { ptt.up(); };
      pttBtn.addEventListener('pointerdown', down);
      pttBtn.addEventListener('pointerup', up);
      pttBtn.addEventListener('pointerleave', up);
      pttBtn.addEventListener('pointercancel', up);
      window.addEventListener('blur', up);
    }
    let _racOn = false;
    window.api.onRemoteClientStatus((s) => {
      const connected = !!(s && s.state === 'connected');
      if (connected && !_racOn) {
        _racOn = true;
        window.api.remoteClientAudioStart().catch(() => {});
      } else if (!connected && _racOn) {
        _racOn = false;
        try { window.api.remoteClientAudioStop(); } catch (e) {}
      }
      if (ptt) ptt.setActive(connected); // force-releases TX if we just dropped
      if (pttBtn) pttBtn.classList.toggle('hidden', !connected);
    });
  }
  // Hydrate on load.
  if (window.api && window.api.connectionTargetsGetStatus) {
    window.api.connectionTargetsGetStatus().then(setChip).catch(() => {});
  }
})();

// ─── Pair My Device dialog (unified pair entry point, v1.9) ─────────
//
// Single dialog hosting both pairing methods:
//   📱 QR — for in-person mobile pairing (5-min single-use)
//   💻 Link — for own laptop or off-site friend (1h–30d, owned/guest)
// Replaces the old separate "Pair my device" QR popout and "Pair my
// laptop" link dialog. Wires to the same backend (echocatCreatePairingQr
// for QR, pairLinkCreate for link).

let _pairLinkCurrentToken = null;
let _pairLinkCurrentLink = null;
let _pairDeviceQrTtlTimer = null;
let _pairDeviceQrLastData = null;

function _pairDeviceOpen() {
  const dlg = document.getElementById('pair-device-dialog');
  if (!dlg) return;
  _pairLinkCurrentToken = null;
  _pairLinkCurrentLink = null;
  if (!dlg.open) dlg.showModal();
  _pairLinkRefreshList();
  // Auto-generate a pair URL the moment the dialog opens. The QR
  // encodes the same URL the Copy button puts on the clipboard — the
  // user scans on a phone OR copies for a desktop/laptop. One flow.
  _pairDeviceQrGenerate();
}

// The Pair-my-device dialog now always mints an OWNED, 24-hour, single-
// use pair link via the same pairLinkCreate IPC the link flow used to
// use. The QR renders the resulting URL; Copy URL puts the same string
// on the clipboard. Guest access is the separate "Share my rig" flow.
const _PAIR_DEVICE_TTL_MS = 24 * 60 * 60 * 1000;

async function _pairDeviceQrGenerate() {
  const svgEl = document.getElementById('pair-device-qr-svg');
  const imgEl = document.getElementById('pair-device-qr-img');
  const fallback = document.getElementById('pair-device-qr-fallback');
  const ttlEl = document.getElementById('pair-device-qr-ttl');
  const status = document.getElementById('pair-device-qr-status');
  const regen = document.getElementById('pair-device-qr-regen');
  const copyBtn = document.getElementById('pair-device-qr-copy-url');

  if (_pairDeviceQrTtlTimer) { clearInterval(_pairDeviceQrTtlTimer); _pairDeviceQrTtlTimer = null; }
  if (regen) { regen.disabled = true; regen.textContent = 'Generating…'; }
  if (copyBtn) copyBtn.disabled = true;
  if (status) status.textContent = '';

  // Revoke the previous link this dialog minted (if any) so the
  // pending list doesn't pile up one row per Regenerate click.
  const prevToken = _pairDeviceQrLastData && _pairDeviceQrLastData.token;
  if (prevToken) {
    try { await window.api.pairLinkRevoke(prevToken); } catch {}
    _pairDeviceQrLastData = null;
  }

  let r;
  try { r = await window.api.pairLinkCreate({ ttlMs: _PAIR_DEVICE_TTL_MS, trust: 'owned' }); }
  catch (err) {
    if (status) status.textContent = 'Pair URL failed: ' + (err.message || err);
    if (regen) { regen.disabled = false; regen.textContent = 'Regenerate'; }
    return;
  }
  if (r && r.error) {
    if (status) status.textContent = r.error;
    if (regen) { regen.disabled = false; regen.textContent = 'Regenerate'; }
    if (svgEl) svgEl.style.display = 'none';
    if (imgEl) imgEl.style.display = 'none';
    return;
  }
  _pairDeviceQrLastData = r;
  if (copyBtn) copyBtn.disabled = !r.url;

  // Render QR. SVG first (crisp), PNG fallback, then text-only fallback.
  let shown = false;
  if (svgEl && r.qrSvg) {
    try {
      svgEl.innerHTML = r.qrSvg;
      if (svgEl.querySelector('svg')) {
        svgEl.style.display = '';
        if (imgEl) imgEl.style.display = 'none';
        if (fallback) fallback.style.display = 'none';
        shown = true;
      }
    } catch {}
  }
  if (!shown && imgEl && r.qrDataUrl) {
    imgEl.onerror = () => {
      imgEl.style.display = 'none';
      if (fallback) fallback.style.display = '';
    };
    imgEl.src = r.qrDataUrl;
    imgEl.style.display = '';
    if (svgEl) svgEl.style.display = 'none';
    if (fallback) fallback.style.display = 'none';
    shown = true;
  }
  if (!shown) {
    if (svgEl) svgEl.style.display = 'none';
    if (imgEl) imgEl.style.display = 'none';
    if (fallback) fallback.style.display = '';
  }
  if (svgEl) svgEl.style.opacity = '1';
  if (imgEl) imgEl.style.opacity = '1';

  // TTL countdown — formatted for hours+minutes since the link lifetime
  // is hours-to-days, not single-digit minutes like the old QR popout.
  // Once the link expires, blank the Copy button and dim the QR.
  if (ttlEl) ttlEl.classList.remove('expired');
  const fmt = (ms) => {
    if (ms <= 0) return 'expired';
    const totalSec = Math.floor(ms / 1000);
    const h = Math.floor(totalSec / 3600);
    const m = Math.floor((totalSec % 3600) / 60);
    const s = totalSec % 60;
    if (h > 0) return h + 'h ' + String(m).padStart(2, '0') + 'm';
    if (m > 0) return m + ':' + String(s).padStart(2, '0');
    return s + 's';
  };
  const tick = () => {
    const remaining = r.expiresAt - Date.now();
    if (remaining <= 0) {
      if (ttlEl) {
        ttlEl.textContent = 'Link expired — click Regenerate.';
        ttlEl.classList.add('expired');
      }
      if (svgEl) svgEl.style.opacity = '0.3';
      if (imgEl) imgEl.style.opacity = '0.3';
      if (copyBtn) copyBtn.disabled = true;
      _pairDeviceQrLastData = null;
      if (_pairDeviceQrTtlTimer) { clearInterval(_pairDeviceQrTtlTimer); _pairDeviceQrTtlTimer = null; }
      return;
    }
    if (ttlEl) ttlEl.textContent = 'Link expires in ' + fmt(remaining);
  };
  tick();
  _pairDeviceQrTtlTimer = setInterval(tick, 1000);

  if (regen) { regen.disabled = false; regen.textContent = 'Regenerate'; }
}

function _pairDeviceTeardownQrTimers() {
  if (_pairDeviceQrTtlTimer) { clearInterval(_pairDeviceQrTtlTimer); _pairDeviceQrTtlTimer = null; }
}

async function _pairLinkRefreshList() {
  const listEl = document.getElementById('pair-link-list');
  if (!listEl) return;
  let list = [];
  try { list = await window.api.pairLinkList(); } catch {}
  if (!Array.isArray(list) || list.length === 0) {
    listEl.innerHTML = '<li class="pair-link-empty">No pending links.</li>';
    return;
  }
  // Newest first, used/expired drop to the bottom so the active
  // links are the operator's first read.
  const now = Date.now();
  list.sort((a, b) => {
    const aActive = !a.used && a.expiresAt > now;
    const bActive = !b.used && b.expiresAt > now;
    if (aActive !== bActive) return aActive ? -1 : 1;
    return b.createdAt - a.createdAt;
  });
  const fmtRel = (ms) => {
    if (ms <= 0) return 'expired';
    const m = Math.floor(ms / 60000);
    if (m < 60) return m + 'm left';
    const h = Math.floor(m / 60);
    if (h < 24) return h + 'h left';
    const d = Math.floor(h / 24);
    return d + 'd left';
  };
  listEl.innerHTML = list.map(l => {
    const remaining = l.expiresAt - now;
    let statusCls = 'active';
    let statusTxt = fmtRel(remaining);
    if (l.used) { statusCls = 'used'; statusTxt = 'used'; }
    else if (remaining <= 0) { statusCls = 'expired'; statusTxt = 'expired'; }
    const label = l.label ? '<span class="pll-label">' + _esc(l.label) + '</span> · ' : '';
    const created = new Date(l.createdAt).toLocaleDateString();
    const trustTag = l.trust === 'owned' ? '🔒 ' : '👤 ';
    return '<li>'
      + '<div class="pll-meta">' + trustTag + label + 'created ' + _esc(created) + '</div>'
      + '<span class="pll-status ' + statusCls + '">' + statusTxt + '</span>'
      + '<button type="button" class="pll-revoke" data-act="pll-revoke" data-token="' + _esc(l.token) + '">Remove</button>'
      + '</li>';
  }).join('');
}

async function _pairLinkRevoke(token, confirmFirst) {
  if (!token) return;
  if (confirmFirst && !confirm('Revoke this pair link? Anyone holding it can no longer pair.')) return;
  try { await window.api.pairLinkRevoke(token); } catch {}
  // If the operator revoked the link currently showing on the QR,
  // clear our cached pointer so Copy URL stops working until a new
  // one is generated.
  if (_pairDeviceQrLastData && _pairDeviceQrLastData.token === token) {
    _pairDeviceQrLastData = null;
    const copyBtn = document.getElementById('pair-device-qr-copy-url');
    if (copyBtn) copyBtn.disabled = true;
  }
  _pairLinkRefreshList();
}

// Listen for pair-link redemption results pushed from main when this
// desktop opens a potacat://pair?... URL (emailed link, second-instance
// argv, or cold-start argv). Shown as a non-blocking confirmation so
// the operator knows the pair landed and which leg succeeded. The
// Remote Radios panel (task #13) will be the persistent UI for the
// resulting connectionTargets row.
if (window.api && window.api.onPairLinkRedeemed) {
  window.api.onPairLinkRedeemed((r) => {
    if (!r) return;
    if (r.ok) {
      const note = 'Paired with ' + (r.name || 'remote shack') + ' via ' + (r.leg || 'unknown') + '. Opens from More → Remote Radios.';
      try { alert(note); } catch {}
    } else {
      try { alert('Pair link redemption failed: ' + (r.error || 'unknown error')); } catch {}
    }
  });
}

(function _pairDeviceWire() {
  const dlg = document.getElementById('pair-device-dialog');
  if (!dlg) return;

  const closeBtn = document.getElementById('pair-device-close');
  if (closeBtn) closeBtn.addEventListener('click', () => dlg.close());

  const qrRegen = document.getElementById('pair-device-qr-regen');
  if (qrRegen) qrRegen.addEventListener('click', () => _pairDeviceQrGenerate());

  const qrCopy = document.getElementById('pair-device-qr-copy-url');
  if (qrCopy) qrCopy.addEventListener('click', () => {
    const url = _pairDeviceQrLastData && _pairDeviceQrLastData.url;
    if (!url) return;
    window.api.copyToClipboard(url);
    const prev = qrCopy.textContent;
    qrCopy.textContent = 'Copied';
    setTimeout(() => { qrCopy.textContent = prev; }, 1400);
  });

  // Stop the TTL timer when the dialog closes; otherwise it keeps
  // ticking for nothing and the next open double-stacks timers.
  // _pairDeviceQrLastData stays set so the live link can be reused
  // on reopen — but the QR view itself re-renders to keep the UI
  // consistent.
  dlg.addEventListener('close', () => {
    _pairDeviceTeardownQrTimers();
  });

  const refresh = document.getElementById('pair-link-refresh');
  if (refresh) refresh.addEventListener('click', _pairLinkRefreshList);

  // Delegated revoke clicks inside the pending-links list.
  const listEl = document.getElementById('pair-link-list');
  if (listEl) listEl.addEventListener('click', (e) => {
    const b = e.target.closest('[data-act="pll-revoke"]');
    if (!b) return;
    const token = b.dataset.token;
    _pairLinkRevoke(token, true);
  });

  // Live push from main when a link is consumed or persisted — keeps
  // the pending list fresh without manual Refresh.
  if (window.api && window.api.onPairLinksUpdated) {
    window.api.onPairLinksUpdated(() => {
      if (dlg.open) _pairLinkRefreshList();
    });
  }
})();

// Electron renderers block window.prompt(). This is a Promise-based
// drop-in: opens a small modal with an input, returns the trimmed value
// on OK or null on Cancel / Esc / backdrop click.
function _summaryPrompt({ title, message, defaultValue = '', placeholder = '', upper = false }) {
  return new Promise((resolve) => {
    const dlg = document.getElementById('ask-prompt-dialog');
    const titleEl = document.getElementById('ask-prompt-title');
    const msgEl = document.getElementById('ask-prompt-message');
    const input = document.getElementById('ask-prompt-input');
    const okBtn = document.getElementById('ask-prompt-ok');
    const cancelBtn = document.getElementById('ask-prompt-cancel');
    if (!dlg || !input) { resolve(null); return; }
    titleEl.textContent = title || 'Enter value';
    msgEl.textContent = message || '';
    msgEl.style.display = message ? 'block' : 'none';
    input.value = defaultValue || '';
    input.placeholder = placeholder || '';
    input.style.textTransform = upper ? 'uppercase' : 'none';

    let done = false;
    const cleanup = (val) => {
      if (done) return;
      done = true;
      input.removeEventListener('keydown', onKey);
      okBtn.removeEventListener('click', onOk);
      cancelBtn.removeEventListener('click', onCancel);
      dlg.removeEventListener('close', onClose);
      try { dlg.close(); } catch {}
      resolve(val);
    };
    const onKey = (e) => {
      if (e.key === 'Enter') { e.preventDefault(); onOk(); }
      else if (e.key === 'Escape') { e.preventDefault(); onCancel(); }
    };
    const onOk = () => {
      const v = String(input.value || '').trim();
      cleanup(v || null);
    };
    const onCancel = () => cleanup(null);
    const onClose = () => cleanup(null);

    input.addEventListener('keydown', onKey);
    okBtn.addEventListener('click', onOk);
    cancelBtn.addEventListener('click', onCancel);
    dlg.addEventListener('close', onClose);
    if (typeof dlg.showModal === 'function') dlg.showModal();
    else dlg.setAttribute('open', '');
    setTimeout(() => { try { input.focus(); input.select(); } catch {} }, 0);
  });
}

async function _summaryOpAddPrompt() {
  const input = await _summaryPrompt({
    title: 'Add operator',
    message: 'Enter the operator’s callsign. POTACAT will create a fresh profile and switch to it.',
    placeholder: 'WB6ACU',
    upper: true,
  });
  if (input == null) return;
  const call = String(input).toUpperCase().trim();
  if (!call) return;
  const r = await window.api.profilesAdd(call);
  if (!r || !r.ok) {
    alert('Could not add operator: ' + (r && r.error ? r.error : 'unknown error'));
    return;
  }
  // Switch into the new profile so the user can finish filling out grid,
  // QRZ creds, etc. with a clean slate. Switch triggers a restart.
  const sw = await window.api.profilesSwitch(call);
  if (!sw || !sw.ok) {
    alert('Operator added, but switching failed: ' + (sw && sw.error ? sw.error : 'unknown'));
    refreshSummaryCard();
  }
  // On success, app is about to relaunch — no need to refresh.
}

async function _summaryOpSwitch(call) {
  if (!call) return;
  if (!confirm('Switch to operator ' + call + '? POTACAT will restart to apply.')) {
    // Revert the dropdown to the active value
    refreshSummaryCard();
    return;
  }
  const r = await window.api.profilesSwitch(call);
  if (!r || !r.ok) {
    alert('Could not switch operator: ' + (r && r.error ? r.error : 'unknown'));
    refreshSummaryCard();
  }
  // On success, app is about to relaunch.
}

async function _summaryOpOpenManage() {
  const dlg = document.getElementById('operators-dialog');
  if (!dlg) return;
  await _summaryOpRenderManageList();
  if (typeof dlg.showModal === 'function') dlg.showModal();
}

async function _summaryOpRenderManageList() {
  const list = document.getElementById('operators-list');
  if (!list) return;
  let active = '';
  let profiles = [];
  try {
    const r = await window.api.profilesList();
    active = (r && r.active) || '';
    profiles = (r && r.profiles) || [];
  } catch {}
  if (profiles.length === 0) {
    list.innerHTML = '<div class="operators-empty">No operators yet. Use "+ Add operator" on the Summary tab.</div>';
    return;
  }
  const esc = (s) => String(s).replace(/[&<>"']/g, (c) => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
  list.innerHTML = profiles.map(c => {
    const isActive = c === active;
    return '<div class="operators-row' + (isActive ? ' active' : '') + '">'
      + '<div><span class="operators-row-name">' + esc(c) + '</span>'
      + (isActive ? '<span class="operators-row-tag">Active</span>' : '')
      + '</div>'
      + (isActive
          ? '<span class="summary-card-sub">Switch first to archive</span>'
          : '<button type="button" data-act="op-archive" data-call="' + esc(c) + '">Archive</button>')
      + '</div>';
  }).join('');
}

async function _renderSummaryLogbook() {
  const totalEl = document.getElementById('summary-log-total');
  const ssbEl = document.getElementById('summary-log-ssb');
  const cwEl = document.getElementById('summary-log-cw');
  const digiEl = document.getElementById('summary-log-digi');
  const sstvEl = document.getElementById('summary-log-sstv');
  const connEl = document.getElementById('summary-log-conn');
  if (!totalEl) return;
  try {
    const c = await window.api.getQsoCounts();
    const fmt = (n) => (n || 0).toLocaleString();
    totalEl.textContent = fmt(c.total);
    ssbEl.textContent = fmt(c.ssb);
    cwEl.textContent = fmt(c.cw);
    digiEl.textContent = fmt(c.digital);
    sstvEl.textContent = fmt(c.sstv);
    if (connEl) {
      const s = await window.api.getSettings();
      const call = s && s.myCallsign ? String(s.myCallsign).toUpperCase() : '';
      connEl.textContent = call ? 'Connected: ' + call : '';
    }
  } catch {
    totalEl.textContent = '—';
  }
}

// Multi-host renderer: the Cloud card is shown both on Summary AND on
// the ECHOCAT settings tab (Casey wants the same control surface in
// both places). Builds the inner HTML once from a single fetch, then
// injects into every `[data-summary-card="cloud"]` host.
async function _renderSummaryCloud() {
  const hosts = document.querySelectorAll('[data-summary-card="cloud"]');
  if (hosts.length === 0) return;
  let html = '';
  try {
    const status = await window.api.cloudGetStatus();
    html = _buildCloudCardHTML(status);
  } catch (err) {
    html = _buildCloudCardHTML(null);
  }
  for (const host of hosts) host.innerHTML = html;
}

function _buildCloudCardHTML(status) {
  if (!status) {
    return _summaryCardChrome('POTACAT Cloud', '—', '',
      '<div class="summary-line">(Cloud status unavailable)</div>', '');
  }
  const loggedIn = !!status.loggedIn;
  const sub = status.subscription || null;
  const subStatus = sub && sub.status ? String(sub.status).toLowerCase() : '';
  const trial = !!(sub && (sub.trialActive === true || subStatus === 'trial'));
  const active = subStatus === 'active' || trial;
  // "Manage subscription" is honest about where the button goes —
  // cloud-open-manage opens the BMAC membership page.
  const syncActions = '<button type="button" class="primary" data-act="cloud-sync-now">Sync now</button>'
    + '<button type="button" data-act="cloud-manage">Manage subscription</button>';
  let pillTxt, pillCls, backupTxt, metaTxt, actions;
  if (!loggedIn) {
    pillTxt = 'Inactive'; pillCls = 'bad';
    backupTxt = 'Your logbook is NOT backed up to the POTACAT Cloud.';
    metaTxt = 'Sign up for a free trial to enable QSO + settings backup.';
    actions = '<button type="button" class="primary" data-act="cloud-signup">Sign up — Free trial</button>';
  } else if (trial) {
    pillTxt = 'Free Trial'; pillCls = 'warn';
    backupTxt = 'Your logbook is backed up to the POTACAT Cloud.';
    metaTxt = _summaryFormatLastSync(status);
    actions = syncActions;
  } else if (active) {
    pillTxt = 'Active'; pillCls = 'ok';
    backupTxt = 'Your logbook is backed up to the POTACAT Cloud.';
    metaTxt = _summaryFormatLastSync(status);
    actions = syncActions;
  } else {
    pillTxt = 'Signed in'; pillCls = '';
    backupTxt = 'Your logbook is NOT backed up — no active subscription.';
    metaTxt = '';
    actions = '<button type="button" class="primary" data-act="cloud-signup">Subscribe</button>';
  }
  const body = '<div class="summary-line">' + _esc(backupTxt) + '</div>'
    + '<div class="summary-sub">' + _esc(metaTxt) + '</div>'
    + '<div class="summary-card-actions">' + actions + '</div>';
  return _summaryCardChrome('POTACAT Cloud', pillTxt, pillCls, body);
}

// Tiny helper to keep card head HTML consistent across all builders.
function _summaryCardChrome(title, pillText, pillCls, bodyHTML) {
  const pill = pillText
    ? '<span class="summary-pill ' + (pillCls || '') + '">' + _esc(pillText) + '</span>'
    : '';
  return '<div class="summary-card-head">'
    + '<span class="summary-card-title">' + _esc(title) + '</span>'
    + pill
    + '</div>'
    + '<div class="summary-card-body">' + bodyHTML + '</div>';
}

function _summaryFormatLastSync(status) {
  // Source priority: lastSyncAt (set on manual Sync Now) → lastSyncTimestamp
  // (the journal cursor — updated on auto-sync) → status.sync.lastSyncAt
  // (server-reported, present even when local cache is empty after a
  // fresh install). Falls back to "No sync yet" only when truly nothing.
  let ts = 0;
  if (status) {
    ts = status.lastSyncAt || status.lastSyncTimestamp || 0;
    if (!ts && status.sync && (status.sync.lastSyncAt || status.sync.lastSyncTimestamp)) {
      ts = status.sync.lastSyncAt || status.sync.lastSyncTimestamp;
    }
  }
  if (!ts) return 'No sync yet on this device.';
  const d = new Date(ts);
  if (isNaN(d.getTime())) return '';
  const ago = Date.now() - d.getTime();
  if (ago < 60000) return 'Last sync: just now.';
  if (ago < 3600000) return 'Last sync: ' + Math.floor(ago / 60000) + ' min ago.';
  if (ago < 86400000) return 'Last sync: ' + Math.floor(ago / 3600000) + ' h ago.';
  return 'Last sync: ' + d.toLocaleDateString();
}

// Multi-host renderer: ECHOCAT card lives on Summary + ECHOCAT tabs.
async function _renderSummaryEchocat() {
  const hosts = document.querySelectorAll('[data-summary-card="echocat"]');
  if (hosts.length === 0) return;
  // Fetch state once; render to all hosts.
  let tunnel = null;
  let tail = null;
  let devices = [];
  let web = null;
  try { tunnel = await window.api.cloudTunnelGetState(); } catch {}
  try { tail = await window.api.echocatTailscaleStatus(); } catch {}
  try { devices = await window.api.echocatListPairedDevices(); } catch {}
  // Browser web-access info — the free, no-app, no-cloud path. The
  // server is always-on; we just need the LAN address(es) + token.
  try {
    const s = await window.api.getSettings();
    const ips = await window.api.getLocalIPs();
    const port = s.remotePort || 7300;
    // Prefer real-LAN addresses for the browser-on-same-WiFi case;
    // Tailscale (100.x) is the remote path the card's pill already
    // covers, so it shouldn't headline the "open in a browser" block.
    const lan = (ips || []).filter((ip) => !ip.tailscale);
    const list = (lan.length ? lan : (ips || [])).map((ip) => ip.address);
    // Tailscale URL for off-network browser access (the LAN IP only
    // works at home). Prefer the MagicDNS hostname — the Tailscale-
    // issued cert is valid for it, so no cert warning; fall back to the
    // 100.x IP only when MagicDNS is off. Casey 2026-06-13.
    let tailscaleUrl = '';
    let tailscaleCertValid = false;
    const tsHost = (tail && tail.installed && tail.loggedIn && tail.hostname) ? String(tail.hostname) : '';
    if (tsHost) {
      tailscaleUrl = 'https://' + tsHost + ':' + port;
      tailscaleCertValid = true;
    } else {
      const tsIp = (ips || []).find((ip) => ip.tailscale);
      if (tsIp) tailscaleUrl = 'https://' + tsIp.address + ':' + port;
    }
    web = {
      addresses: list,
      port,
      token: (s.remoteRequireToken !== false) ? (s.remoteToken || '') : '',
      tailscaleUrl,
      tailscaleCertValid,
    };
  } catch {}
  const html = _buildEchocatCardHTML(tunnel, tail, devices, web);
  for (const host of hosts) host.innerHTML = html;
}

// The free, no-app, no-cloud path: a browser on the same WiFi opens the
// always-on ECHOCAT server directly. Promoted onto the card so it has
// equal billing with Pair / Cloud instead of hiding in a collapsed
// accordion (Casey 2026-06-13 — "make it available for users who don't
// want to pay").
function _buildEchocatWebHTML(web) {
  if (!web || !Array.isArray(web.addresses) || web.addresses.length === 0) {
    return '<div class="echo-web">'
      + '<div class="echo-web-head"><span class="echo-web-title">Open in a browser</span>'
      + '<span class="echo-web-tag">no app needed</span></div>'
      + '<div class="echo-web-empty">No local network detected — connect this computer to your WiFi/LAN to get a browser link.</div>'
      + '</div>';
  }
  const primary = 'https://' + web.addresses[0] + ':' + web.port;
  const extras = web.addresses.slice(1).map((a) => 'https://' + a + ':' + web.port);
  const hasTs = !!web.tailscaleUrl;
  // One URL row: optional label, the url, a copy button.
  const urlRow = (label, url, isPrimary) =>
    (label ? '<div class="echo-web-rowlabel">' + label + '</div>' : '')
    + '<div class="echo-web-urlrow">'
    + '<code class="echo-web-url">' + _esc(url) + '</code>'
    + '<button type="button" class="echo-web-copy' + (isPrimary ? ' primary' : '') + '" data-act="echo-copy-weburl" data-copy="' + _esc(url) + '" title="Copy link">Copy</button>'
    + '</div>';
  // When a Tailscale URL exists, label the two so users know which
  // works where; the LAN one only works on the home network.
  const lanBlock = urlRow(hasTs ? 'On your WiFi (home)' : '', primary, !hasTs);
  const tsBlock = hasTs
    ? urlRow('Away from home (Tailscale)', web.tailscaleUrl, true)
      + (web.tailscaleCertValid
        ? ''
        : '<div class="echo-web-extra">MagicDNS is off — this uses your Tailscale IP, so you\'ll get a certificate warning. Turn on MagicDNS for a clean link.</div>')
    : '';
  const tokenLine = web.token
    ? '<div class="echo-web-token">Token <code>' + _esc(web.token) + '</code>'
      + '<button type="button" class="echo-web-copy" data-act="echo-copy-weburl" data-copy="' + _esc(web.token) + '" title="Copy token">Copy</button></div>'
    : '';
  const extrasLine = extras.length
    ? '<div class="echo-web-extra">Other home addresses: ' + extras.map((u) => '<code>' + _esc(u) + '</code>').join(', ') + '</div>'
    : '';
  const hint = hasTs
    ? 'Use the WiFi link at home; the Tailscale link works anywhere both devices are signed into your tailnet. Must be <code>https://</code>; accept the warning the first time.'
    : 'Type it into any phone, tablet, or computer on your home WiFi. Must be <code>https://</code>; accept the security warning the first time.';
  return '<div class="echo-web">'
    + '<div class="echo-web-head">'
    + '<span class="echo-web-title">Open in a browser</span>'
    + '<span class="echo-web-tag">no app needed</span>'
    + '</div>'
    + lanBlock
    + tsBlock
    + tokenLine
    + extrasLine
    + '<div class="echo-web-hint">' + hint + '</div>'
    + '</div>';
}

function _buildEchocatCardHTML(tunnel, tail, devices, web) {
  // Tunnel + Tailscale state. cloud-tunnel state lives on `.status`,
  // not `.state`. Possible values: off | provisioning | connecting |
  // live | reconnecting | error (see lib/cloud-tunnel.js).
  let pillTxt = 'LAN only';
  let pillCls = '';
  let detail = '';
  let tunnelEnabled = false;
  let tunnelState = 'off';
  if (tunnel) {
    tunnelEnabled = !!tunnel.enabled;
    tunnelState = String(tunnel.status || 'off');
    if (tunnelState === 'live') {
      pillTxt = 'Cloud Tunnel'; pillCls = 'ok';
      detail = 'Available remotely via POTACAT Cloud tunnel.';
    } else if (tunnelState === 'connecting' || tunnelState === 'provisioning' || tunnelState === 'reconnecting') {
      pillTxt = tunnelState === 'provisioning' ? 'Provisioning…' : 'Connecting…';
      pillCls = 'warn';
      detail = 'POTACAT Cloud tunnel is ' + tunnelState + '.';
    } else if (tunnelState === 'error') {
      pillTxt = 'Tunnel error'; pillCls = 'bad';
      detail = tunnel.lastError ? ('Tunnel error: ' + tunnel.lastError) : 'POTACAT Cloud tunnel reported an error.';
    }
  }
  if (pillCls === '' && tail && tail.installed && tail.loggedIn) {
    pillTxt = 'Tailscale'; pillCls = 'ok';
    detail = tail.hostname
      ? 'Available remotely via Tailscale (' + tail.hostname + ').'
      : 'Available remotely via Tailscale (tailnet connected; MagicDNS off, use the device IP).';
  } else if (pillCls === '' && tail && tail.installed && !tail.loggedIn) {
    detail = 'Tailscale is installed but not connected. Sign in to your tailnet, or enable POTACAT Cloud Tunnel.';
  }
  if (pillCls === '' && !detail) {
    detail = 'Available only on the local network. Enable POTACAT Cloud Tunnel or connect to your tailnet for remote access.';
  }
  // Tunnel toggle button text — reflects user-intent (enabled) not the
  // momentary status, so it doesn't flicker mid-startup.
  const tunnelEffectivelyOn = tunnelEnabled
    || tunnelState === 'live' || tunnelState === 'connecting'
    || tunnelState === 'provisioning' || tunnelState === 'reconnecting';
  const tunnelBtn = tunnelEffectivelyOn
    ? '<button type="button" data-act="tunnel-off">Turn off tunnel</button>'
    : '<button type="button" class="primary" data-act="tunnel-on">Turn on Cloud Tunnel</button>';
  // Order (Casey 2026-06-13): the remote-access status line first
  // ("Available remotely via POTACAT Cloud Tunnel" / "…local network
  // only"), THEN the browser block (On your WiFi / Away from home),
  // then devices + actions.
  const body = '<div class="summary-line">' + _esc(detail) + '</div>'
    + _buildEchocatWebHTML(web)
    + '<div class="summary-sub" style="margin-top:6px;font-weight:600;">My devices</div>'
    + '<div class="summary-device-list">' + _summaryDeviceListHTML(devices) + '</div>'
    + '<div class="summary-card-actions">'
    + '<button type="button" data-act="echo-pair-device">Pair my device&hellip;</button>'
    + '<button type="button" data-act="echo-share">Share my rig&hellip;</button>'
    + tunnelBtn
    + '<button type="button" data-act="echo-diagnostics" title="Cloud Tunnel diagnostics">Diagnostics</button>'
    + '</div>';
  return _summaryCardChrome('ECHOCAT', pillTxt, pillCls, body);
}

function _summaryDeviceListHTML(devices) {
  if (!Array.isArray(devices) || devices.length === 0) {
    return '<div class="summary-empty">No paired devices. Tap "Pair device" to connect a phone or tablet.</div>';
  }
  const fmtAge = (ts) => {
    if (!ts) return 'never';
    const ago = Date.now() - new Date(ts).getTime();
    if (ago < 60000) return 'just now';
    if (ago < 3600000) return Math.floor(ago / 60000) + 'm ago';
    if (ago < 86400000) return Math.floor(ago / 3600000) + 'h ago';
    return Math.floor(ago / 86400000) + 'd ago';
  };
  return devices.map(d => {
    const name = _esc(d.name || d.label || 'Unnamed device');
    const created = d.createdAt ? new Date(d.createdAt).toLocaleDateString() : '';
    const seen = fmtAge(d.lastSeen);
    return '<div class="summary-device">'
      + '<div>'
      + '<div class="summary-device-name">' + name + '</div>'
      + '<div class="summary-device-meta">paired ' + _esc(created) + ' · last seen ' + _esc(seen) + '</div>'
      + '</div>'
      + '<div class="summary-device-actions">'
      + '<button type="button" data-act="device-rename" data-id="' + _esc(d.id || '') + '" data-name="' + _esc(d.name || '') + '">Rename</button>'
      + '<button type="button" data-act="device-revoke" data-id="' + _esc(d.id || '') + '">Revoke</button>'
      + '</div>'
      + '</div>';
  }).join('');
}

async function _renderSummaryPota() {
  const pill = document.getElementById('summary-pota-pill');
  const signed = document.getElementById('summary-pota-signed');
  const actions = document.getElementById('summary-pota-actions');
  const hParks = document.getElementById('summary-pota-h-parks');
  const hQ = document.getElementById('summary-pota-h-qsos');
  const hAwards = document.getElementById('summary-pota-h-awards');
  const hEndorse = document.getElementById('summary-pota-h-endorse');
  const aActs = document.getElementById('summary-pota-a-acts');
  const aParks = document.getElementById('summary-pota-a-parks');
  const aQ = document.getElementById('summary-pota-a-qsos');
  if (!pill) return;
  try {
    const st = await window.api.potaSyncStatus();
    pill.classList.remove('ok', 'warn', 'bad');
    if (!st || !st.connected) {
      pill.textContent = 'Signed out';
      signed.textContent = 'Sign in to display your POTA.app activity.';
      hParks.textContent = '—'; hQ.textContent = '—'; hAwards.textContent = '—'; hEndorse.textContent = '—';
      aActs.textContent = '—'; aParks.textContent = '—'; aQ.textContent = '—';
      actions.innerHTML = '<button type="button" class="primary" data-act="pota-connect">Sign in to POTA.app</button>';
      return;
    }
    pill.textContent = 'Signed in';
    pill.classList.add('ok');
    signed.textContent = 'Signed in as ' + (st.connectedAs || '—');
    const p = st.profile || {};
    const h = p.hunter || {};
    const a = p.activator || {};
    // awards + endorsements are top-level (not split between hunter/activator)
    // per the api.pota.app/stats/user response shape. Casey's sketch puts
    // them on the Hunter row.
    const fmt = (n) => (n == null ? '—' : Number(n).toLocaleString());
    hParks.textContent = fmt(h.parks);
    hQ.textContent = fmt(h.qsos);
    hAwards.textContent = fmt(p.awards);
    hEndorse.textContent = fmt(p.endorsements);
    aActs.textContent = fmt(a.activations);
    aParks.textContent = fmt(a.parks);
    aQ.textContent = fmt(a.qsos);
    actions.innerHTML = '<button type="button" data-act="pota-refresh">Refresh</button>';
  } catch {
    pill.textContent = '—';
  }
}

function _wireSummaryCardActionsOnce() {
  if (_summaryWired) return;
  const card = document.getElementById('summary-card-operator')?.parentElement;
  if (!card) return;
  _summaryWired = true;

  // Operator dropdown — switch on change (with confirm).
  const opSel = document.getElementById('summary-op-select');
  if (opSel) opSel.addEventListener('change', (e) => _summaryOpSwitch(e.target.value));
  const opAdd = document.getElementById('summary-op-add');
  if (opAdd) opAdd.addEventListener('click', _summaryOpAddPrompt);
  const opManage = document.getElementById('summary-op-manage');
  if (opManage) opManage.addEventListener('click', (e) => { e.preventDefault(); _summaryOpOpenManage(); });
  // Manage Operators dialog wiring
  const opsDlg = document.getElementById('operators-dialog');
  const opsClose = document.getElementById('operators-close');
  const opsList = document.getElementById('operators-list');
  if (opsClose && opsDlg) opsClose.addEventListener('click', () => opsDlg.close());
  if (opsList) opsList.addEventListener('click', async (e) => {
    const btn = e.target.closest('[data-act="op-archive"]');
    if (!btn) return;
    const call = btn.dataset.call;
    if (!call) return;
    if (!confirm('Archive operator ' + call + '? Their logbook and settings move to profiles/_archived/ and disappear from the dropdown. You can restore by moving the folder back later.')) return;
    const r = await window.api.profilesArchive(call);
    if (!r || !r.ok) {
      alert('Could not archive: ' + (r && r.error ? r.error : 'unknown'));
      return;
    }
    await _summaryOpRenderManageList();
    refreshSummaryCard();
  });

  // Logbook card buttons
  const openBtn = document.getElementById('summary-log-open');
  const importBtn = document.getElementById('summary-log-import');
  const exportBtn = document.getElementById('summary-log-export');
  if (openBtn) openBtn.addEventListener('click', () => window.api.qsoPopoutOpen());
  if (importBtn) importBtn.addEventListener('click', () => {
    // Delegate to existing handler — preserves the result-text update flow
    // that lives on the Logging tab's adif-import-btn click handler.
    const real = document.getElementById('adif-import-btn');
    if (real) real.click();
    else window.api.importAdif();
  });
  if (exportBtn) exportBtn.addEventListener('click', () => window.api.qsoPopoutOpen());

  // Document-level delegation. The Cloud and ECHOCAT cards are
  // duplicated in the Summary tab AND the ECHOCAT settings tab, so a
  // single top-level handler covers both. Action ids are owned by the
  // card builders above (data-act="cloud-signup" etc.) — adding a new
  // action here means adding it to the appropriate _build*HTML.
  document.addEventListener('click', async (e) => {
    const btn = e.target.closest('[data-act]');
    if (!btn) return;
    // Only act on data-act inside known Summary surfaces or hosts.
    const inSummaryHost = btn.closest('[data-summary-card], #summary-card-operator, #summary-card-logbook, #summary-card-pota, #operators-dialog');
    if (!inSummaryHost) return;
    const act = btn.dataset.act;
    try {
      if (act === 'cloud-signup') await window.api.cloudOpenSubscribe();
      else if (act === 'cloud-manage') await window.api.cloudOpenManage();
      else if (act === 'cloud-sync-now') {
        btn.disabled = true;
        btn.textContent = 'Syncing…';
        const r = await window.api.cloudSyncNow();
        if (r && r.error) alert('Sync failed: ' + r.error);
      }
      else if (act === 'tunnel-on') {
        const r = await window.api.cloudTunnelEnable();
        if (r && r.error) {
          const map = {
            'entitlement-required': 'POTACAT Cloud Tunnel requires an active POTACAT Cloud subscription. Sign up from the Cloud card above to enable it.',
            'cloudflared-missing': 'POTACAT can\'t find the cloudflared helper. Reinstall POTACAT (the installer bundles it).',
            'auth-required': 'You need to sign in to POTACAT Cloud first. Use the Cloud card above to sign in.',
          };
          alert(map[r.error] || ('Could not turn on the tunnel: ' + r.error));
        }
      }
      else if (act === 'tunnel-off') await window.api.cloudTunnelDisable();
      else if (act === 'echo-pair-device') _pairDeviceOpen();
      else if (act === 'echo-share') _shareRigOpen();
      else if (act === 'echo-diagnostics') _summaryTunnelDiagOpen();
      else if (act === 'echo-copy-weburl') {
        const val = btn.dataset.copy || '';
        if (val) {
          try { await navigator.clipboard.writeText(val); }
          catch { try { window.api.copyToClipboard(val); } catch {} }
          const prev = btn.textContent;
          btn.textContent = 'Copied';
          setTimeout(() => { btn.textContent = prev; }, 1400);
        }
      }
      else if (act === 'pota-connect') await window.api.potaSyncConnect();
      else if (act === 'pota-refresh') await window.api.potaSyncNow();
      else if (act === 'device-revoke') {
        const id = btn.dataset.id;
        if (!id) return;
        if (!confirm('Revoke this paired device? It will need to scan a new QR code to reconnect.')) return;
        await window.api.echocatRevokeDevice(id);
      }
      else if (act === 'device-rename') {
        const id = btn.dataset.id;
        const current = btn.dataset.name || '';
        if (!id) return;
        const next = await _summaryPrompt({
          title: 'Rename device',
          message: 'Pick a name you’ll recognize when you see it in the device list.',
          defaultValue: current,
        });
        if (next == null) return;
        const trimmed = next.trim();
        if (!trimmed || trimmed === current) return;
        await window.api.echocatRenameDevice(id, trimmed);
      }
      else return; // unrelated data-act somewhere else in the dialog
    } catch (err) {
      console.warn('[summary]', act, err);
    }
    setTimeout(refreshSummaryCard, 200);
  });

  // Subscribe to push events that should trigger a re-render
  if (window.api.onEchocatPairedDevices) {
    window.api.onEchocatPairedDevices(() => {
      if (settingsDialog.open) _renderSummaryEchocat();
    });
  }
  if (window.api.onCloudTunnelState) {
    window.api.onCloudTunnelState(() => {
      if (settingsDialog.open) _renderSummaryEchocat();
    });
  }
  if (window.api.onCloudSyncStatus) {
    window.api.onCloudSyncStatus(() => {
      if (settingsDialog.open) _renderSummaryCloud();
    });
  }
  if (window.api.onPotaSyncStatus) {
    window.api.onPotaSyncStatus(() => {
      if (settingsDialog.open) _renderSummaryPota();
    });
  }
}

// ── POTACAT Cloud Tunnel pair state machine ─────────────────────────
// Renders the Settings → ECHOCAT → Pair Mobile App state panel based
// on cloud auth + entitlement + tunnel state. Determines whether the
// pair button should request a cloud-only QR (no LAN) or the legacy
// LAN+cloud combo. Tailscale path stays available via the <details>
// disclosure but is no longer the default suggestion.

let _pairCurrentMode = 'lan'; // 'cloud' | 'lan' — what the pair button will request
let _pairLastTunnelState = null;
let _pairLastCloudStatus = null;

function _pairIsCloudEntitled(sub) {
  if (!sub) return false;
  if (sub.status === 'active') return true;
  if (sub.status === 'trial') return true;
  if (sub.trialActive === true) return true;
  return false;
}

function _pairEscape(s) {
  return String(s == null ? '' : s).replace(/[&<>"']/g, (c) => ({
    '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;',
  }[c]));
}

function _pairRenderState() {
  const panel = document.getElementById('pair-state-display');
  if (!panel) return;
  const pairBtn = document.getElementById('echocat-pair-btn');

  const cs = _pairLastCloudStatus;
  const tunnel = _pairLastTunnelState;
  const loggedIn = !!(cs && cs.loggedIn);
  const sub = cs && cs.subscription;
  const entitled = loggedIn && _pairIsCloudEntitled(sub);
  const tunnelLive = !!(tunnel && tunnel.status === 'live' && tunnel.cloudHost);

  const bmacUrl = 'https://buymeacoffee.com/potacat/membership';
  const remoteInstructionsUrl = 'https://potacat.com/remote-instructions';

  if (entitled && tunnelLive) {
    _pairCurrentMode = 'cloud';
    panel.className = 'pair-state-display pair-state-ready';
    panel.innerHTML =
      '<span class="pair-state-title">&#x2713; POTACAT Cloud Tunnel ready</span>' +
      '<span class="pair-state-body">Phone connects directly via your cloud hostname. No Tailscale, no port forwarding, works from anywhere.</span>' +
      '<div class="pair-host-pill">' + _pairEscape(tunnel.cloudHost) + '</div>';
    if (pairBtn) pairBtn.textContent = 'Open pairing QR';
    return;
  }

  if (entitled && !tunnelLive) {
    _pairCurrentMode = 'cloud';
    panel.className = 'pair-state-display';
    const statusText = tunnel
      ? (tunnel.status === 'off' ? 'POTACAT Cloud Tunnel is off.' :
         tunnel.status === 'provisioning' ? 'Provisioning POTACAT Cloud Tunnel&hellip;' :
         tunnel.status === 'connecting' ? 'Connecting POTACAT Cloud Tunnel&hellip;' :
         tunnel.status === 'reconnecting' ? 'Reconnecting POTACAT Cloud Tunnel&hellip;' :
         tunnel.status === 'error' ? ('POTACAT Cloud Tunnel error: ' + _pairEscape(tunnel.lastError || 'unknown')) :
         'POTACAT Cloud Tunnel is off.')
      : 'POTACAT Cloud Tunnel is off.';
    panel.innerHTML =
      '<span class="pair-state-title">POTACAT Cloud Tunnel</span>' +
      '<span class="pair-state-body">' + statusText + ' Enable it for one-tap remote pairing.</span>' +
      '<div class="pair-state-actions">' +
        '<button type="button" id="pair-enable-tunnel-btn" class="btn btn-primary btn-sm">Enable POTACAT Cloud Tunnel</button>' +
      '</div>';
    const enableBtn = document.getElementById('pair-enable-tunnel-btn');
    if (enableBtn) {
      enableBtn.addEventListener('click', async () => {
        enableBtn.disabled = true;
        enableBtn.textContent = 'Enabling…';
        try {
          const r = await window.api.cloudTunnelEnable();
          if (r && r.error) {
            enableBtn.textContent = 'Failed: ' + r.error;
            enableBtn.disabled = false;
          }
          // The tunnel manager will emit 'change' events that re-render automatically.
        } catch (err) {
          enableBtn.textContent = 'Failed: ' + (err.message || err);
          enableBtn.disabled = false;
        }
      });
    }
    if (pairBtn) pairBtn.textContent = 'Open pairing QR (LAN/Tailscale)';
    return;
  }

  // Not entitled — either signed in but free tier, or signed out.
  _pairCurrentMode = 'lan';
  panel.className = 'pair-state-display';
  if (pairBtn) pairBtn.textContent = 'Open pairing QR (Tailscale)';
  let title, body, primaryLabel;
  if (loggedIn) {
    title = 'Join POTACAT Cloud to instantly and securely connect to your radio while remote';
    body = 'Start a free 30-day trial — no credit card needed. Alternatively, enable Tailscale on your shack computer and mobile device (turn on MagicDNS and HTTPS Certificates).';
    primaryLabel = 'Start free trial';
  } else {
    title = 'Join POTACAT Cloud to instantly and securely connect to your radio while remote';
    body = 'Sign in to POTACAT Cloud and start a free trial. Alternatively, enable Tailscale on your shack computer and mobile device (turn on MagicDNS and HTTPS Certificates).';
    primaryLabel = 'Sign in to POTACAT Cloud';
  }
  panel.innerHTML =
    '<span class="pair-state-title">' + title + '</span>' +
    '<span class="pair-state-body">' + body + '</span>' +
    '<div class="pair-state-actions">' +
      (loggedIn
        ? '<a href="' + bmacUrl + '" target="_blank" class="btn btn-primary btn-sm">' + primaryLabel + '</a>'
        : '<button type="button" id="pair-signin-btn" class="btn btn-primary btn-sm">' + primaryLabel + '</button>') +
      '<a href="' + remoteInstructionsUrl + '" target="_blank" class="btn btn-sm">Remote-access guide</a>' +
    '</div>';
  const signinBtn = document.getElementById('pair-signin-btn');
  if (signinBtn) {
    signinBtn.addEventListener('click', () => {
      // Jump the Settings dialog to the Cloud tab so the user can sign in.
      const cloudTab = document.querySelector('.settings-tab[data-tab="cloud"]');
      if (cloudTab) cloudTab.click();
    });
  }
}

async function _pairRefreshCloudStatus() {
  try {
    if (window.api && window.api.cloudGetStatus) {
      _pairLastCloudStatus = await window.api.cloudGetStatus();
    }
  } catch {
    _pairLastCloudStatus = null;
  }
  _pairRenderState();
}

(function _pairInit() {
  if (window.api && window.api.cloudTunnelGetState) {
    window.api.cloudTunnelGetState().then((s) => {
      _pairLastTunnelState = s;
      _pairRenderState();
    }).catch(() => {});
  }
  _pairRefreshCloudStatus();
  if (window.api && window.api.onCloudTunnelState) {
    window.api.onCloudTunnelState((s) => {
      _pairLastTunnelState = s;
      _pairRenderState();
    });
  }
})();

