  const srcLabels = { pota: '#spots-pota', sota: '#spots-sota', wwff: '#spots-wwff',
    llota: '#spots-llota', tiles: '#spots-tiles', dxc: '#spots-cluster', rbn: '#spots-rbn', pskr: '#spots-pskr' };
