function getTodayUtcQsoCount() {
  const now = new Date();
  const todayUtc = now.getUTCFullYear().toString() +
    String(now.getUTCMonth() + 1).padStart(2, '0') +
    String(now.getUTCDate()).padStart(2, '0');
  let count = 0;
  for (const entries of workedQsos.values()) {
    for (const e of entries) {
      if (e.date === todayUtc) count++;
    }
  }
  return count;
}

function checkQsoMilestone() {
  const count = getTodayUtcQsoCount();
  // Reset celebrated milestones if day rolled over (count dropped)
  if (count < lastKnownDailyQsoCount) celebratedMilestones.clear();
  lastKnownDailyQsoCount = count;
  for (const m of QSO_MILESTONES) {
    if (count >= m && !celebratedMilestones.has(m)) {
      celebratedMilestones.add(m);
      if (m === 500) {
        showMegaCelebration(`500 QSOs today! You are UNSTOPPABLE!`);
      } else {
        showCatCelebration(`${m} QSOs today! Keep going!`);
      }
      break; // one celebration at a time
    }
  }
}

// --- Events ---
// Band/mode dropdowns already wired via initMultiDropdown()
// --- Spots dropdown panel ---
spotsBtn.addEventListener('click', (e) => {
  e.stopPropagation();
  document.querySelectorAll('.multi-dropdown.open').forEach((d) => {
    if (d !== spotsDropdown) d.classList.remove('open');
  });
  const opening = !spotsDropdown.classList.contains('open');
  spotsDropdown.classList.toggle('open');
  if (opening) syncSpotsPanel();
});

function syncSpotsPanel() {
  spotsPota.checked = enablePota;
  spotsSota.checked = enableSota;
  spotsWwff.checked = enableWwff;
  spotsLlota.checked = enableLlota;
  if (spotsWwbota) spotsWwbota.checked = enableWwbota;
  if (spotsTiles) spotsTiles.checked = enableTiles;
  spotsCluster.checked = enableCluster;
  spotsCwSpots.checked = enableCwSpots;
  spotsRbn.checked = enableRbn;
  spotsPskr.checked = enablePskr;
  spotsDxe.checked = enableDxe;
  // Sync per-source children + gray them out when master is off.
  for (const k of DXE_SOURCE_KEYS) {
    const el = spotsDxeChildren[k];
    if (!el) continue;
    el.checked = !!enableDxeSources[k];
    const row = el.closest('.spots-toggle');
    if (row) row.classList.toggle('disabled', !enableDxe);
  }
  spotsHideWorked.checked = hideWorked;
  spotsHideParks.checked = hideWorkedParks;
  spotsHideCallRef.checked = hideWorkedCallRef;
  spotsPrioritizeNew.checked = prioritizeNewParks;
  spotsStrictAtno.checked = strictAtno;
  spotsHideOob.checked = hideOutOfBand;
  spotsHideQrt.checked = hideQrt;
  spotsShowHidden.checked = showHiddenSpots;
  quickShowMeter.checked = meterBoxVisible;
  const hCount = hiddenSpotCount();
  spotsHiddenCount.textContent = hCount;
  spotsHiddenCount.classList.toggle('hidden', hCount === 0);
  spotsDxcc.checked = enableDxcc;
  spotsHideParksLabel.classList.toggle('hidden', workedParksSet.size === 0);
  spotsPrioritizeNewLabel.classList.toggle('hidden', workedParksSet.size === 0);
  // Strict ATNO is only meaningful when the POTA hunter CSV is loaded —
  // without it there's nothing to compare against.
  spotsStrictAtnoLabel.classList.toggle('hidden', creditedParksSet.size === 0);
  // Strict CALL+REF filter only makes sense once the user has logged QSOs;
  // hide the toggle entirely when there's nothing in the worked-QSO map.
  spotsHideCallRefLabel.classList.toggle('hidden', workedQsos.size === 0);
}

document.querySelector('.spots-dropdown-panel').addEventListener('click', (e) => e.stopPropagation());

document.querySelector('.spots-dropdown-panel').addEventListener('change', async (e) => {
  enablePota = spotsPota.checked;
  enableSota = spotsSota.checked;
  enableWwff = spotsWwff.checked;
  enableLlota = spotsLlota.checked;
  enableWwbota = spotsWwbota ? spotsWwbota.checked : enableWwbota;
  enableTiles = spotsTiles ? spotsTiles.checked : enableTiles;
  enableCluster = spotsCluster.checked;
  enableCwSpots = spotsCwSpots.checked;
  enableRbn = spotsRbn.checked;
  enablePskr = spotsPskr.checked;
  enableDxe = spotsDxe.checked;
  for (const k of DXE_SOURCE_KEYS) {
    const el = spotsDxeChildren[k];
    if (el) enableDxeSources[k] = el.checked;
  }
  // Re-gray children whenever master flips. (syncSpotsPanel handles this
  // on open; we mirror here so toggling the master while the menu is open
  // updates the visual state immediately.)
  for (const k of DXE_SOURCE_KEYS) {
    const el = spotsDxeChildren[k];
    const row = el && el.closest('.spots-toggle');
    if (row) row.classList.toggle('disabled', !enableDxe);
  }

  // DX Cluster and RBN require a callsign
  if (enableCluster && !myCallsign) {
    enableCluster = false;
    spotsCluster.checked = false;
    alert('DX Cluster requires a callsign. Please set your callsign in Settings first.');
  }
  if (enableCwSpots && !myCallsign) {
    enableCwSpots = false;
    spotsCwSpots.checked = false;
    alert('CW Spots requires a callsign. Please set your callsign in Settings first.');
  }
  if (enableRbn && !myCallsign) {
    enableRbn = false;
    spotsRbn.checked = false;
    alert('RBN requires a callsign. Please set your callsign in Settings first.');
  }
  hideWorked = spotsHideWorked.checked;
  hideWorkedParks = spotsHideParks.checked;
  hideWorkedCallRef = spotsHideCallRef.checked;
  prioritizeNewParks = spotsPrioritizeNew.checked;
  strictAtno = spotsStrictAtno.checked;
  hideOutOfBand = spotsHideOob.checked;
  hideQrt = spotsHideQrt.checked;
  showHiddenSpots = spotsShowHidden.checked;
  enableDxcc = spotsDxcc.checked;

  // Sync Settings dialog checkboxes
  setEnablePota.checked = enablePota;
  setEnableSota.checked = enableSota;
  setEnableWwff.checked = enableWwff;
  setEnableLlota.checked = enableLlota;
  if (setEnableWwbota) setEnableWwbota.checked = enableWwbota;
  if (setEnableTiles) setEnableTiles.checked = enableTiles;
  setEnableCluster.checked = enableCluster;
  setEnableCwSpots.checked = enableCwSpots;
  setEnableRbn.checked = enableRbn;
  setEnablePskr.checked = enablePskr;
  setHideWorked.checked = hideWorked;
  setHideWorkedParks.checked = hideWorkedParks;
  quickHideWorkedParks.checked = hideWorkedParks;
  setHideOutOfBand.checked = hideOutOfBand;
  setEnableDxcc.checked = enableDxcc;

  updateRbnButton();
  updateDxccButton();
  updateDxCommandBar();

  // Save and let main process handle connect/disconnect
  await window.api.saveSettings({
    enablePota, enableSota, enableWwff, enableLlota, enableWwbota, enableTiles,
    enableCluster, enableCwSpots, enableRbn, enablePskr, enableDxe,
    enableDxeSources: { ...enableDxeSources },
    hideWorked, hideWorkedParks, hideWorkedCallRef, prioritizeNewParks, strictAtno, hideOutOfBand,
    enableDxcc,
  });

  render();
});

// --- Hide spot context menu ---
const hideSpotMenu = document.getElementById('hide-spot-menu');
const hideSpotCallEl = document.getElementById('hide-spot-call');
const hideSpotFreqLabel = document.getElementById('hide-spot-freq-label');
let hideSpotTarget = '';
let hideSpotFreq = '';

function showHideSpotMenu(x, y, callsign, frequency) {
  hideSpotTarget = callsign.toUpperCase();
  hideSpotFreq = String(Math.round(parseFloat(frequency)));
  hideSpotCallEl.textContent = callsign;
  hideSpotFreqLabel.textContent = `Hide on ${frequency} kHz only`;
  // Show unhide button if already hidden
  const unhideBtn = hideSpotMenu.querySelector('.hide-spot-unhide');
  unhideBtn.classList.toggle('hidden', !isSpotHidden(callsign, frequency));
  // Render the watchlist buttons every open so newly-renamed groups (and the
  // current member-or-not state) reflect immediately. Each button writes
  // directly to settings + rebuilds the lookup, no settings-dialog round-trip.
  renderWatchlistAddButtons(hideSpotTarget);
  hideSpotMenu.classList.remove('hidden');
  // Position near click, keep on screen
  const rect = hideSpotMenu.getBoundingClientRect();
  hideSpotMenu.style.left = Math.min(x, window.innerWidth - 180) + 'px';
  hideSpotMenu.style.top = Math.min(y, window.innerHeight - rect.height - 10) + 'px';
}

function closeHideSpotMenu() {
  hideSpotMenu.classList.add('hidden');
}

document.addEventListener('click', (e) => {
  if (!hideSpotMenu.contains(e.target)) closeHideSpotMenu();
});

function computeExpiry(dur) {
  if (dur === 'forever') return Infinity;
  if (dur === 'today') {
    const now = new Date();
    return new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), now.getUTCDate() + 1)).getTime();
  }
  return Date.now() + parseInt(dur, 10);
}

hideSpotMenu.addEventListener('click', (e) => {
  const btn = e.target.closest('.hide-spot-btn');
  if (!btn || !hideSpotTarget) return;
  const dur = btn.dataset.dur;
  const scope = btn.dataset.scope;
  if (dur === 'unhide') {
    unhideSpot(hideSpotTarget);
  } else if (scope === 'freq') {
    hideSpotEntry(hideSpotTarget, hideSpotFreq, computeExpiry(dur));
  } else {
    hideSpotEntry(hideSpotTarget, '*', computeExpiry(dur));
  }
  closeHideSpotMenu();
  render();
});

// --- Right-click "Add to watchlist" buttons ---
// Renders one button for the general watchlist plus one per named group.
// Empty/unnamed group slots are skipped. If the callsign is already in a
// list we show "Remove from <name>" instead so the menu is symmetric.
function _hasInGeneralWatchlist(callsign) {
  const raw = (settings && settings.watchlist) || '';
  const up = callsign.toUpperCase();
  return raw.split(/[\s,;]+/).map(s => s.split(':')[0].trim().toUpperCase()).includes(up);
}

function _hasInGroupCallsigns(idx, callsign) {
  const g = watchlistGroups[idx];
  if (!g) return false;
  return _parseCallsignList(g.callsigns).includes(callsign.toUpperCase());
}

function _addToGeneralWatchlist(callsign) {
  const raw = (settings && settings.watchlist) || '';
  const sep = raw && !raw.endsWith(',') && !raw.endsWith('\n') ? ', ' : '';
  const next = (raw + sep + callsign).replace(/^[,\s]+/, '');
  settings.watchlist = next;
  watchlist = parseWatchlist(next);
  // Keep the Settings textarea in sync in case it's open behind the menu.
  if (setWatchlist) setWatchlist.value = next;
  window.api.saveSettings({ watchlist: next });
}

function _removeFromGeneralWatchlist(callsign) {
  const up = callsign.toUpperCase();
  const raw = (settings && settings.watchlist) || '';
  // Preserve original separator style (commas/newlines) by splitting on a
  // capturing group, keeping non-matching tokens + their following separator.
  const parts = raw.split(/([\s,;]+)/);
  let next = '';
  for (let i = 0; i < parts.length; i += 2) {
    const tok = parts[i] || '';
    const sep = parts[i + 1] || '';
    if (tok.split(':')[0].trim().toUpperCase() === up) continue; // drop this token + its sep
    next += tok + sep;
  }
  next = next.replace(/^[,\s]+|[,\s]+$/g, '');
  settings.watchlist = next;
  watchlist = parseWatchlist(next);
  if (setWatchlist) setWatchlist.value = next;
  window.api.saveSettings({ watchlist: next });
}

function _addToGroupCallsigns(idx, callsign) {
  const g = watchlistGroups[idx];
  if (!g) return;
  const cur = g.callsigns || '';
  const sep = cur && !cur.endsWith(',') && !cur.endsWith('\n') ? ', ' : '';
  g.callsigns = (cur + sep + callsign).replace(/^[,\s]+/, '');
  rebuildWatchlistGroupLookup();
  const partial = JSON.parse(JSON.stringify(watchlistGroups));
  window.api.saveSettings({ watchlistGroups: partial });
}

function _removeFromGroupCallsigns(idx, callsign) {
  const g = watchlistGroups[idx];
  if (!g) return;
  const up = callsign.toUpperCase();
  const parts = (g.callsigns || '').split(/([\s,;]+)/);
  let next = '';
  for (let i = 0; i < parts.length; i += 2) {
    const tok = parts[i] || '';
    const sep = parts[i + 1] || '';
    if (tok.split(':')[0].trim().toUpperCase() === up) continue;
    next += tok + sep;
  }
  g.callsigns = next.replace(/^[,\s]+|[,\s]+$/g, '');
  rebuildWatchlistGroupLookup();
  const partial = JSON.parse(JSON.stringify(watchlistGroups));
  window.api.saveSettings({ watchlistGroups: partial });
}

function renderWatchlistAddButtons(callsign) {
  const host = document.getElementById('hide-spot-watch-buttons');
  if (!host) return;
  host.innerHTML = '';
  const mkBtn = (label, color, onClick) => {
    const b = document.createElement('button');
    b.className = 'hide-spot-btn';
    b.textContent = label;
    if (color) b.style.borderLeft = `3px solid ${color}`;
    b.addEventListener('click', (e) => {
      e.preventDefault();
      onClick();
      closeHideSpotMenu();
      render();
    });
    host.appendChild(b);
  };
  // General watchlist
  if (_hasInGeneralWatchlist(callsign)) {
    mkBtn(`Remove from Watchlist`, '', () => _removeFromGeneralWatchlist(callsign));
  } else {
    mkBtn(`Add to Watchlist`, '', () => _addToGeneralWatchlist(callsign));
  }
  // Per group (skip empty / unnamed slots)
  for (let i = 0; i < watchlistGroups.length; i++) {
    const g = watchlistGroups[i];
    if (!g || !g.name) continue;
    if (_hasInGroupCallsigns(i, callsign)) {
      mkBtn(`Remove from ${g.name}`, g.color, () => _removeFromGroupCallsigns(i, callsign));
    } else {
      mkBtn(`Add to ${g.name}`, g.color, () => _addToGroupCallsigns(i, callsign));
    }
  }
}

// Column sorting — click for primary, Shift+click for secondary
document.querySelectorAll('thead th[data-sort]').forEach((th) => {
  th.addEventListener('click', (e) => {
    const col = th.dataset.sort;
    if (e.shiftKey) {
      // Shift+click: set or toggle secondary sort
      if (col === sortCol) return; // can't secondary-sort on same column as primary
      if (sortCol2 === col) {
        sortAsc2 = !sortAsc2;
      } else {
        sortCol2 = col;
        sortAsc2 = col === 'distance' || col === 'bearing';
      }
    } else {
      // Regular click: set primary sort, clear secondary
      if (sortCol === col) {
        sortAsc = !sortAsc;
      } else {
        sortCol = col;
        sortAsc = col === 'distance' || col === 'bearing';
      }
      sortCol2 = '';
    }
    saveViewState();
    render();
  });
});

