  setSsbFilter.value = s.ssbFilterWidth || 0;
  setDigitalFilter.value = s.digitalFilterWidth || 0;
  setWatchlist.value = s.watchlist || '';
  // Hydrate watchlist groups from settings — default colors + empty fields
