// --- Floating S-Meter / SWR Box ---
const meterBox = document.getElementById('meter-box');
let meterBoxVisible = localStorage.getItem('meterBoxVisible') !== 'false'; // default visible

// Draggable meter box
(function() {
  let dragging = false, startX, startY, startLeft, startTop;
  // Restore saved position
  const saved = localStorage.getItem('meterBoxPos');
  if (saved) {
    try {
      const pos = JSON.parse(saved);
      meterBox.style.left = pos.left + 'px';
      meterBox.style.top = pos.top + 'px';
      meterBox.style.right = 'auto';
      meterBox.style.bottom = 'auto';
    } catch {}
  }
  meterBox.addEventListener('mousedown', (e) => {
    dragging = true;
    meterBox.classList.add('dragging');
    startX = e.clientX;
    startY = e.clientY;
    const rect = meterBox.getBoundingClientRect();
    const parentRect = meterBox.parentElement.getBoundingClientRect();
    startLeft = rect.left - parentRect.left;
    startTop = rect.top - parentRect.top;
    e.preventDefault();
  });
  document.addEventListener('mousemove', (e) => {
    if (!dragging) return;
    const dx = e.clientX - startX;
    const dy = e.clientY - startY;
    meterBox.style.left = (startLeft + dx) + 'px';
    meterBox.style.top = (startTop + dy) + 'px';
    meterBox.style.right = 'auto';
    meterBox.style.bottom = 'auto';
  });
  document.addEventListener('mouseup', () => {
    if (!dragging) return;
    dragging = false;
    meterBox.classList.remove('dragging');
    localStorage.setItem('meterBoxPos', JSON.stringify({
      left: parseInt(meterBox.style.left, 10),
      top: parseInt(meterBox.style.top, 10),
    }));
  });
})();
const smeterBarCanvas = document.getElementById('smeter-bar');
const smeterTextEl = document.getElementById('smeter-text');
const swrBarCanvas = document.getElementById('swr-bar');
const swrTextEl = document.getElementById('swr-text');
const alcBarCanvas = document.getElementById('alc-bar');
const alcTextEl = document.getElementById('alc-text');

function drawMeterBar(canvas, level, color) {
  if (!canvas) return;
  const ctx = canvas.getContext('2d');
  const w = canvas.width, h = canvas.height;
  ctx.clearRect(0, 0, w, h);
  ctx.fillStyle = '#1a1a2e';
  ctx.fillRect(0, 0, w, h);
  const barW = Math.round(Math.max(0, Math.min(1, level)) * w);
  ctx.fillStyle = color;
  ctx.fillRect(0, 0, barW, h);
  // Tick marks
  ctx.fillStyle = 'rgba(255,255,255,0.15)';
  for (let i = 1; i <= 9; i++) {
    ctx.fillRect(Math.round(i * w / 12), 0, 1, h);
  }
}

window.api.onCatSmeter((val) => {
  if (meterBoxVisible) meterBox.classList.remove('hidden');
  const level = val / 255;
  const color = val < 80 ? '#4ecca3' : val < 160 ? '#ffd740' : '#e94560';
  drawMeterBar(smeterBarCanvas, level, color);
  if (val <= 120) {
    smeterTextEl.textContent = 'S' + Math.round(val * 9 / 120);
  } else {
    smeterTextEl.textContent = 'S9+' + Math.round((val - 120) * 60 / 135);
  }
  smeterTextEl.style.color = color;
});

window.api.onCatSwr((val) => {
  if (val <= 0) {
    drawMeterBar(swrBarCanvas, 0, '#333');
    swrTextEl.textContent = '—';
    swrTextEl.style.color = '#666';
    return;
  }
  if (meterBoxVisible) meterBox.classList.remove('hidden');
  const swr = 1.0 + (val / 60);
  const level = Math.min(1, (swr - 1) / 4);
  const color = swr <= 1.5 ? '#4ecca3' : swr <= 2.0 ? '#ffd740' : swr <= 3.0 ? '#f0a500' : '#e94560';
  drawMeterBar(swrBarCanvas, level, color);
  swrTextEl.textContent = swr < 10 ? swr.toFixed(1) : '>10';
  swrTextEl.style.color = color;
});

// Direct SWR ratio from FlexRadio vita49 (bypasses RM1 conversion)
window.api.onCatSwrRatio((swr) => {
  if (meterBoxVisible) meterBox.classList.remove('hidden');
  const level = Math.min(1, (swr - 1) / 4);
  const color = swr <= 1.5 ? '#4ecca3' : swr <= 2.0 ? '#ffd740' : swr <= 3.0 ? '#f0a500' : '#e94560';
  drawMeterBar(swrBarCanvas, level, color);
  swrTextEl.textContent = swr < 10 ? swr.toFixed(1) : '>10';
  swrTextEl.style.color = color;
});

window.api.onCatAlc((val) => {
  if (meterBoxVisible) meterBox.classList.remove('hidden');
  // Radios report ALC on 0..255 scale (Kenwood RM3 / Yaesu RM2). Anything
  // above ~40% ALC is into compression — color accordingly.
  const pct = Math.min(1, val / 255);
  const color = pct <= 0 ? '#666' : pct < 0.4 ? '#4ecca3' : pct < 0.7 ? '#ffd740' : pct < 0.9 ? '#f0a500' : '#e94560';
  drawMeterBar(alcBarCanvas, pct, pct <= 0 ? '#333' : color);
  alcTextEl.textContent = pct <= 0 ? '—' : Math.round(pct * 100) + '%';
  alcTextEl.style.color = color;
});

window.api.onCatStatus((s) => {
  if (!s.connected) meterBox.classList.add('hidden');
});

// --- CAT Log Panel ---
const catLogPanel = document.getElementById('cat-log-panel');
const catLogOutput = document.getElementById('cat-log-output');
const catLogCopyBtn = document.getElementById('cat-log-copy');
const catLogClearBtn = document.getElementById('cat-log-clear');
const catLogToggleBtn = document.getElementById('cat-log-toggle');

// SPLIT pill: click to disable. Confirm so legitimate split users don't
// lose their setting on a stray click. Settings → Spots stays the only
// place to enable split (no UI here for turning it ON).
const splitIndicatorBtn = document.getElementById('split-indicator');
if (splitIndicatorBtn) {
  splitIndicatorBtn.addEventListener('click', async () => {
    if (!enableSplit) return;
    if (!confirm('Disable Split mode? RX and TX will return to the same VFO.')) return;
    enableSplit = false;
    setEnableSplit.checked = false;
    await window.api.saveSettings({ enableSplit: false });
    updateSplitIndicator();
    showLogToast('Split mode OFF', { duration: 1500 });
  });
}
const catLogLines = [];
const CAT_LOG_MAX = 500;

window.api.onCatLog((msg) => {
  console.log(msg);
  catLogLines.push(msg);
  if (catLogLines.length > CAT_LOG_MAX) catLogLines.shift();
  catLogOutput.value = catLogLines.join('\n');
  catLogOutput.scrollTop = catLogOutput.scrollHeight;
});

catLogToggleBtn.addEventListener('click', () => {
  const isHidden = catLogPanel.classList.toggle('hidden');
  catLogToggleBtn.classList.toggle('active', !isHidden);
  document.body.classList.toggle('cat-log-open', !isHidden);
});

catLogCopyBtn.addEventListener('click', () => {
  navigator.clipboard.writeText(catLogOutput.value).then(() => {
    catLogCopyBtn.textContent = 'Copied!';
    setTimeout(() => { catLogCopyBtn.textContent = 'Copy'; }, 1500);
  });
});

catLogClearBtn.addEventListener('click', () => {
  catLogLines.length = 0;
  catLogOutput.value = '';
});

// --- Report a Bug flow ---
// One-click path that guides users through capturing a verbose log and
// packaging it with diagnostic metadata for Discord #bug-report.
// Replaces the manual "open settings, toggle verbose, save, find the log
// button, reproduce, copy" sequence.
(function setupReportBug() {
  const btn = document.getElementById('report-bug-btn');
  if (!btn) return;

  async function buildReport() {
    const s = await window.api.getSettings();
    const rigs = s.rigs || [];
    const activeRig = rigs.find(r => r.id === s.activeRigId) || rigs[0];
    const rigDesc = activeRig
      ? [activeRig.name, activeRig.model, activeRig.catTarget && activeRig.catTarget.type,
         activeRig.catTarget && (activeRig.catTarget.host ? activeRig.catTarget.host + ':' + activeRig.catTarget.port : activeRig.catTarget.path)]
        .filter(Boolean).join(' / ')
      : '(none configured)';
    const enabled = [
      s.enablePota && 'POTA', s.enableSota && 'SOTA', s.enableWwff && 'WWFF', s.enableLlota && 'LLOTA', s.enableWwbota && 'WWBOTA',
      s.enableCluster && 'DX-Cluster', s.enableCwSpots && 'CW-Spots', s.enableRbn && 'RBN',
      s.enablePskr && 'PSKR', s.enableDxcc && 'DXCC', s.enableFreedv && 'FreeDV',
      s.enableAutoSstv && 'Auto-SSTV',
    ].filter(Boolean).join(', ') || '(none)';
    const md = {
      version: window._appVersion || s.appVersion || 'unknown',
      platform: window.api.platform,
      rig: rigDesc,
      callsign: (s.myCallsign || '(not set)').toUpperCase(),
      features: enabled,
    };
    const log = catLogLines.join('\n') || '(log is empty — verbose logging may not have captured anything during the repro)';
    return [
      '## POTACAT Bug Report',
      '',
      '**Version:** v' + md.version,
      '**Platform:** ' + md.platform,
      '**Rig:** ' + md.rig,
      '**Callsign:** ' + md.callsign,
      '**Features enabled:** ' + md.features,
      '',
      '### What I tried to do',
      '<!-- fill in: the steps you took -->',
      '',
      '### What happened',
      '<!-- fill in: what went wrong, what you expected -->',
      '',
      '### Verbose log',
      '```',
      log,
      '```',
    ].join('\n');
  }

  async function startBugReport() {
    // Snapshot the pre-flow state so we can restore it on dismiss. The
    // user expects "Report a Bug" to be a one-shot diagnostic — if they
    // had Verbose Log off before, they want it off after, and the toggle
    // button hidden again. Without this, every bug report leaves the
    // user staring at a Verbose Log button they didn't ask for and don't
    // know how to remove. (Casey report 2026-04-28.)
    const s = await window.api.getSettings();
    const priorVerboseLog = !!s.verboseLog;
    const priorLogPanelHidden = catLogPanel.classList.contains('hidden');
    let weEnabledVerbose = false;

    // 1. Enable verbose logging in settings if not already
    if (!priorVerboseLog) {
      weEnabledVerbose = true;
      await window.api.saveSettings({ verboseLog: true });
      // Re-sync local UI state — show the Verbose Log toggle button
      if (setVerboseLog) setVerboseLog.checked = true;
      if (catLogToggleBtn) catLogToggleBtn.classList.remove('hidden');
    }
    // 2. Show the log panel + clear existing lines
    catLogLines.length = 0;
    catLogOutput.value = '';
    if (priorLogPanelHidden) {
      catLogPanel.classList.remove('hidden');
      catLogToggleBtn.classList.add('active');
      document.body.classList.add('cat-log-open');
    }
    // 3. Float a recording banner with Copy + Cancel
    let banner = document.getElementById('bug-report-banner');
    if (!banner) {
      banner = document.createElement('div');
      banner.id = 'bug-report-banner';
      // KF8ELA report: buttons had a tiny clickable strip on macOS — the
      // native button height was getting clipped by the flex parent's
      // align-items:center under certain content widths. Explicit min-height,
      // -webkit-appearance:none on the buttons, and flex-shrink:0 so the
      // layout can't compress them.
      banner.style.cssText = 'position:fixed;top:0;left:0;right:0;background:#c24150;color:#fff;padding:12px 16px;font-size:13px;z-index:10000;display:flex;align-items:center;gap:12px;box-shadow:0 2px 8px rgba(0,0,0,0.4);min-height:50px;';
      document.body.appendChild(banner);
    }
    const btnBase = 'flex-shrink:0;-webkit-appearance:none;appearance:none;border-radius:4px;cursor:pointer;font-size:13px;line-height:1.2;min-height:32px;padding:8px 16px;';
    banner.innerHTML = [
      '<strong style="flex-shrink:0;">🐞 Recording bug report…</strong>',
      '<span style="flex:1;min-width:0;">Now reproduce the problem. When the log below contains what you need, click Copy Report.</span>',
      `<button type="button" id="bug-report-copy" style="${btnBase}background:#fff;color:#c24150;border:none;font-weight:700;">Copy Report</button>`,
      `<button type="button" id="bug-report-cancel" style="${btnBase}background:transparent;color:#fff;border:1px solid #fff;">Cancel</button>`,
    ].join('');

    // Push page content down so the menu bar isn't covered by the banner.
    // Use a ResizeObserver because the banner can wrap to two/three lines
    // on narrow windows — a fixed padding value would either over- or
    // under-shoot. (Casey report 2026-04-28: banner overlays the Table
    // View menu and makes the page hard to navigate.)
    const applyBannerOffset = () => {
      if (banner && banner.isConnected) {
        document.body.style.paddingTop = banner.offsetHeight + 'px';
      } else {
        document.body.style.paddingTop = '';
      }
    };
    let bannerRO = null;
    if (typeof ResizeObserver !== 'undefined') {
      bannerRO = new ResizeObserver(applyBannerOffset);
      bannerRO.observe(banner);
    }
    applyBannerOffset();

    let dismissed = false;
    let autoDismissTimer = null;
    async function dismissBanner() {
      if (dismissed) return;
      dismissed = true;
      if (autoDismissTimer) { clearTimeout(autoDismissTimer); autoDismissTimer = null; }
      if (bannerRO) { try { bannerRO.disconnect(); } catch {} bannerRO = null; }
      banner.remove();
      document.body.style.paddingTop = '';

      // Restore prior verbose-log state — but only if WE turned it on AND
      // it's still on (don't undo a user who manually toggled it off
      // mid-flow). Same defensive read for the panel.
      if (weEnabledVerbose) {
        try {
          const cur = await window.api.getSettings();
          if (cur.verboseLog === true) {
            await window.api.saveSettings({ verboseLog: false });
            if (setVerboseLog) setVerboseLog.checked = false;
            if (catLogToggleBtn) catLogToggleBtn.classList.add('hidden');
          }
        } catch {}
      }
      if (priorLogPanelHidden && !catLogPanel.classList.contains('hidden')) {
        catLogPanel.classList.add('hidden');
        if (catLogToggleBtn) catLogToggleBtn.classList.remove('active');
        document.body.classList.remove('cat-log-open');
      }
    }

    banner.querySelector('#bug-report-cancel').onclick = dismissBanner;
    banner.querySelector('#bug-report-copy').onclick = async () => {
      const report = await buildReport();
      // Use main-process clipboard via IPC — navigator.clipboard.writeText
      // silently fails in some Electron focus/permission contexts.
      let copied = false;
      try {
        const result = await window.api.copyToClipboard(report);
        copied = !!(result && result.ok);
      } catch { copied = false; }
      if (!copied) {
        // Last-ditch fallback: drop the report in the log textarea + select it
        catLogOutput.value = report;
        catLogOutput.select();
      }
      banner.innerHTML = copied
        ? '<strong>✅ Copied to clipboard.</strong><span style="flex:1">Paste it into Discord #bug-report. Fill in the "What I tried" and "What happened" sections before sending.</span><button type="button" id="bug-report-close" style="background:transparent;color:#fff;border:1px solid #fff;padding:4px 10px;border-radius:3px;cursor:pointer;font-size:12px;">Close</button>'
        : '<strong>⚠ Clipboard write failed.</strong><span style="flex:1">The report is shown in the log below — select all, copy manually, paste in Discord.</span><button type="button" id="bug-report-close" style="background:transparent;color:#fff;border:1px solid #fff;padding:4px 10px;border-radius:3px;cursor:pointer;font-size:12px;">Close</button>';
      banner.querySelector('#bug-report-close').onclick = dismissBanner;
      applyBannerOffset();
      // Auto-dismiss after 20 s so the banner doesn't linger forever
      autoDismissTimer = setTimeout(dismissBanner, 20000);
    };
  }

  btn.addEventListener('click', () => {
    // Close the Quick Settings dropdown so the banner isn't hidden behind it
    if (settingsDropdown) settingsDropdown.classList.remove('open');
    // Close the Settings dialog too — the recording banner shows on the main
    // window, so leaving the modal up would hide it behind the dialog.
    const dlg = document.getElementById('settings-dialog');
    if (dlg && typeof dlg.close === 'function' && dlg.open) dlg.close();
    startBugReport();
  });
})();

// --- Solar data listener ---
function updateSolarVisibility() {
  const method = enableSolar ? 'remove' : 'add';
  sfiStatusEl.classList[method]('hidden');
  kStatusEl.classList[method]('hidden');
  aStatusEl.classList[method]('hidden');
}

window.api.onSolarData((payload) => {
  const { sfi, kIndex, aIndex } = payload || {};
  const hidden = enableSolar ? '' : ' hidden';

  if (sfi != null) {
    const sfiClass = sfi >= 100 ? 'connected' : sfi >= 70 ? 'warn' : 'disconnected';
    sfiStatusEl.textContent = `SFI ${sfi}`;
    sfiStatusEl.className = `status solar-pill ${sfiClass}${hidden}`;
  }
  if (kIndex != null) {
    const kClass = kIndex <= 2 ? 'connected' : kIndex <= 4 ? 'warn' : 'disconnected';
    kStatusEl.textContent = `K ${kIndex}`;
    kStatusEl.className = `status solar-pill ${kClass}${hidden}`;
  }
  if (aIndex != null) {
    const aClass = aIndex <= 7 ? 'connected' : aIndex <= 20 ? 'warn' : 'disconnected';
    aStatusEl.textContent = `A ${aIndex}`;
    aStatusEl.className = `status solar-pill ${aClass}${hidden}`;
  }
  // Note: the full Conditions panel lives in conditions-popout.html and
  // subscribes to its own solar-data IPC — no in-window render here.
});

// Conditions popout owns its own render — see renderer/conditions-popout.js.



// --- Band Activity Heatmap ---
const HEATMAP_BANDS = ['160m', '80m', '60m', '40m', '30m', '20m', '17m', '15m', '12m', '10m', '6m', '4m', '2m', '70cm'];
const HEATMAP_CONTINENTS = ['EU', 'NA', 'SA', 'AS', 'AF', 'OC'];

function updateBandActivityVisibility() {
  if (enableBandActivity && showMap) {
    bandActivityBar.classList.remove('hidden');
  } else {
    bandActivityBar.classList.add('hidden');
  }
  if (map) setTimeout(() => map.invalidateSize(), 0);
}

function renderBandActivity() {
  if (!enableBandActivity || !showMap) return;

  const now = Date.now();
  const oneHourAgo = now - 3600000;

  // Filter spots from the last 60 minutes
  const recentSpots = allSpots.filter((s) => {
    if (!s.spotTime) return false;
    try {
      const t = new Date(s.spotTime.endsWith('Z') ? s.spotTime : s.spotTime + 'Z').getTime();
      return t >= oneHourAgo;
    } catch { return false; }
  });

  // Aggregate by band × continent
  const counts = {}; // key: "band|continent" -> count
  for (const s of recentSpots) {
    if (!s.band || !s.continent) continue;
    const key = `${s.band}|${s.continent}`;
    counts[key] = (counts[key] || 0) + 1;
  }

  // Build grid: columns = header + bands, rows = header + continents
  const cols = HEATMAP_BANDS.length + 1; // +1 for row labels
  bandActivityBar.innerHTML = '';

  const grid = document.createElement('div');
  grid.className = 'band-activity-grid';
  grid.style.gridTemplateColumns = `auto repeat(${HEATMAP_BANDS.length}, 1fr)`;

  // Header row: empty corner + band labels
  const corner = document.createElement('div');
  corner.className = 'band-activity-header';
  corner.textContent = '';
  grid.appendChild(corner);

  for (const band of HEATMAP_BANDS) {
    const hdr = document.createElement('div');
    hdr.className = 'band-activity-header';
    hdr.textContent = band;
    grid.appendChild(hdr);
  }

  // Data rows: continent label + cells
  for (const cont of HEATMAP_CONTINENTS) {
    const label = document.createElement('div');
    label.className = 'band-activity-label';
    label.textContent = cont;
    grid.appendChild(label);

    for (const band of HEATMAP_BANDS) {
      const count = counts[`${band}|${cont}`] || 0;
      const cell = document.createElement('div');
      cell.className = 'band-activity-cell';

      // Heat level: 0 = empty, 1 = 1-2 spots, 2 = 3-5, 3 = 6+
      const heat = count === 0 ? 0 : count <= 2 ? 1 : count <= 5 ? 2 : 3;
      cell.classList.add(`heat-${heat}`);
      cell.textContent = count || '';
      cell.title = `${band} ${cont}: ${count} spot${count !== 1 ? 's' : ''}`;
      grid.appendChild(cell);
    }
  }

  bandActivityBar.appendChild(grid);
}

// --- RBN Map ---
function initRbnMap() {
  rbnMap = L.map('rbn-map', { zoomControl: true, worldCopyJump: true }).setView(DEFAULT_CENTER, 3);

  L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
    attribution: '&copy; OpenStreetMap contributors',
    maxZoom: 18,
    className: 'dark-tiles',
  }).addTo(rbnMap);

  rbnMarkerLayer = L.layerGroup().addTo(rbnMap);

  // Bind QRZ handlers inside popups
  bindPopupClickHandlers(rbnMap);

  // Add home marker
  updateRbnHomeMarker();

  // Add day/night overlay
  updateRbnNightOverlay();
  setInterval(updateRbnNightOverlay, 60000);
}

async function updateRbnHomeMarker() {
  if (!rbnMap) return;
  const settings = await window.api.getSettings();
  const grid = settings.grid || 'FN20jb';
  const pos = gridToLatLonLocal(grid);
  if (!pos) return;
  rbnHomePos = pos;

  if (rbnHomeMarker) {
    for (const m of rbnHomeMarker) rbnMap.removeLayer(m);
  }

  const homeIcon = L.divIcon({
    className: 'home-marker-icon',
    html: '<div style="background:#e94560;width:14px;height:14px;border-radius:50%;border:2px solid #fff;"></div>',
    iconSize: [14, 14],
    iconAnchor: [7, 7],
  });

  rbnHomeMarker = [-360, 0, 360].map((offset) =>
    L.marker([pos.lat, pos.lon + offset], { icon: homeIcon, zIndexOffset: 1000 })
      .bindPopup(`<b>My QTH</b><br>${grid}`)
      .addTo(rbnMap)
  );

  rbnMap.setView([pos.lat, pos.lon], rbnMap.getZoom());
}

function updateRbnNightOverlay() {
  if (!rbnMap) return;
  const rings = computeNightPolygon();
  if (rbnNightLayer) {
    rbnNightLayer.setLatLngs(rings);
  } else {
    rbnNightLayer = L.polygon(rings, {
      fillColor: '#000',
      fillOpacity: 0.25,
      color: '#4fc3f7',
      weight: 1,
      opacity: 0.4,
      interactive: false,
    }).addTo(rbnMap);
  }
  if (rbnMarkerLayer) rbnMarkerLayer.bringToFront();
}

function getFilteredRbnSpots() {
  const bands = getDropdownValues(rbnBandFilterEl);
  const modes = getDropdownValues(propModeFilterEl);
  const maxAge = parseInt(rbnMaxAgeInput.value, 10) || 30;
  const ageUnit = rbnAgeUnitSelect.value; // 'm' or 'h'
  const maxAgeSecs = maxAge * (ageUnit === 'h' ? 3600 : 60);

  // Merge RBN and PSKReporter spots based on source toggles
  const merged = [];
  if (propShowRbn) {
    for (const s of rbnSpots) merged.push({ ...s, _source: 'rbn', _station: s.spotter });
  }
  if (propShowPskr) {
    for (const s of pskrMapSpots) merged.push({ ...s, _source: 'pskr', _station: s.receiver });
  }

  return merged.filter((s) => {
    if (bands && !bands.has(s.band)) return false;
    if (modes && !modes.has(s.mode)) return false;
    if (spotAgeSecs(s.spotTime) > maxAgeSecs) return false;
    return true;
  });
}

function rerenderRbn() {
  if (currentView === 'rbn' || activatorRbnVisible) {
    renderRbnMarkers();
    renderRbnTable();
  }
}

function renderRbnMarkers() {
  if (!rbnMarkerLayer) return;
  rbnMarkerLayer.clearLayers();

  const filtered = getFilteredRbnSpots();
  const unit = distUnit === 'km' ? 'km' : 'mi';
  const activeBands = new Set();

  // Draw arcs first (underneath markers)
  if (rbnHomePos) {
    for (const s of filtered) {
      if (s.lat == null || s.lon == null) continue;
      const color = RBN_BAND_COLORS_ACTIVE[s.band] || '#ffffff';
      const arcPoints = greatCircleArc(rbnHomePos.lat, rbnHomePos.lon, s.lat, s.lon, 50);
      for (const offset of [-360, 0, 360]) {
        const offsetPoints = arcPoints.map(([lat, lon]) => [lat, lon + offset]);
        L.polyline(offsetPoints, {
          color: color,
          weight: 1.5,
          opacity: 0.45,
          interactive: false,
        }).addTo(rbnMarkerLayer);
      }
    }
  }

  // Draw circle markers on top
  for (const s of filtered) {
    if (s.lat == null || s.lon == null) continue;
    if (s.band) activeBands.add(s.band);

    const color = RBN_BAND_COLORS_ACTIVE[s.band] || '#ffffff';
    const distStr = s.distance != null ? formatDistance(s.distance) + ' ' + unit : '';
    const snrStr = s.snr != null ? s.snr + ' dB' : '';
    const wpmStr = s.wpm != null ? s.wpm + ' WPM' : '';
    const details = [snrStr, wpmStr].filter(Boolean).join(' / ');
    const srcLabel = s._source === 'pskr' ? 'PSKReporter' : 'RBN';

    const popupContent = `
      <b><a href="#" class="popup-qrz" data-call="${s._station}">${s._station}</a></b> <span class="help-text">${srcLabel}</span><br>
      ${s.locationDesc}<br>
      ${s.band || ''} ${s.mode || ''} &middot; ${details}<br>
      ${distStr ? distStr + '<br>' : ''}
      <span class="help-text">${formatAge(s.spotTime)}</span>
    `;

    for (const offset of [-360, 0, 360]) {
      L.circleMarker([s.lat, s.lon + offset], {
        radius: 7,
        fillColor: color,
        color: color,
        weight: 1,
        opacity: 0.9,
        fillOpacity: 0.7,
      }).bindPopup(popupContent).addTo(rbnMarkerLayer);
    }
  }

  rbnCountEl.textContent = filtered.length;
  renderRbnLegend(activeBands);
}

function renderRbnLegend(activeBands) {
  rbnLegendEl.innerHTML = '';
  const sortedBands = ['160m', '80m', '60m', '40m', '30m', '20m', '17m', '15m', '12m', '10m', '6m', '4m', '2m', '70cm'];
  for (const band of sortedBands) {
    if (!activeBands.has(band)) continue;
    const item = document.createElement('span');
    item.className = 'rbn-legend-item';
    const swatch = document.createElement('span');
    swatch.className = 'rbn-legend-swatch';
    swatch.style.background = RBN_BAND_COLORS_ACTIVE[band] || '#fff';
    item.appendChild(swatch);
    item.appendChild(document.createTextNode(band));
    rbnLegendEl.appendChild(item);
  }
}

function renderRbnTable() {
  rbnTableBody.innerHTML = '';
  rbnDistHeader.textContent = distUnit === 'km' ? 'Dist (km)' : 'Dist (mi)';

  // Show newest spots first
  const sorted = [...getFilteredRbnSpots()].reverse();

  for (const s of sorted) {
    const tr = document.createElement('tr');

    // Station (QRZ link with source dot)
    const stationTd = document.createElement('td');
    const dot = document.createElement('span');
    dot.className = 'prop-source-dot';
    dot.style.background = s._source === 'pskr' ? '#ff6b6b' : 'var(--source-rbn)';
    dot.title = s._source === 'pskr' ? 'PSKReporter' : 'RBN';
    stationTd.appendChild(dot);
    const stationLink = document.createElement('a');
    stationLink.textContent = s._station;
    stationLink.href = '#';
    stationLink.className = 'qrz-link';
    stationLink.addEventListener('click', (e) => {
      e.preventDefault();
      window.api.openExternal(`https://www.qrz.com/db/${encodeURIComponent(s._station.split('/')[0])}`);
    });
    stationTd.appendChild(stationLink);
    tr.appendChild(stationTd);

    // Location
    const locTd = document.createElement('td');
    locTd.textContent = s.locationDesc || '';
    tr.appendChild(locTd);

    // Distance
    const distTd = document.createElement('td');
    distTd.textContent = s.distance != null ? formatDistance(s.distance) : '\u2014';
    tr.appendChild(distTd);

    // Freq
    const freqTd = document.createElement('td');
    freqTd.textContent = parseFloat(s.frequency).toFixed(1);
    tr.appendChild(freqTd);

    // Mode
    const modeTd = document.createElement('td');
    modeTd.textContent = s.mode || '';
    tr.appendChild(modeTd);

    // SNR
    const snrTd = document.createElement('td');
    snrTd.textContent = s.snr != null ? s.snr + ' dB' : '';
    tr.appendChild(snrTd);

    // Time
    const timeTd = document.createElement('td');
    try {
      const d = new Date(s.spotTime);
      timeTd.textContent = d.toISOString().slice(11, 16) + 'z';
    } catch { timeTd.textContent = ''; }
    tr.appendChild(timeTd);

    // Seen (relative age)
    const seenTd = document.createElement('td');
    seenTd.textContent = formatAge(s.spotTime);
    tr.appendChild(seenTd);

    rbnTableBody.appendChild(tr);
  }
}

// --- RBN splitter drag ---
rbnSplitter.addEventListener('mousedown', (e) => {
  e.preventDefault();
  const rbnViewEl = document.getElementById('rbn-view');
  const startY = e.clientY;
  const startMapH = rbnMapContainer.offsetHeight;
  const startTableH = rbnTableContainer.offsetHeight;

  const onMove = (ev) => {
    const delta = ev.clientY - startY;
    const newMapH = Math.max(80, startMapH + delta);
    const newTableH = Math.max(60, startTableH - delta);
    rbnMapContainer.style.flex = 'none';
    rbnTableContainer.style.flex = 'none';
    rbnMapContainer.style.height = newMapH + 'px';
    rbnTableContainer.style.height = newTableH + 'px';
    if (rbnMap) rbnMap.invalidateSize();
  };

  const onUp = () => {
    document.removeEventListener('mousemove', onMove);
    document.removeEventListener('mouseup', onUp);
    document.body.style.cursor = '';
  };

  document.body.style.cursor = 'row-resize';
  document.addEventListener('mousemove', onMove);
  document.addEventListener('mouseup', onUp);
});

