// FreeDV tooltip — show countdown to next poll on hover
(function setupPskrTooltip() {
  const label = spotsPskr.closest('label');
  if (!label) return;
  let tipTimer = null;
  const updateTip = () => {
    if (!pskrNextPollAt) { label.title = 'FreeDV spots from PSKReporter'; return; }
    const secsLeft = Math.max(0, Math.round((pskrNextPollAt - Date.now()) / 1000));
    if (secsLeft === 0) { label.title = 'Updating now\u2026'; return; }
    const m = Math.floor(secsLeft / 60);
    const s = secsLeft % 60;
    label.title = `Next update in ${m}m ${String(s).padStart(2, '0')}s`;
  };
  label.addEventListener('mouseenter', () => {
    updateTip();
    tipTimer = setInterval(updateTip, 1000);
  });
  label.addEventListener('mouseleave', () => {
    if (tipTimer) { clearInterval(tipTimer); tipTimer = null; }
  });
})();

// --- CW Keyer: MIDI + Sidetone ---
let midiAccess = null;
let midiInput = null;
let cwLearningTarget = null; // 'dit' | 'dah' | null
let sidetoneCtx = null;
let sidetoneOsc = null;
let sidetoneGain = null;

async function populateMidiDevices() {
  setCwMidiDevice.innerHTML = '<option value="">— No MIDI devices —</option>';
  try {
    if (!midiAccess) midiAccess = await navigator.requestMIDIAccess();
    const inputs = Array.from(midiAccess.inputs.values());
    if (inputs.length > 0) {
      setCwMidiDevice.innerHTML = '';
      for (const inp of inputs) {
        const opt = document.createElement('option');
        opt.value = inp.id;
        opt.textContent = inp.name || inp.id;
        setCwMidiDevice.appendChild(opt);
      }
    }
  } catch (err) {
    console.warn('MIDI not available:', err.message);
  }
}

function connectMidiDevice(id) {
  if (midiInput) {
    midiInput.onmidimessage = null;
    midiInput = null;
  }
  if (!midiAccess || !id) return;
  const inp = midiAccess.inputs.get(id);
  if (!inp) return;
  midiInput = inp;
  midiInput.onmidimessage = handleMidiMessage;
}

function handleMidiMessage(msg) {
  const [status, note, velocity] = msg.data;
  const cmd = status & 0xF0;
  const isNoteOn = cmd === 0x90 && velocity > 0;
  const isNoteOff = cmd === 0x80 || (cmd === 0x90 && velocity === 0);

  // Learn mode — capture note number
  if (cwLearningTarget && isNoteOn) {
    if (cwLearningTarget === 'dit') {
      setCwMidiDitNote.value = note;
    } else if (cwLearningTarget === 'dah') {
      setCwMidiDahNote.value = note;
    }
    stopLearning();
    return;
  }

  const ditNote = parseInt(setCwMidiDitNote.value, 10);
  const dahNote = parseInt(setCwMidiDahNote.value, 10);

  if (note === ditNote) {
    if (isNoteOn) window.api.cwPaddleDit(true);
    else if (isNoteOff) window.api.cwPaddleDit(false);
  } else if (note === dahNote) {
    if (isNoteOn) window.api.cwPaddleDah(true);
    else if (isNoteOff) window.api.cwPaddleDah(false);
  }
}

function stopLearning() {
  cwLearningTarget = null;
  cwLearnDitBtn.classList.remove('learning');
  cwLearnDitBtn.textContent = 'Learn';
  cwLearnDahBtn.classList.remove('learning');
  cwLearnDahBtn.textContent = 'Learn';
}

cwLearnDitBtn.addEventListener('click', () => {
  if (cwLearningTarget === 'dit') { stopLearning(); return; }
  stopLearning();
  cwLearningTarget = 'dit';
  cwLearnDitBtn.classList.add('learning');
  cwLearnDitBtn.textContent = 'Press...';
});

cwLearnDahBtn.addEventListener('click', () => {
  if (cwLearningTarget === 'dah') { stopLearning(); return; }
  stopLearning();
  cwLearningTarget = 'dah';
  cwLearnDahBtn.classList.add('learning');
  cwLearnDahBtn.textContent = 'Press...';
});

cwMidiRefreshBtn.addEventListener('click', () => {
  populateMidiDevices().then(() => connectMidiDevice(setCwMidiDevice.value));
});

// Auto-connect MIDI device when dropdown changes
setCwMidiDevice.addEventListener('change', () => {
  connectMidiDevice(setCwMidiDevice.value);
});

// --- Keyboard CW (VBand/Vail: Left Ctrl = dit, Right Ctrl = dah) ---
document.addEventListener('keydown', (e) => {
  if (!setEnableCwKeyer.checked) return;
  if (e.repeat) return; // ignore key repeat
  if (e.code === 'ControlLeft') { e.preventDefault(); window.api.cwPaddleDit(true); }
  else if (e.code === 'ControlRight') { e.preventDefault(); window.api.cwPaddleDah(true); }
});
document.addEventListener('keyup', (e) => {
  if (!setEnableCwKeyer.checked) return;
  if (e.code === 'ControlLeft') { e.preventDefault(); window.api.cwPaddleDit(false); }
  else if (e.code === 'ControlRight') { e.preventDefault(); window.api.cwPaddleDah(false); }
});

// Sidetone
function initSidetone() {
  if (sidetoneCtx) return;
  sidetoneCtx = new (window.AudioContext || window.webkitAudioContext)();
  sidetoneOsc = sidetoneCtx.createOscillator();
  sidetoneOsc.type = 'sine';
  sidetoneOsc.frequency.value = parseInt(setCwSidetonePitch.value, 10) || 600;
  sidetoneGain = sidetoneCtx.createGain();
  sidetoneGain.gain.value = 0;
  sidetoneOsc.connect(sidetoneGain);
  sidetoneGain.connect(sidetoneCtx.destination);
  sidetoneOsc.start();
}

function sidetoneKey(down) {
  if (!sidetoneCtx || !sidetoneGain) return;
  // Resume AudioContext if suspended (Chromium requires user gesture to start)
  if (sidetoneCtx.state === 'suspended') sidetoneCtx.resume();
  const now = sidetoneCtx.currentTime;
  sidetoneGain.gain.cancelScheduledValues(now);
  sidetoneGain.gain.setValueAtTime(sidetoneGain.gain.value, now);
  const vol = (parseInt(setCwSidetoneVolume.value, 10) || 30) / 100;
  sidetoneGain.gain.linearRampToValueAtTime(down ? vol : 0, now + 0.005);
}

function updateSidetonePitch() {
  if (sidetoneOsc) {
    sidetoneOsc.frequency.value = parseInt(setCwSidetonePitch.value, 10) || 600;
  }
}

setCwSidetonePitch.addEventListener('change', updateSidetonePitch);
setCwSidetoneVolume.addEventListener('input', () => {
  cwSidetoneVolumeLabel.textContent = setCwSidetoneVolume.value + '%';
  if (cwPopoverVolume) { cwPopoverVolume.value = setCwSidetoneVolume.value; cwPopoverVolumeLabel.textContent = setCwSidetoneVolume.value + '%'; }
});

// Live WPM adjustment — send to main immediately and sync popover
setCwWpm.addEventListener('change', () => {
  const wpm = parseInt(setCwWpm.value, 10);
  if (wpm >= 5 && wpm <= 50) {
    window.api.cwSetWpm(wpm);
    if (cwPopoverWpm) cwPopoverWpm.value = wpm;
  }
});

// CW key events from main process -> sidetone
window.api.onCwKey(({ down }) => {
  console.log(`[Sidetone] key down=${down} checked=${setCwSidetone.checked} ctx=${!!sidetoneCtx}`);
  if (setCwSidetone.checked) {
    initSidetone();
    sidetoneKey(down);
  }
  // "Keying but no RF" diagnostic — if the operator is sending CW through
  // POTACAT but the rig reports zero forward power for 2+ seconds, the most
  // common causes are: wrong CW key source on the rig (USB vs. paddle jack),
  // CW power turned to 0 in rig menu, or the rig is in TUNE/lock-out.
  if (down) noteCwKeyDown();
});

// TX-but-no-RF detector. Arm a 2.5 s watcher on each key-down; if we see any
// non-zero power report during the window, the rig is happy. Otherwise, the
// watcher fires and emits a throttled toast pointing at the usual suspects.
let _cwRfArmedAt = 0;
let _cwRfSeenPower = false;
let _cwRfTimer = null;
let _cwRfLastToast = 0;
function noteCwKeyDown() {
  _cwRfArmedAt = Date.now();
  _cwRfSeenPower = false;
  if (_cwRfTimer) clearTimeout(_cwRfTimer);
  _cwRfTimer = setTimeout(() => {
    _cwRfTimer = null;
    if (_cwRfSeenPower) return;
    const now = Date.now();
    if (now - _cwRfLastToast < 10 * 60 * 1000) return; // throttle per 10 min
    _cwRfLastToast = now;
    showTuneBlockedToast('Radio is keying CW but reporting no RF. Check the rig\u2019s CW key source (paddle jack vs. USB), CW power level, and that the rig isn\u2019t in TUNE or menu mode.');
  }, 2500);
}
function showTuneBlockedToast(msg) {
  // Reuse the tune-blocked-toast DOM node for any transient notification.
  let t = document.getElementById('tune-blocked-toast');
  if (!t) {
    t = document.createElement('div');
    t.id = 'tune-blocked-toast';
    t.style.cssText = 'position:fixed;top:50%;left:50%;transform:translate(-50%,-50%);background:#e94560;color:#fff;padding:12px 24px;border-radius:8px;font-size:15px;font-weight:bold;z-index:10001;pointer-events:none;box-shadow:0 4px 20px rgba(233,69,96,0.5);opacity:0;transition:opacity 0.2s';
    document.body.appendChild(t);
  }
  t.textContent = msg;
  t.style.opacity = '1';
  clearTimeout(t._timer);
  t._timer = setTimeout(() => { t.style.opacity = '0'; }, 5000);
}

// CW keyer status
window.api.onCwKeyerStatus(({ enabled, cwAuth, winkeyer, version }) => {
  cwKeyerStatusEl.classList.toggle('hidden', !enabled);
  updateCwMacroBar();
  if (!enabled) { closeCwPopover(); }
  if (winkeyer) {
    cwKeyerStatusEl.textContent = 'WK';
    cwKeyerStatusEl.title = `WinKeyer v${version || '?'} connected`;
    cwKeyerStatusEl.style.background = '#b8860b';
    if (winkeyerVersionEl) winkeyerVersionEl.textContent = `WinKeyer v${version || '?'} connected`;
  } else if (cwAuth) {
    // 'gui' = Flex Direct (POTACAT is the GUI client) — a fully authorized CW
    // state, same as 'bind'. Only a genuinely unbound keyer shows "(?)".
    const cwAuthOk = cwAuth === 'bind' || cwAuth === 'gui';
    cwKeyerStatusEl.textContent = cwAuthOk ? 'CW' : 'CW (?)';
    cwKeyerStatusEl.title = cwAuth === 'gui'
      ? 'CW keyer active — Flex Direct (POTACAT is the GUI client)'
      : `CW keyer active — ${cwAuth === 'bind' ? 'bound to SmartSDR' : 'unbound (CW may still work)'}`;
    cwKeyerStatusEl.style.background = '#b8860b';
  }
});
// --- Floating CW Macro Box (draggable, like meter box) ---
const cwMacroBar = document.getElementById('cw-macro-bar');
const cwMacroBtns = document.getElementById('cw-macro-btns');
const cwMacroInput = document.getElementById('cw-macro-input');
const cwMacroSendBtn = document.getElementById('cw-macro-send');
const cwMacroCancelBtn = document.getElementById('cw-macro-cancel');
const quickShowCwMacros = document.getElementById('quick-show-cw-macros');
let cwMacroBoxVisible = localStorage.getItem('cwMacroBoxVisible') === 'true';

// Draggable CW macro box
(function() {
  if (!cwMacroBar) return;
  let dragging = false, startX, startY, startLeft, startTop;
  const saved = localStorage.getItem('cwMacroBoxPos');
  if (saved) {
    try {
      const pos = JSON.parse(saved);
      cwMacroBar.style.left = pos.left + 'px';
      cwMacroBar.style.top = pos.top + 'px';
      cwMacroBar.style.right = 'auto';
      cwMacroBar.style.bottom = 'auto';
    } catch {}
  }
  cwMacroBar.addEventListener('mousedown', (e) => {
    if (e.target.tagName === 'INPUT' || e.target.tagName === 'BUTTON') return;
    dragging = true;
    cwMacroBar.classList.add('dragging');
    startX = e.clientX;
    startY = e.clientY;
    const rect = cwMacroBar.getBoundingClientRect();
    const parentRect = cwMacroBar.parentElement.getBoundingClientRect();
    startLeft = rect.left - parentRect.left;
    startTop = rect.top - parentRect.top;
    e.preventDefault();
  });
  document.addEventListener('mousemove', (e) => {
    if (!dragging) return;
    cwMacroBar.style.left = (startLeft + e.clientX - startX) + 'px';
    cwMacroBar.style.top = (startTop + e.clientY - startY) + 'px';
    cwMacroBar.style.right = 'auto';
    cwMacroBar.style.bottom = 'auto';
  });
  document.addEventListener('mouseup', () => {
    if (!dragging) return;
    dragging = false;
    cwMacroBar.classList.remove('dragging');
    localStorage.setItem('cwMacroBoxPos', JSON.stringify({
      left: parseInt(cwMacroBar.style.left, 10),
      top: parseInt(cwMacroBar.style.top, 10),
    }));
  });
})();

let _cwMacroCache = null; // cached macros from settings (avoids depending on Settings dialog DOM)

async function updateCwMacroBar() {
  if (!cwMacroBar) return;
  cwMacroBar.classList.toggle('hidden', !cwMacroBoxVisible);
  if (quickShowCwMacros) quickShowCwMacros.checked = cwMacroBoxVisible;
  if (!cwMacroBoxVisible) return;
  // Use cached macros, or load from settings (not from the editor DOM which may be empty)
  if (!_cwMacroCache) {
    const s = await window.api.getSettings();
    _cwMacroCache = s.cwMacros && s.cwMacros.length ? s.cwMacros : DEFAULT_CW_MACROS;
  }
  cwMacroBtns.innerHTML = '';
  _cwMacroCache.forEach((m, i) => {
    if (!m.label && !m.text) return;
    const btn = document.createElement('button');
    btn.type = 'button';
    btn.textContent = m.label || '?';
    const cwHk = hotkeyBindings.find(h => h.action === 'cw-macro-' + (i + 1));
    btn.title = (m.text || '') + (cwHk && cwHk.key ? ' (' + cwHk.key + ')' : '');
    btn.addEventListener('click', () => {
      window.api.sendCwText(expandDesktopCwMacros(m.text));
    });
    cwMacroBtns.appendChild(btn);
  });
}
// Invalidate cache when settings are saved so macro bar picks up edits
function invalidateCwMacroCache() { _cwMacroCache = null; }
function expandDesktopCwMacros(text) {
  // {call} — tuned spot callsign (from log dialog or last tuned spot)
  const logCall = document.getElementById('log-callsign');
  const call = (logCall && logCall.value) ? logCall.value.trim().toUpperCase()
    : (lastTunedSpot ? lastTunedSpot.callsign : '');
  // {op_firstname} — nickname (preferred) or first name from QRZ
  const bareCall = call.split('/')[0];
  const qrzOp = bareCall ? qrzData.get(bareCall) : null;
  const opName = (qrzOp && (cleanQrzName(qrzOp.nickname) || cleanQrzName(qrzOp.fname))) || '';
  // {state} — state from QRZ
  const opState = (qrzOp && qrzOp.state) || '';
  return text
    .replace(/\{call\}/gi, call)
    .replace(/\{op_firstname\}/gi, opName)
    .replace(/\{state\}/gi, opState);
}
