document.getElementById('welcome-start').addEventListener('click', async () => {
  const myCallsign = (welcomeCallsignInput.value.trim() || '').toUpperCase();
  const grid = welcomeGridInput.value.trim() || 'FN20jb';
  const distUnitVal = document.getElementById('welcome-dist-unit').value;
  const licenseClassVal = document.getElementById('welcome-license-class').value;
  const hideOobChecked = document.getElementById('welcome-hide-oob').checked;
  const autoSstvChecked = document.getElementById('welcome-enable-auto-sstv').checked;
  const autoSstvMinVal = Math.max(5, Math.min(600, parseInt(document.getElementById('welcome-auto-sstv-min').value, 10) || 90));
  const ft8brEl = document.getElementById('welcome-enable-ft8br');
  const ft8brChecked = ft8brEl ? ft8brEl.checked : false;
  const lightModeEnabled = welcomeLightMode.checked;
  const qrzUser = (document.getElementById('welcome-qrz-user')?.value || '').trim().toUpperCase();
  const qrzPass = document.getElementById('welcome-qrz-pass')?.value || '';
  const currentSettings = await window.api.getSettings();

  // Merge with existing settings so upgrade doesn't wipe user preferences
  const saveData = {
    ...currentSettings,
    myCallsign,
    grid,
    distUnit: distUnitVal,
    licenseClass: licenseClassVal,
    hideOutOfBand: hideOobChecked,
    enableAutoSstv: autoSstvChecked,
    autoSstvInactivityMin: autoSstvMinVal,
    enableFt8br: ft8brChecked,
    firstRun: false,
    lastVersion: currentSettings.appVersion,
    lightMode: lightModeEnabled,
  };
  // Only set QRZ if user filled it in (don't overwrite existing with blank)
  if (qrzUser) {
    saveData.qrzUsername = qrzUser;
    saveData.enableQrz = true;
  }
  if (qrzPass) saveData.qrzPassword = qrzPass;
  delete saveData.appVersion; // runtime-only, don't persist

  // Add rig if configured in welcome (skip if already exists)
  if (welcomeRig) {
    const existingRigs = currentSettings.rigs || [];
    if (!existingRigs.some(r => r.id === welcomeRig.id)) {
      saveData.rigs = [...existingRigs, welcomeRig];
    }
    saveData.activeRigId = welcomeRig.id;
  }

  await window.api.saveSettings(saveData);
  // Mirror lastVersion into localStorage too — see checkFirstRun for why.
  if (saveData.lastVersion) {
    try { localStorage.setItem('whatsNewSeenVersion', saveData.lastVersion); } catch {}
  }

  welcomeDialog.close();
  _welcomeRemoteClose();
  // Reload prefs so the main UI reflects welcome choices
  loadPrefs();
});

// ─── Welcome → Connect to a Remote Shack (v1.9) ──────────────────────
//
// Three discovery surfaces in one place:
//   1. mDNS list — auto-populates when the dialog opens, refreshes
//      every 5s for as long as the dialog is visible. Covers LAN and
//      same-Tailnet shacks that broadcast _potacat._tcp.
//   2. POTACAT Cloud sign-in CTA — opens the existing Google OAuth
//      flow. After sign-in lands, future welcome-screen renders
//      pull cloud_devices and surface the shack picker. (Phase 1
//      degrades gracefully: signing in here doesn't fail, it just
//      doesn't yet auto-list cloud shacks because tasks #16/#17
//      haven't shipped — the user can still paste a link.)
//   3. Paste-link input — accepts a potacat://pair?... URL. Lets
//      anyone (especially off-LAN Tailscale users and email
//      recipients) pair without leaving the welcome screen.

let _welcomeRemoteScanTimer = null;

function _welcomeRemoteStatus(msg, kind) {
  const el = document.getElementById('welcome-remote-status');
  if (!el) return;
  el.classList.remove('hidden', 'error', 'success');
  if (kind === 'error') el.classList.add('error');
  else if (kind === 'success') el.classList.add('success');
  el.textContent = msg;
}
function _welcomeRemoteClearStatus() {
  const el = document.getElementById('welcome-remote-status');
  if (el) el.classList.add('hidden');
}

async function _welcomeRemoteScan() {
  const listEl = document.getElementById('welcome-remote-list');
  if (!listEl) return;
  let shacks = [];
  try { shacks = await window.api.discoverShacks(); } catch {}
  // Don't overwrite a "Pairing…" / "Approving on shack…" status row
  // mid-scan with a stale snapshot.
  const pairingInProgress = listEl.querySelector('[data-pairing="true"]');
  if (pairingInProgress) return;
  if (!Array.isArray(shacks) || shacks.length === 0) {
    listEl.innerHTML = '<li class="welcome-remote-empty">No shacks found on your network yet. If your shack is reachable only via Tailscale or the internet, use one of the options below.</li>';
    return;
  }
  listEl.innerHTML = shacks.map((s) => {
    const fpShort = s.fingerprint ? String(s.fingerprint).slice(0, 19) + '…' : '';
    const rig = s.rigModel ? ' &middot; ' + _esc(s.rigModel) : '';
    return '<li>'
      + '<div class="wrl-info">'
      +   '<div class="wrl-name">' + _esc(s.name) + '</div>'
      +   '<div class="wrl-meta">' + _esc(s.host) + ':' + _esc(String(s.port)) + rig + (fpShort ? ' &middot; <code>' + _esc(fpShort) + '</code>' : '') + '</div>'
      + '</div>'
      + '<button type="button" data-host="' + _esc(s.host) + '" data-port="' + _esc(String(s.port)) + '" data-name="' + _esc(s.name) + '" data-fp="' + _esc(s.fingerprint || '') + '" data-rig="' + _esc(s.rigModel || '') + '" data-service="' + _esc(s.serviceName || '') + '">Connect</button>'
      + '</li>';
  }).join('');
}

async function _welcomeRemoteTapPair(btn) {
  const target = {
    host: btn.dataset.host,
    port: Number(btn.dataset.port),
    name: btn.dataset.name,
    fingerprint: btn.dataset.fp,
    rigModel: btn.dataset.rig,
    serviceName: btn.dataset.service,
    wssUrl: 'wss://' + btn.dataset.host + ':' + btn.dataset.port,
  };
  btn.disabled = true;
  const prev = btn.textContent;
  btn.textContent = 'Approving…';
  const li = btn.closest('li');
  if (li) li.dataset.pairing = 'true';
  _welcomeRemoteStatus(
    'Connecting to ' + target.name + '… check the screen on that computer and click ' +
    'Approve to allow this device.',
    null
  );
  try {
    const r = await window.api.pairRequestDiscovered(target);
    if (r && r.error) {
      _welcomeRemoteStatus('Could not pair: ' + r.error, 'error');
    } else if (r && r.ok) {
      _welcomeRemoteStatus('Paired with ' + (r.name || target.name) + '. Click Save to finish setup.', 'success');
      // Activate immediately so the user lands in remote mode on Save.
      try { await window.api.connectionTargetsActivate(r.targetId); } catch {}
    }
  } catch (err) {
    _welcomeRemoteStatus('Pair failed: ' + (err.message || err), 'error');
  } finally {
    btn.disabled = false;
    btn.textContent = prev;
    if (li) delete li.dataset.pairing;
  }
}

async function _welcomeRemoteShowCloudShacks() {
  _welcomeRemoteStatus('Loading your shacks…', null);
  let r = null;
  try { r = await window.api.cloudFindShacks(); }
  catch (err) {
    _welcomeRemoteStatus('Could not load shacks: ' + (err.message || err), 'error');
    return;
  }
  if (r && r.error) {
    _welcomeRemoteStatus(r.error, 'error');
    return;
  }
  const shacks = (r && r.shacks) || [];
  if (shacks.length === 0) {
    _welcomeRemoteStatus(
      'Signed in. No other shacks on your account yet — install POTACAT on the computer ' +
      'with your radio and sign in there to register it. Until then, use the pair link path below.',
      null
    );
    return;
  }
  // Inject a temporary panel below the status to show the cloud
  // shacks list. Reuses the .welcome-remote-list styling.
  const fmtAge = (iso) => {
    if (!iso) return 'unknown';
    const ago = Date.now() - new Date(iso).getTime();
    if (ago < 60000) return 'just now';
    if (ago < 3600000) return Math.floor(ago / 60000) + 'm ago';
    if (ago < 86400000) return Math.floor(ago / 3600000) + 'h ago';
    return Math.floor(ago / 86400000) + 'd ago';
  };
  const html = '<div style="margin-top:6px;">'
    + '<div class="welcome-remote-discovered-header" style="margin-bottom:6px;">'
    + '<span>Your shacks on this account</span></div>'
    + '<ul class="welcome-remote-list">'
    + shacks.map(s => {
      const reach = [];
      if (s.lan_host) reach.push('LAN');
      if (s.ts_host) reach.push('Tailscale');
      if (s.cloud_host) reach.push('Cloud');
      const reachTxt = reach.length ? reach.join(' / ') : 'no hosts on file';
      const rig = s.rig_model ? ' · ' + _esc(s.rig_model) : '';
      return '<li>'
        + '<div class="wrl-info">'
        +   '<div class="wrl-name">' + _esc(s.name) + '</div>'
        +   '<div class="wrl-meta">' + _esc(reachTxt) + rig + ' · seen ' + _esc(fmtAge(s.last_seen_at)) + '</div>'
        + '</div>'
        + '<button type="button" data-cloud-shack="' + _esc(s.device_id) + '" data-name="' + _esc(s.name) + '">Pair (1-click)</button>'
        + '</li>';
    }).join('')
    + '</ul></div>';
  const statusEl = document.getElementById('welcome-remote-status');
  if (statusEl) {
    statusEl.classList.remove('hidden', 'error');
    statusEl.classList.add('success');
    statusEl.innerHTML = '<div style="margin-bottom:6px;">✓ Signed in as ' + _esc((r && r.user && r.user.email) || 'POTACAT Cloud') + '.</div>' + html;
    // Delegated click on the inline Pair buttons.
    statusEl.querySelectorAll('button[data-cloud-shack]').forEach(btn => {
      btn.addEventListener('click', async () => {
        const sid = btn.dataset.cloudShack;
        const sname = btn.dataset.name;
        btn.disabled = true;
        const prev = btn.textContent;
        btn.textContent = 'Pairing…';
        try {
          const p = await window.api.cloudPairShack(sid);
          if (p && p.error) {
            _welcomeRemoteStatus('Pair failed: ' + p.error, 'error');
          } else if (p && p.ok) {
            // Activate immediately and report success.
            try { await window.api.connectionTargetsActivate(p.targetId); } catch {}
            _welcomeRemoteStatus('✓ Paired with ' + (p.name || sname) + ' via ' + (p.leg || '?') + '. Click Save to finish setup.', 'success');
          }
        } catch (err) {
          _welcomeRemoteStatus('Pair failed: ' + (err.message || err), 'error');
        } finally {
          btn.disabled = false;
          btn.textContent = prev;
        }
      });
    });
  }
}

async function _welcomeRemotePasteLink() {
  const input = document.getElementById('welcome-remote-paste-input');
  if (!input) return;
  const url = (input.value || '').trim();
  if (!url) return;
  if (!/^potacat:\/\/pair\?/i.test(url)) {
    _welcomeRemoteStatus('That doesn\'t look like a POTACAT pair link. It should start with potacat://pair?', 'error');
    return;
  }
  _welcomeRemoteStatus('Redeeming pair link…', null);
  // Redeem DIRECTLY in main via IPC — the renderer can't dial sockets, but
  // main can. Do NOT bounce through window.api.openExternal: that re-hands
  // the URL to the OS protocol handler, which only works if potacat:// is
  // registered with Windows (the installer registers it; a dev build does
  // not), so the paste box silently did nothing on dev/unregistered machines.
  // redeemPairLinkUrl still fires 'pair-link-redeemed' for the inline status;
  // the returned result gives us an immediate error if the dial failed.
  try {
    if (window.api && window.api.pairRedeemUrl) {
      const r = await window.api.pairRedeemUrl(url);
      if (r && r.ok === false) {
        _welcomeRemoteStatus('Could not redeem the link: ' + (r.error || 'all paths failed'), 'error');
      }
    } else if (window.api && window.api.openExternal) {
      window.api.openExternal(url); // legacy fallback
    }
  } catch (err) {
    _welcomeRemoteStatus('Could not redeem the link: ' + (err.message || err), 'error');
  }
}

// onPairLinkRedeemed is already wired globally above to alert() on
// success. While the welcome dialog is open we hijack its surface
// to show the result inline so the user doesn't get a modal alert
// stacked on top of the welcome flow.
let _welcomeRemoteResultPending = false;
async function _welcomeRemoteOpen() {
  _welcomeRemoteResultPending = true;
  _welcomeRemoteScan();
  if (_welcomeRemoteScanTimer) clearInterval(_welcomeRemoteScanTimer);
  _welcomeRemoteScanTimer = setInterval(_welcomeRemoteScan, 5000);
}
function _welcomeRemoteClose() {
  _welcomeRemoteResultPending = false;
  if (_welcomeRemoteScanTimer) { clearInterval(_welcomeRemoteScanTimer); _welcomeRemoteScanTimer = null; }
}

(function _welcomeRemoteWire() {
  const list = document.getElementById('welcome-remote-list');
  if (list) list.addEventListener('click', (e) => {
    const btn = e.target.closest('button[data-host]');
    if (btn) return _welcomeRemoteTapPair(btn);
  });
  const rescan = document.getElementById('welcome-remote-rescan');
  if (rescan) rescan.addEventListener('click', () => {
    const listEl = document.getElementById('welcome-remote-list');
    if (listEl) listEl.innerHTML = '<li class="welcome-remote-scanning">Looking on the local network&hellip;</li>';
    _welcomeRemoteScan();
  });
  const pasteBtn = document.getElementById('welcome-remote-paste-btn');
  if (pasteBtn) pasteBtn.addEventListener('click', _welcomeRemotePasteLink);
  const pasteInput = document.getElementById('welcome-remote-paste-input');
  if (pasteInput) pasteInput.addEventListener('keydown', (e) => {
    if (e.key === 'Enter') { e.preventDefault(); _welcomeRemotePasteLink(); }
  });
  const cloudBtn = document.getElementById('welcome-remote-cloud-btn');
  if (cloudBtn) cloudBtn.addEventListener('click', async () => {
    _welcomeRemoteStatus('Opening sign-in…', null);
    try {
      // First check if already signed in — skip the OAuth popup if so.
      let st = null;
      try { st = await window.api.cloudGetStatus(); } catch {}
      if (!st || !st.loggedIn) {
        const r = await window.api.cloudGoogleSignIn();
        if (r && r.error) {
          _welcomeRemoteStatus('Sign-in failed: ' + r.error, 'error');
          return;
        }
      }
      _welcomeRemoteShowCloudShacks();
    } catch (err) {
      _welcomeRemoteStatus('Sign-in failed: ' + (err.message || err), 'error');
    }
  });
  // Suppress the global pair-link-redeemed alert while the welcome
  // dialog is visible — show the result inline instead.
  if (window.api && window.api.onPairLinkRedeemed) {
    window.api.onPairLinkRedeemed((r) => {
      const dlg = document.getElementById('welcome-dialog');
      if (!_welcomeRemoteResultPending || !dlg || !dlg.open) return;
      if (r && r.ok) {
        _welcomeRemoteStatus('Paired with ' + (r.name || 'shack') + ' via ' + (r.leg || 'unknown') + '. Click Save to finish.', 'success');
      } else if (r) {
        _welcomeRemoteStatus('Pair link failed: ' + (r.error || 'unknown'), 'error');
      }
    });
  }
})();

async function checkFirstRun(force = false) {
  const s = await window.api.getSettings();
  // Track "What's New seen" in BOTH settings.json (lastVersion) AND localStorage
  // (whatsNewSeenVersion). The localStorage backup catches at least two ways
  // settings.json can fail to persist the lastVersion update on slow disks /
  // forced exits / partial saves overlapping startup. Either source counts as
  // "seen" — we only show What's New when neither matches the current version.
  const seenLs = (() => { try { return localStorage.getItem('whatsNewSeenVersion'); } catch { return null; } })();
  const versionAlreadySeen = (s.lastVersion === s.appVersion) || (seenLs === s.appVersion);
  const isNewVersion = s.appVersion && !versionAlreadySeen;

  if (force || s.firstRun) {
    // Reset welcome rig state
    welcomeRig = null;
    const welcomeRigDisplay = document.getElementById('welcome-rig-display');
    welcomeRigDisplay.innerHTML = '';
    welcomeRigDisplay.classList.add('hidden');
    document.getElementById('welcome-rig-add-btn').classList.remove('hidden');
    document.getElementById('welcome-rig-editor').classList.add('hidden');
    // Pre-fill with existing settings when forced (not fresh install)
    if (force) {
      welcomeCallsignInput.value = s.myCallsign || '';
      welcomeGridInput.value = s.grid || '';
      if (s.distUnit) document.getElementById('welcome-dist-unit').value = s.distUnit;
      if (s.licenseClass) document.getElementById('welcome-license-class').value = s.licenseClass;
      document.getElementById('welcome-hide-oob').checked = s.hideOutOfBand === true;
      // Auto-SSTV default is ON for fresh installs (the HTML `checked`
      // attribute handles that); on re-open we reflect whatever the user
      // has saved — `!== false` so undefined stays ON.
      document.getElementById('welcome-enable-auto-sstv').checked = s.enableAutoSstv !== false;
      document.getElementById('welcome-auto-sstv-min').value = s.autoSstvInactivityMin || 90;
      const welcomeQrzUser = document.getElementById('welcome-qrz-user');
      const welcomeQrzPass = document.getElementById('welcome-qrz-pass');
      if (welcomeQrzUser) welcomeQrzUser.value = s.qrzUsername || '';
      if (welcomeQrzPass) welcomeQrzPass.value = s.qrzPassword || '';
      welcomeLightMode.checked = s.lightMode === true;
      // Show existing active rig if any
      const rigs = s.rigs || [];
      const activeRig = rigs.find(r => r.id === s.activeRigId) || rigs[0];
      if (activeRig) {
        welcomeRig = activeRig;
        showWelcomeRigItem(activeRig);
      }
    }
    welcomeDialog.showModal();
    _welcomeRemoteOpen();
  } else if (isNewVersion) {
    // Version changed — show "What's New" release notes, not the welcome screen.
    // Triple guard against re-showing on subsequent launches:
    //   1. localStorage (sync, survives slow-disk settings.json write loss)
    //   2. sessionStorage flag (this-session guard against any double-fire
    //      from re-mount / reinit during the same launch)
    //   3. settings.json lastVersion (canonical, used by checkFirstRun)
    // Mark all three BEFORE the dialog opens so even a force-quit while
    // the user is reading release notes can't replay the dialog next time.
    try { localStorage.setItem('whatsNewSeenVersion', s.appVersion); } catch {}
    try { sessionStorage.setItem('whatsNewShownThisSession', s.appVersion); } catch {}
    await window.api.saveSettings({ lastVersion: s.appVersion });
    showWhatsNew(s.appVersion);
  }
}

async function showWhatsNew(version) {
  const dialog = document.getElementById('whats-new-dialog');
  const title = document.getElementById('whats-new-title');
  const body = document.getElementById('whats-new-body');
  const closeBtn = document.getElementById('whats-new-close');

  title.textContent = `What's New in v${version}`;
  body.innerHTML = '<em>Loading release notes...</em>';
  dialog.showModal();

  closeBtn.onclick = () => dialog.close();
  dialog.addEventListener('click', (e) => {
    if (e.target === dialog) dialog.close();
  }, { once: true });

  const data = await window.api.getReleaseNotes(version);
  if (data && data.body) {
    // Convert markdown-ish release notes to simple HTML
    body.innerHTML = formatReleaseNotes(data.body);
    // Open links externally
    body.querySelectorAll('a').forEach(a => {
      a.addEventListener('click', (e) => {
        e.preventDefault();
        if (a.href) window.api.openExternal(a.href);
      });
    });
  } else {
    body.innerHTML = '<p>No release notes available for this version.</p>';
  }
}

// Render GitHub-flavored release notes to clean HTML for the
// What's New dialog. The previous implementation just bolded
// `**Headline:**`, leaving the literal word on-screen and skipping
// inline code, italics, links, and paragraph breaks. This version
// is a small focused markdown renderer plus pre-processing for the
// project's release-notes conventions (`**Headline:** …`, signoff,
// CI-asset footers).
function formatReleaseNotes(md) {
  // ── Pre-processing ──────────────────────────────────────────────
  // Trim download / install / checksum / smartscreen tail.
  md = md.replace(/\n---+[\s\S]*?(?:sudo |SmartScreen|`shasum|`sha256sum|Download |latest-(?:mac|linux|win))[\s\S]*/im, '\n---\n').trim();
  md = md.replace(/\n#{1,4} *(Install|Download|Checksum|SHA-?256|SmartScreen|Assets)[\s\S]*/i, '').trim();
  // Strip Claude / Anthropic attribution if it leaked through.
  md = md.replace(/^.*(?:generated with|claude|anthropic).*$/gim, '').trim();
  // Pull the H1 title — we render it as the lead heading at the top.
  let h1 = '';
  md = md.replace(/^# +(.+)$/m, (_m, h) => { h1 = h.trim(); return ''; }).trim();
  // The `**Headline:** <prose>` convention introduces a lead paragraph.
  // Extract it so we can render it visually distinct (lighter, larger),
  // then strip the literal word "Headline:" so it doesn't appear inline.
  let lead = '';
  md = md.replace(/^\*\*Headline:\*\*\s*(.+)$/m, (_m, prose) => { lead = prose.trim(); return ''; }).trim();
  // Strip the standalone `73.` signoff if it's the very last line —
  // we render it ourselves in the chrome instead.
  md = md.replace(/\n+73\.?\s*$/i, '').trim();
  // Strip horizontal rules that now bracket empty regions.
  md = md.replace(/(^|\n)---+\s*$/g, '$1').trim();

  // ── Block-level rendering ───────────────────────────────────────
  // Pull code fences out first so their contents aren't re-escaped.
  const codeBlocks = [];
  md = md.replace(/```([a-z]*)\n([\s\S]*?)```/gi, (_m, _lang, body) => {
    const idx = codeBlocks.push(body.trim()) - 1;
    return `CODEBLOCK${idx}`;
  });
  // HTML-escape everything else.
  const esc = (s) => s.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
  md = esc(md);

  // Headings (in descending order so ## doesn't eat ###).
  md = md.replace(/^#### +(.+)$/gm, '<h5 class="rn-h5">$1</h5>');
  md = md.replace(/^### +(.+)$/gm, '<h4 class="rn-h4">$1</h4>');
  md = md.replace(/^## +(.+)$/gm, '<h3 class="rn-h3">$1</h3>');
  md = md.replace(/^---+\s*$/gm, '<hr class="rn-hr">');

  // Inline transforms (run before list/paragraph wrapping so lists pick
  // up the rendered text).
  // Inline code (backticks). Single backticks only — code fences are
  // already extracted above.
  md = md.replace(/`([^`\n]+)`/g, '<code class="rn-code">$1</code>');
  // Bold / italic. Bold first so the asterisk-counting works.
  md = md.replace(/\*\*([^*\n]+)\*\*/g, '<strong>$1</strong>');
  md = md.replace(/(^|[^*])\*([^*\n]+)\*(?!\*)/g, '$1<em>$2</em>');
  md = md.replace(/(^|[^_])_([^_\n]+)_(?!_)/g, '$1<em>$2</em>');
  // Links: [text](url)
  md = md.replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2" data-external="1">$1</a>');

  // Lists: turn consecutive `- ` lines into a <ul>. Indented nested
  // lines (4 spaces, "  - " or "  * ") aren't handled — release notes
  // don't use them.
  md = md.replace(/(^|\n)((?:[ \t]*[-*+] +.+(?:\n|$))+)/g, (_m, pre, block) => {
    const items = block.split(/\n/).filter(Boolean).map(line =>
      '<li>' + line.replace(/^[ \t]*[-*+] +/, '') + '</li>'
    ).join('');
    return pre + '<ul class="rn-ul">' + items + '</ul>';
  });

  // Paragraphs: split on blank lines, wrap text-only chunks in <p>.
  // Leave anything that's already HTML alone.
  const blocks = md.split(/\n{2,}/);
  const out = blocks.map(b => {
    const trimmed = b.trim();
    if (!trimmed) return '';
    if (/^<(h\d|ul|pre|hr|blockquote)/.test(trimmed)) return trimmed;
    // Soft line breaks inside a paragraph become <br>.
    return '<p class="rn-p">' + trimmed.replace(/\n/g, '<br>') + '</p>';
  }).join('\n');

  // ── Reinsert code blocks ────────────────────────────────────────
  let html = out.replace(/CODEBLOCK(\d+)/g, (_m, idx) => {
    return '<pre class="rn-pre"><code>' + esc(codeBlocks[+idx]) + '</code></pre>';
  });

  // ── Compose final ──────────────────────────────────────────────
  const head = (h1 || lead)
    ? '<div class="rn-head">'
      + (h1 ? '<div class="rn-h1">' + esc(h1) + '</div>' : '')
      + (lead ? '<div class="rn-lead">' + esc(lead) + '</div>' : '')
      + '</div>'
    : '';
  return head + html;
}

