// ===== JTCAT (FT8/FT4 Digital Modes) =====

var jtcatAudioCtx = null;
var jtcatAudioStream = null;
var jtcatAudioProcessor = null;
var jtcatAnalyser = null;
// Pre-gain tap on the raw input stream. Used only by the meter render
// loop to distinguish "no signal coming in" from "signal coming in but
// gain is muting it" — drives the .jtcat-rx-low-hint badge.
var jtcatPreGainAnalyser = null;
// Sticky timer: when pre-gain is hot and post-gain is starved, count
// frames so the badge appears after sustained low instead of blinking.
var _jtcatRxLowStartedAt = 0;
var jtcatAudioSource = null; // strong ref to prevent GC in Chromium 134+
var jtcatRxGainNode = null;
var jtcatMeterAnim = null;
var jtcatRemoteActive = false; // true when phone is driving JTCAT
var jtcatQuietFreq = 1500;     // auto-detected quiet TX frequency (Hz)
var jtcatQuietFreqFrame = 0;   // frame counter for throttling quiet freq updates
var jtcatSpectrumFrame = 0;    // frame counter for throttling spectrum IPC to ~10fps

// --- SmartSDR Direct: synthetic JTCAT audio stream ---
// On "SmartSDR Direct" the JTCAT audio doesn't come from a Windows DAX
// device — it comes from VITA-49 dax_rx frames forwarded by main. We
// schedule those frames into a MediaStreamAudioDestinationNode and hand
// its .stream to startJtcatAudio() exactly where getUserMedia's stream
// would go, so the entire downstream pipeline (gain, analyser, waterfall,
// worklet) is byte-identical to the Windows-device path. K3SBP 2026-05-14.
var jtcatVita49Ctx = null;
var jtcatVita49Dest = null;
var jtcatVita49Node = null; // single AudioWorkletNode — replaces per-frame BufferSource churn

window.api.onJtcatVita49Audio(function (frame) {
  // Return false so the preload acks immediately when we're not the
  // active consumer — keeps main's IPC backlog at 0 for this window
  // while the JTCAT popout is the live audio sink.
  if (!jtcatVita49Node || !frame || !frame.pcm || !frame.pcm.length) return false;
  if (jtcatVita49Ctx && jtcatVita49Ctx.state === 'suspended') jtcatVita49Ctx.resume().catch(function () {});
  // Hand the raw PCM frame to the worklet's port. The worklet maintains
  // a single ring buffer + linear-interp resampler — no per-frame Web
  // Audio node allocation. The IPC-deserialized typed array may not be
  // a Float32Array; coerce so the worklet sees uniform shape.
  var pcm = (frame.pcm instanceof Float32Array) ? frame.pcm : new Float32Array(frame.pcm);
  jtcatVita49Node.port.postMessage(pcm);
  return true;
});

async function startJtcatAudio() {
  // Always stop existing audio first to ensure clean device state
  // (prevents stale stream after ECHOCAT releases the shared device)
  stopJtcatAudio();
  // Brief delay for the OS to fully release the audio device
  await new Promise(function(r) { setTimeout(r, 300); });
  try {
    var s = await window.api.getSettings();

    if (s.audioSource === 'smartsdr') {
      // SmartSDR Direct: JTCAT audio is the VITA-49 dax_rx stream that
      // main forwards as 'jtcat-vita49-audio' frames — not a Windows
      // audio device. Build a synthetic MediaStream from those frames so
      // everything below this point (createMediaStreamSource, gain,
      // analyser, waterfall, worklet) runs unchanged.
      //
      // A SINGLE AudioWorkletNode owns the ring buffer + linear-interp
      // resampler and pumps samples into a MediaStreamDestination. The
      // module-scope `onJtcatVita49Audio` handler just port.postMessages
      // raw PCM at it — no per-frame BufferSource creation, no Web Audio
      // scheduler churn. K3SBP 2026-06-02 — replaces the previous
      // createBuffer+createBufferSource-per-frame path that drove the
      // "renderer not keeping up" backpressure spiral.
      jtcatVita49Ctx = new AudioContext();
      if (jtcatVita49Ctx.state === 'suspended') {
        try { await jtcatVita49Ctx.resume(); } catch (e) { /* logged below if it bites */ }
      }
      try {
        await jtcatVita49Ctx.audioWorklet.addModule('jtcat-vita49-source-worklet.js');
      } catch (e) {
        console.error('[JTCAT] failed to load VITA-49 source worklet:', e);
        if (window.api.jtcatLog) window.api.jtcatLog('[JTCAT] VITA-49 source worklet load failed: ' + (e.message || e));
        throw e;
      }
      jtcatVita49Node = new AudioWorkletNode(jtcatVita49Ctx, 'jtcat-vita49-source', {
        numberOfInputs: 0,
        numberOfOutputs: 1,
        outputChannelCount: [1],
        processorOptions: { sourceRate: 24000 },
      });
      jtcatVita49Dest = jtcatVita49Ctx.createMediaStreamDestination();
      jtcatVita49Node.connect(jtcatVita49Dest);
      jtcatAudioStream = jtcatVita49Dest.stream;
      if (window.api.jtcatLog) window.api.jtcatLog('[JTCAT] Audio source: SmartSDR Direct (VITA-49 dax_rx via AudioWorklet)');
    } else {
      var audioConstraints = {
        channelCount: 1,
        echoCancellation: false,
        noiseSuppression: false,
        autoGainControl: false,
      };
      // Use the same audio input device as ECHOCAT (remoteAudioInput)
      if (s.remoteAudioInput) {
        audioConstraints.deviceId = { exact: s.remoteAudioInput };
      }
      try {
        jtcatAudioStream = await navigator.mediaDevices.getUserMedia({ audio: audioConstraints });
      } catch (e) {
        // Fall back to default device if configured one fails. Silent
        // fallback used to mask "JTCAT silently decodes nothing" bugs
        // (e.g. Casey 2026-05-03 — SSTV popout held the rig audio device,
        // JTCAT got the laptop mic and produced zero decodes), so surface
        // this loud in the CAT log too.
        const warn = `[JTCAT] Configured audio input failed (${e.message}). Falling back to default device — decoding may not work if your rig audio is on a different input.`;
        console.warn(warn);
        if (window.api.jtcatLog) window.api.jtcatLog(warn);
        delete audioConstraints.deviceId;
        jtcatAudioStream = await navigator.mediaDevices.getUserMedia({ audio: audioConstraints });
      }
    }

    // Use native sample rate and downsample properly to 12kHz for FT8 decoder.
    jtcatAudioCtx = new AudioContext();
    if (jtcatAudioCtx.state === 'suspended') {
      try { await jtcatAudioCtx.resume(); } catch (e) { console.warn('[JTCAT] resume failed:', e.message); }
    }
    // K3SBP 2026-05-04: phone-triggered START on a cold-start desktop
    // sometimes left the AudioContext suspended even after resume() — the
    // page hadn't received a user gesture, and despite the
    // 'autoplay-policy=no-user-gesture-required' switch in main.js,
    // Chromium can still leave the context in a non-running state. When
    // that happens, getUserMedia returns a real stream but the worklet /
    // ScriptProcessor never fires (silent capture). Surface this loud so
    // the user knows to click the desktop window once.
    if (jtcatAudioCtx.state !== 'running') {
      const warn = `[JTCAT] AudioContext state is "${jtcatAudioCtx.state}" after resume() — audio capture will be silent. Click the POTACAT desktop window once to grant audio permission, or restart POTACAT.`;
      console.warn(warn);
      if (window.api.jtcatLog) window.api.jtcatLog(warn);
    }
    var source = jtcatAudioCtx.createMediaStreamSource(jtcatAudioStream);
    jtcatAudioSource = source; // prevent GC — Chromium 134+ may collect unrooted audio nodes

    // RX GainNode for level control — use current slider value, not default 1.0
    jtcatRxGainNode = jtcatAudioCtx.createGain();
    jtcatRxGainNode.gain.value = jtcatRxGainSlider ? parseInt(jtcatRxGainSlider.value, 10) / 100 : 1.0;
    source.connect(jtcatRxGainNode);

    // AnalyserNode for waterfall FFT (after gain so level changes affect waterfall)
    jtcatAnalyser = jtcatAudioCtx.createAnalyser();
    jtcatAnalyser.fftSize = 2048;
    jtcatAnalyser.smoothingTimeConstant = 0.3;
    jtcatRxGainNode.connect(jtcatAnalyser);

    // Pre-gain tap — observes the raw input level so the meter loop can
    // tell "rig audio is silent" from "rig audio is fine but the slider
    // is starving the decoder." Tap directly off `source`, never connect
    // to destination so it doesn't double-route audio. chriskf0jfw 5/27.
    jtcatPreGainAnalyser = jtcatAudioCtx.createAnalyser();
    jtcatPreGainAnalyser.fftSize = 2048;
    jtcatPreGainAnalyser.smoothingTimeConstant = 0.3;
    source.connect(jtcatPreGainAnalyser);

    // Start RX level meter rendering
    startJtcatMeter();

    var nativeRate = jtcatAudioCtx.sampleRate;
    var dsRatio = nativeRate / 12000;
    console.log('[JTCAT] AudioContext sample rate:', nativeRate, 'dsRatio:', dsRatio.toFixed(2));

    // Try AudioWorklet first (reliable on Chromium 134+), fall back to ScriptProcessorNode
    try {
      await jtcatAudioCtx.audioWorklet.addModule('jtcat-audio-worklet.js');
      var workletNode = new AudioWorkletNode(jtcatAudioCtx, 'jtcat-processor', {
        processorOptions: { dsRatio: dsRatio },
      });
      workletNode.port.onmessage = function(e) {
        window.api.jtcatAudio(e.data);
      };
      jtcatRxGainNode.connect(workletNode);
      workletNode.connect(jtcatAudioCtx.destination);
      jtcatAudioProcessor = workletNode;
      console.log('[JTCAT] Using AudioWorkletNode for audio capture');
    } catch (workletErr) {
      console.warn('[JTCAT] AudioWorklet failed:', workletErr.message, '— falling back to ScriptProcessorNode');
      var bufSize = dsRatio > 1 ? 4096 * Math.ceil(dsRatio) : 4096;
      bufSize = Math.pow(2, Math.ceil(Math.log2(bufSize)));
      if (bufSize > 16384) bufSize = 16384;
      jtcatAudioProcessor = jtcatAudioCtx.createScriptProcessor(bufSize, 1, 1);
      // Build anti-alias FIR filter for proper downsampling
      var firCoeffs = null, firHistory = null, firIdx = 0, decCounter = 0;
      if (dsRatio > 1.01) {
        var cutoff = 0.45 / dsRatio;
        var taps = Math.max(31, Math.round(dsRatio * 16) | 1);
        firCoeffs = new Float32Array(taps);
        firHistory = new Float32Array(taps);
        var mid = (taps - 1) / 2, fsum = 0;
        for (var t = 0; t < taps; t++) {
          var n = t - mid;
          var h = Math.abs(n) < 1e-6 ? 2 * cutoff : Math.sin(2 * Math.PI * cutoff * n) / (Math.PI * n);
          var w = 0.42 - 0.5 * Math.cos(2 * Math.PI * t / (taps - 1)) + 0.08 * Math.cos(4 * Math.PI * t / (taps - 1));
          firCoeffs[t] = h * w; fsum += firCoeffs[t];
        }
        for (var t = 0; t < taps; t++) firCoeffs[t] /= fsum;
      }
      jtcatAudioProcessor.onaudioprocess = function(e) {
        try {
          var rawSamples = e.inputBuffer.getChannelData(0);
          var samples;
          if (dsRatio > 1.01) {
            var out = [];
            var ratio = Math.round(dsRatio);
            for (var i = 0; i < rawSamples.length; i++) {
              firHistory[firIdx] = rawSamples[i];
              firIdx = (firIdx + 1) % firCoeffs.length;
              decCounter++;
              if (decCounter >= ratio) {
                decCounter = 0;
                var sum = 0, idx = firIdx;
                for (var t = 0; t < firCoeffs.length; t++) {
                  sum += firHistory[idx] * firCoeffs[t];
                  idx = (idx + 1) % firCoeffs.length;
                }
                out.push(sum);
              }
            }
            samples = out;
          } else {
            samples = Array.from(rawSamples);
          }
          window.api.jtcatAudio(samples);
        } catch (err) {
          console.error('[JTCAT] Audio processor error:', err.message || err);
        }
      };
      jtcatRxGainNode.connect(jtcatAudioProcessor);
      jtcatAudioProcessor.connect(jtcatAudioCtx.destination);
    }

    // Monitor audio stream — some rigs (e.g. Yaesu FT-710) disconnect USB audio during TX
    var audioTrack = jtcatAudioStream.getAudioTracks()[0];
    if (audioTrack) {
      // Surface the device label that getUserMedia actually grabbed — useful
      // when the configured device fell through to the system default.
      try {
        var deviceLabel = audioTrack.label || '(no label)';
        var notice = `[JTCAT] Audio capture device: ${deviceLabel}${audioTrack.muted ? ' (MUTED at start — Chromium will not deliver samples)' : ''}`;
        console.log(notice);
        if (window.api.jtcatLog) window.api.jtcatLog(notice);
      } catch {}
      audioTrack.addEventListener('ended', function() {
        console.warn('[JTCAT] Audio track ended (device disconnected?) — restarting capture in 2s');
        if (window.api.jtcatLog) window.api.jtcatLog('[JTCAT] Audio track ended (device disconnected?) — restarting capture in 2s');
        setTimeout(function() {
          if (jtcatRunning || jtcatRemoteActive) {
            stopJtcatAudio();
            startJtcatAudio();
          }
        }, 2000);
      });
      audioTrack.addEventListener('mute', function() {
        var w = '[JTCAT] Audio track muted by the OS — silent capture until unmuted';
        console.warn(w);
        if (window.api.jtcatLog) window.api.jtcatLog(w);
      });
      audioTrack.addEventListener('unmute', function() {
        if (window.api.jtcatLog) window.api.jtcatLog('[JTCAT] Audio track unmuted');
      });
    }

    // Start waterfall rendering loop
    jtcatWaterfallLoop();

    console.log('[JTCAT] Audio capture started, device:', s.remoteAudioInput || 'default', 'sample rate:', jtcatAudioCtx.sampleRate);
  } catch (err) {
    console.error('[JTCAT] Audio capture failed:', err.message || err);
  }
}

// --- JTCAT RX Audio Meter ---
// Reusable buffer — at ~60fps this avoids allocating a fresh Uint8Array
// 60 times a second.
var _jtcatMeterBuf = null;
function _jtcatRmsFromAnalyser(analyser) {
  if (!analyser) return 0;
  if (!_jtcatMeterBuf || _jtcatMeterBuf.length !== analyser.frequencyBinCount) {
    _jtcatMeterBuf = new Uint8Array(analyser.frequencyBinCount);
  }
  analyser.getByteTimeDomainData(_jtcatMeterBuf);
  var sum = 0;
  for (var i = 0; i < _jtcatMeterBuf.length; i++) {
    var v = (_jtcatMeterBuf[i] - 128) / 128;
    sum += v * v;
  }
  return Math.sqrt(sum / _jtcatMeterBuf.length);
}
function startJtcatMeter() {
  var canvas = document.getElementById('jtcat-rx-meter');
  if (!canvas || jtcatMeterAnim) return;
  var lowHintEl = document.getElementById('jtcat-rx-low-hint');
  function render() {
    if (jtcatAnalyser && canvas) {
      var ctx = canvas.getContext('2d');
      var w = canvas.width, h = canvas.height;
      var postRms = _jtcatRmsFromAnalyser(jtcatAnalyser);
      var db = postRms > 0 ? 20 * Math.log10(postRms) : -60;
      var level = Math.max(0, Math.min(1, (db + 40) / 40));
      ctx.clearRect(0, 0, w, h);
      var barW = Math.round(level * w);
      ctx.fillStyle = level < 0.6 ? '#4ecca3' : level < 0.85 ? '#ffd740' : '#e94560';
      ctx.fillRect(0, 0, barW, h);

      // "RX low — bump gain" hint. Fires when pre-gain RMS shows actual
      // input signal but post-gain RMS is starving the decoder. Sustained
      // for 3 seconds before showing (avoid flashing on transients), and
      // sustained for 1 second below threshold before clearing (avoid
      // flashing off mid-call). chriskf0jfw 5/27.
      if (lowHintEl) {
        var preRms = _jtcatRmsFromAnalyser(jtcatPreGainAnalyser);
        var inputHot = preRms > 0.005;    // -46 dBFS — clearly above silence
        var outputStarved = postRms < 0.025; // -32 dBFS — below FT8 decode floor
        var now = Date.now();
        if (inputHot && outputStarved) {
          if (!_jtcatRxLowStartedAt) _jtcatRxLowStartedAt = now;
          if (now - _jtcatRxLowStartedAt > 3000) {
            lowHintEl.classList.remove('hidden');
          }
        } else {
          // Reset only if we've been NOT in the low state for ≥1s,
          // implemented via the negative side of the counter — flip the
          // anchor to a future "release time" stamp so the hide is gated.
          if (_jtcatRxLowStartedAt > 0 && _jtcatRxLowStartedAt < now) {
            // Use negative value as a sentinel for "release pending"
            _jtcatRxLowStartedAt = -now;
          } else if (_jtcatRxLowStartedAt < 0 && now + _jtcatRxLowStartedAt > 1000) {
            lowHintEl.classList.add('hidden');
            _jtcatRxLowStartedAt = 0;
          }
        }
      }
    }
    jtcatMeterAnim = requestAnimationFrame(render);
  }
  jtcatMeterAnim = requestAnimationFrame(render);
}

var jtcatRxGainSlider = document.getElementById('jtcat-rx-gain');
var jtcatRxGainVal = document.getElementById('jtcat-rx-gain-val');
if (jtcatRxGainSlider) {
  jtcatRxGainSlider.addEventListener('input', function() {
    var pct = parseInt(jtcatRxGainSlider.value, 10);
    jtcatRxGainVal.textContent = pct + '%';
    if (jtcatRxGainNode) jtcatRxGainNode.gain.value = pct / 100;
  });
}

// TX Power slider — attenuates FT8 tone amplitude before audio output
var jtcatTxGainSlider = document.getElementById('jtcat-tx-gain');
var jtcatTxGainVal = document.getElementById('jtcat-tx-gain-val');
var jtcatTxGainLevel = 1.0;
// TX Pwr uses a square curve: gain = (pct/100)^2
// This gives fine control at the low end (FT8 sweet spot ~10-20%)
// and full range at the top. Slider 14% ≈ 0.02 gain, 20% ≈ 0.04 gain.
function txPwrToGain(pct) { return (pct / 100) * (pct / 100); }
function gainToTxPwr(gain) { return Math.round(Math.sqrt(gain) * 100); }

if (jtcatTxGainSlider) {
  jtcatTxGainSlider.addEventListener('input', function() {
    var pct = parseInt(jtcatTxGainSlider.value, 10);
    jtcatTxGainVal.textContent = pct + '%';
    jtcatTxGainLevel = txPwrToGain(pct);
  });
}
// Accept RX gain from popout or ECHOCAT
window.api.onJtcatSetRxGain(function(level) {
  if (jtcatRxGainNode) jtcatRxGainNode.gain.value = level;
  if (jtcatRxGainSlider) {
    jtcatRxGainSlider.value = Math.round(level * 100);
    jtcatRxGainVal.textContent = Math.round(level * 100) + '%';
  }
});
// Accept TX gain from popout or ECHOCAT
window.api.onJtcatSetTxGain(function(level) {
  jtcatTxGainLevel = level;
  if (jtcatTxGainSlider) {
    jtcatTxGainSlider.value = gainToTxPwr(level);
    jtcatTxGainVal.textContent = gainToTxPwr(level) + '%';
  }
});

function stopJtcatAudio() {
  if (jtcatMeterAnim) { cancelAnimationFrame(jtcatMeterAnim); jtcatMeterAnim = null; }
  if (waterfallAnimFrame) {
    cancelAnimationFrame(waterfallAnimFrame);
    waterfallAnimFrame = null;
  }
  jtcatAnalyser = null;
  jtcatAudioSource = null;
  jtcatRxGainNode = null;
  if (jtcatAudioProcessor) {
    jtcatAudioProcessor.disconnect();
    jtcatAudioProcessor = null;
  }
  if (jtcatAudioCtx) {
    jtcatAudioCtx.close().catch(function() {});
    jtcatAudioCtx = null;
  }
  if (jtcatAudioStream) {
    jtcatAudioStream.getTracks().forEach(function(t) { t.stop(); });
    jtcatAudioStream = null;
  }
  // SmartSDR Direct synthetic-stream context — frame handler no-ops once
  // jtcatVita49Node is null, so this cleanly stops the synthetic feed.
  if (jtcatVita49Node) {
    try { jtcatVita49Node.disconnect(); } catch (e) { /* already gone */ }
    jtcatVita49Node = null;
  }
  if (jtcatVita49Ctx) {
    jtcatVita49Ctx.close().catch(function() {});
    jtcatVita49Ctx = null;
  }
  jtcatVita49Dest = null;
}

// Restart JTCAT audio after ECHOCAT releases the shared audio device
window.api.onRestartJtcatAudio(() => {
  if (jtcatRunning && !jtcatRemoteActive && !jtcatPopoutOpen) {
    console.log('[JTCAT] Restarting audio after ECHOCAT teardown');
    stopJtcatAudio();
    startJtcatAudio();
  }
});

function startJtcatView() {
  if (jtcatRunning) return;
  jtcatRunning = true;
  jtcatDecodes = [];
  jtcatDecodeLog = [];
  jtcatMapClear();
  // If remote is already driving the engine, just start the UI — don't restart engine/audio
  // If popout is open, it handles its own engine start + audio capture
  if (!jtcatRemoteActive && !jtcatPopoutOpen) {
    window.api.jtcatStart(jtcatModeSelect.value);
    startJtcatAudio();
  }
  startJtcatCountdown();
}

function stopJtcatView() {
  if (!jtcatRunning) return;
  jtcatRunning = false;
  // If the phone is driving JTCAT, keep audio capture and engine running
  if (!jtcatRemoteActive) {
    window.api.jtcatStop();
    stopJtcatAudio();
  }
  if (jtcatCountdownTimer) {
    clearInterval(jtcatCountdownTimer);
    jtcatCountdownTimer = null;
  }
  jtcatCountdown.textContent = '\u2014';
  jtcatCycleIndicator.textContent = '\u2014';
  jtcatSyncStatus.textContent = 'Sync: \u2014';
}

function startJtcatCountdown() {
  if (jtcatCountdownTimer) clearInterval(jtcatCountdownTimer);
  jtcatCountdownTimer = setInterval(() => {
    if (!jtcatRunning) return;
    const now = Date.now();
    const mode = jtcatModeSelect.value;
    const cycleMs = (mode === 'FT4' ? 7.5 : 15) * 1000;
    const msInto = now % cycleMs;
    const remaining = Math.ceil((cycleMs - msInto) / 1000);
    jtcatCountdown.textContent = remaining + 's';
    const cycleSec = mode === 'FT4' ? 7.5 : 15;
    const slot = Math.floor(now / 1000 / cycleSec) % 2 === 0 ? 'Even' : 'Odd';
    jtcatCycleIndicator.textContent = slot;
    jtcatCycleIndicator.className = 'jtcat-cycle ' + (slot === 'Even' ? 'jtcat-slot-even' : 'jtcat-slot-odd');
  }, 200);
}

// Band buttons
document.querySelectorAll('.jtcat-band-btn').forEach(function(btn) {
  btn.addEventListener('click', function() {
    var freq = parseInt(btn.dataset.freq, 10);
    var band = btn.dataset.band;
    // Use JTCAT-specific slice if configured, otherwise main CAT
    var slicePort = jtcatSliceSelect.value ? parseInt(jtcatSliceSelect.value, 10) : 0;
    if (slicePort) {
      window.api.tune(freq, jtcatModeSelect.value, null, slicePort);
    } else {
      window.api.tune(freq, jtcatModeSelect.value);
    }
    jtcatCurrentBand = band;
    document.querySelectorAll('.jtcat-band-btn').forEach(function(b) { b.classList.remove('active'); });
    btn.classList.add('active');
  });
});

